    async function loadProjectFromBackend(options) {
        const opts = options || {};
        bindCanvasBridgeResponseListener();
        if (backendLoadedStorageKey === storageKey && !opts.force) {
            return true;
        }
        const directLoad = await sendCanvasProjectLoadRequest({ project_id: project.id || PROJECT_ID });
        if (directLoad && directLoad.ok) {
            const incoming = sanitizeProject(directLoad.project || createDefaultProject());
            if (directLoad.storage && typeof directLoad.storage === 'object') incoming.storage = directLoad.storage;
            const decision = browserBackendProjectDecision(incoming, Object.assign({}, opts, { backendFound: directLoad.found !== false }));
            if (decision.keepBrowser) {
                syncCanvasProjectAssetRoot(project);
                resetRenderedProjectDomCache();
                backendLoadedStorageKey = storageKey;
                renderAll();
                scheduleAutoPresetModelChecks();
                if (!opts.silent) showToast(t('Browser cache is newer; keeping local canvas.', 'Browser cache is newer; keeping local canvas.'));
                return true;
            }
            project = incoming;
            setActiveBrowserCacheProject(project.id || PROJECT_ID, storageScope);
            syncCanvasProjectAssetRoot(project);
            resetRenderedProjectDomCache();
            saveProjectToBrowserCache({ reason: 'backend_direct_load_apply' });
            backendLoadedStorageKey = storageKey;
            selectedNodeId = null;
            selectedGroupId = null;
            selectedEdgeId = null;
            resetHistory();
            renderAll();
            resetGalleryFrostReveals();
            scheduleAutoPresetModelChecks();
            if (!opts.silent) showToast(t('Loaded canvas from {location}', '已从 {location} 读取画布').replace('{location}', project.storage?.location || storageScope.location));
            return true;
        }
        if (!isCanvasBridgeReady()) {
            if (!opts.silent) showToast(t('Backend save bridge is not ready; using {location}', '后端保存桥未就绪，正在使用 {location}').replace('{location}', storageScope.cacheLocation));
            return false;
        }
        if (backendLoadedStorageKey === storageKey && !opts.force) {
            return true;
        }
        let result = await sendCanvasProjectLoadRequest({ project_id: project.id || PROJECT_ID });
        if ((!result || !result.ok) && isCanvasBridgeReady()) {
            result = await sendCanvasBridgeRequest('load_project', { project_id: project.id || PROJECT_ID }, 45000);
        }
        if (!result || !result.ok) {
            if (!opts.silent) showToast(t('Project load from directory failed; using local cache{error}', '目录项目读取失败，正在使用本地缓存{error}').replace('{error}', result && result.error ? `: ${result.error}` : ''));
            return false;
        }
        if (result.project && typeof result.project === 'object') {
            const incoming = sanitizeProject(result.project);
            if (result.storage && typeof result.storage === 'object') incoming.storage = result.storage;
            const decision = browserBackendProjectDecision(incoming, Object.assign({}, opts, { backendFound: result.found !== false }));
            if (decision.keepBrowser) {
                syncCanvasProjectAssetRoot(project);
                resetRenderedProjectDomCache();
                backendLoadedStorageKey = storageKey;
                renderAll();
                if (!opts.silent) showToast(t('Browser cache is newer; keeping local canvas.', 'Browser cache is newer; keeping local canvas.'));
                return true;
            }
            project = incoming;
            setActiveBrowserCacheProject(project.id || PROJECT_ID, storageScope);
            syncCanvasProjectAssetRoot(project);
            resetRenderedProjectDomCache();
            saveProjectToBrowserCache({ reason: 'backend_bridge_load_apply' });
            backendLoadedStorageKey = storageKey;
            selectedNodeId = null;
            selectedGroupId = null;
            selectedEdgeId = null;
            resetHistory();
            renderAll();
            resetGalleryFrostReveals();
            if (!opts.silent) showToast(t('Canvas loaded from {location}', '已从 {location} 读取画布').replace('{location}', project.storage?.location || storageScope.location));
            return true;
        }
        return false;
    }

    function scheduleSave() {
        if (saveTimer) clearTimeout(saveTimer);
        saveTimer = setTimeout(() => {
            if (hasActivePointerInteraction() || performance.now() < suppressWheelUntil) {
                scheduleSave();
                return;
            }
            saveTimer = 0;
            saveProject(true).catch((err) => console.warn('[SimpAI Canvas] autosave failed:', err));
        }, 320);
    }

    function hasActivePointerInteraction() {
        return !!(dragState || groupDragState || nodeResizeState || noteTailDragState || groupResizeState || panState || minimapDragState || marqueeState || connectState || compareDragState || timelineDragState || timelinePlayheadDragState || timelinePreviewDragState || directorTimelineDragState || timelineMaskDrawState || timelineMaskAnchorDragState || timelineKeyframeDragState);
    }

    function scheduleViewportSave() {
        if (viewportSaveTimer) clearTimeout(viewportSaveTimer);
        viewportSaveTimer = setTimeout(() => {
            viewportSaveTimer = 0;
            scheduleSave();
        }, 1500);
    }

    function invalidateMinimapStaticCache() {
        minimapStaticDirty = true;
    }

    function invalidateNodeSpatialIndex() {
        nodeSpatialIndexDirty = true;
    }

    function mutate(options) {
        const opts = options || {};
        project.updated_at = nowIso();
        invalidateMinimapStaticCache();
        invalidateNodeSpatialIndex();
        scheduleSave();
        renderAll(opts);
    }

    /** Lightweight update for polling: only refresh status text/progress/asset on result nodes */
    function pollUpdate() {
        if (!root || root.hidden) return;
        project.nodes.forEach((node) => {
            if (node.type !== 'result') return;
            const nodeEl = nodesLayer?.querySelector(`[data-node-id="${CSS.escape(node.id)}"]`);
            if (!nodeEl) return;
            const status = node.status || {};
            const stateEl = nodeEl.querySelector('.sai-result-status');
            if (stateEl) {
                stateEl.dataset.state = status.state || 'queued';
                const stateText = stateEl.querySelector(':scope > span');
                const percentText = stateEl.querySelector(':scope > b');
                if (stateText) stateText.textContent = status.state || 'queued';
                if (percentText) percentText.textContent = `${Math.round(clamp(Number(status.percent || 0), 0, 1) * 100)}%`;
            }
            const bar = nodeEl.querySelector('.sai-result-progress i');
            if (bar) bar.style.width = `${Math.round(clamp(Number(status.percent || 0), 0, 1) * 100)}%`;
            const foot = nodeEl.querySelector('.sai-node-foot');
            if (foot) foot.textContent = status.message || '';
            // Update preview image and asset media if HTML wasn't re-rendered
            const mediaEl = nodeEl.querySelector('.sai-result-media');
            const previewPlayerHandled = syncResultPreviewPlayerDom(node, nodeEl);
            if (mediaEl && !previewPlayerHandled) {
                const showRunningPreview = shouldShowResultRunningPreview(node);
                const hasMediaRendered = mediaEl.querySelector('img,video,audio');
                const hasPreviewStream = mediaEl.querySelector('.sai-result-preview-stream, [data-result-preview-player]');
                const selAsset = resultMediaDisplayAsset(node);
                const previewSource = resultPreviewAspectSource(node);
                const previewThumb = resultPreviewFrameSrc(previewSource, node.preview?.data_url || node.preview?.thumb || '');
                const shouldRebuildMedia = (showRunningPreview && !hasPreviewStream) || (!hasMediaRendered && (selAsset || previewThumb));
                if (shouldRebuildMedia) {
                    mediaEl.innerHTML = renderResultMediaHtml(node, selAsset, safeAssetFallbackSrc(selAsset || previewSource || node.preview, previewThumb));
                    bindNodeMediaControlEvents(nodeEl);
                    const srcAsset = selAsset || previewSource;
                    applyResultPreviewAspect(mediaEl, srcAsset);
                    bindResultPreviewAspectFromImage(mediaEl.querySelector('[data-result-preview-player], img'), mediaEl, srcAsset);
                } else if (selAsset || previewThumb) {
                    const src = selAsset
                        ? safeAssetFullDisplaySrc(selAsset, '')
                        : previewThumb;
                    const img = mediaEl.querySelector('img');
                    if (img && src && img.getAttribute('src') !== src) {
                        img.src = src;
                    }
                    const srcAsset = selAsset || previewSource;
                    applyResultPreviewAspect(mediaEl, srcAsset);
                    bindResultPreviewAspectFromImage(img, mediaEl, srcAsset);
                }
            }
            // Update running class
            nodeEl.classList.toggle('is-running', isNodeVisuallyRunning(node));
        });
        // Update selected result inspector if needed
        if (selectedNodeId) {
            const sel = getNode(selectedNodeId);
            if (sel && sel.type === 'result' && isCanvasRunActiveState(nodeStatusState(sel))) {
                renderInspector();
            }
        }
        renderStatus();
        renderRunQueuePanelIfOpen();
    }

    function cloneProjectForHistory() {
        return cloneRunValue(project, createDefaultProject());
    }

    function pushHistory(label) {
        const snapshot = cloneProjectForHistory();
        const last = undoStack[undoStack.length - 1];
        try {
            if (last && JSON.stringify(last.project) === JSON.stringify(snapshot)) return;
        } catch (err) {}
        undoStack.push({ label: label || 'Edit canvas', project: snapshot, selectedNodeId, selectedEdgeId, selectedGroupId, selectedNodeIds: Array.from(selectedNodeIds || []) });
        if (undoStack.length > HISTORY_LIMIT) undoStack.shift();
        redoStack = [];
        renderHistoryButtons();
    }

    function pushHistoryBatch(key, label) {
        const nextKey = String(key || label || 'edit');
        if (historyBatchKey !== nextKey) {
            pushHistory(label);
            historyBatchKey = nextKey;
        }
        clearTimeout(historyBatchTimer);
        historyBatchTimer = window.setTimeout(() => {
            historyBatchKey = '';
        }, 900);
    }

    function restoreHistoryEntry(entry) {
        if (!entry || !entry.project) return;
        const storage = project.storage || buildProjectStorageInfo(storageKey, storageScope);
        project = sanitizeProject(cloneRunValue(entry.project, createDefaultProject()));
        project.storage = project.storage || storage;
        resetRenderedProjectDomCache();
        selectedNodeId = entry.selectedNodeId || null;
        selectedEdgeId = entry.selectedEdgeId || null;
        selectedGroupId = entry.selectedGroupId || null;
        selectedNodeIds = new Set(Array.isArray(entry.selectedNodeIds) ? entry.selectedNodeIds : (selectedNodeId ? [selectedNodeId] : []));
        closeContextMenu();
        scheduleSave();
        renderAll();
    }

    function undoCanvasEdit() {
        if (!undoStack.length) {
            showToast(t('No canvas edits to undo', '没有可撤销的画布编辑'));
            return;
        }
        redoStack.push({ label: 'Redo snapshot', project: cloneProjectForHistory(), selectedNodeId, selectedEdgeId, selectedGroupId, selectedNodeIds: Array.from(selectedNodeIds || []) });
        const entry = undoStack.pop();
        restoreHistoryEntry(entry);
        showToast(t('Undo: {label}', '撤销：{label}').replace('{label}', entry.label || t('Edit canvas', '编辑画布')));
        renderHistoryButtons();
    }

    function redoCanvasEdit() {
        if (!redoStack.length) {
            showToast(t('No canvas edits to redo', '没有可重做的画布编辑'));
            return;
        }
        undoStack.push({ label: 'Undo snapshot', project: cloneProjectForHistory(), selectedNodeId, selectedEdgeId, selectedGroupId, selectedNodeIds: Array.from(selectedNodeIds || []) });
        if (undoStack.length > HISTORY_LIMIT) undoStack.shift();
        const entry = redoStack.pop();
        restoreHistoryEntry(entry);
        showToast(t('Canvas edit redone', '已重做画布编辑'));
        renderHistoryButtons();
    }

    function renderHistoryButtons() {
        if (!root) return;
        const undoButton = root.querySelector('[data-canvas-action="undo"]');
        const redoButton = root.querySelector('[data-canvas-action="redo"]');
        if (undoButton) undoButton.disabled = !undoStack.length;
        if (redoButton) redoButton.disabled = !redoStack.length;
    }

    function resetHistory() {
        undoStack = [];
        redoStack = [];
        historyBatchKey = '';
        clearTimeout(historyBatchTimer);
        renderHistoryButtons();
    }

