    function localizeTemplateText(value, fallback) {
        if (value && typeof value === 'object') return t(value.en || fallback || '', value.zh || value.cn || value.en || fallback || '');
        return String(value || fallback || '');
    }

    function normalizeTemplateModelDependency(raw, fallbackCategory) {
        const source = raw && typeof raw === 'object' ? raw : {};
        const nested = source.modelDependency || source.model_dependency || source.requirements || {};
        const dep = nested && typeof nested === 'object' ? nested : {};
        let mode = String(dep.mode || dep.kind || source.model_dependency_mode || '').trim().toLowerCase();
        if (!mode) mode = fallbackCategory === 'starter' ? 'model_free' : 'unknown';
        if (!['model_free', 'teaching_only', 'requires_models', 'unknown'].includes(mode)) mode = 'unknown';
        const modelList = Array.isArray(dep.models || dep.model_list)
            ? (dep.models || dep.model_list).map(item => String(item?.name || item?.path_file || item || '').trim()).filter(Boolean)
            : [];
        const defaultLabel = {
            model_free: t('Model-free', '无模型依赖'),
            teaching_only: t('Teaching only', '教学示例'),
            requires_models: t('Requires models', '需要模型'),
            unknown: t('Model status unknown', '模型状态未知')
        }[mode] || t('Model status unknown', '模型状态未知');
        const defaultNote = {
            model_free: t('Can be browsed and edited without model files.', '无需模型文件即可浏览和编辑。'),
            teaching_only: t('Static teaching template; it is not meant to run generation.', '静态教学模板，不用于真实生成。'),
            requires_models: modelList.length
                ? t('Requires {count} model file(s). Check/download models before Run.', '需要 {count} 个模型文件。运行前请检查/下载模型。').replace('{count}', modelList.length)
                : t('Check/download models before running this template.', '运行此模板前请检查/下载模型。'),
            unknown: t('Open the template and check model readiness before Run.', '打开模板后请先检查模型就绪状态再运行。')
        }[mode] || '';
        return {
            mode,
            label: localizeTemplateText(dep.label, defaultLabel),
            note: localizeTemplateText(dep.note || dep.description, defaultNote),
            models: modelList
        };
    }

    function resolveTemplatePreviewPath(preview) {
        const value = String(preview || '').trim();
        if (!value) return '';
        if (/^(https?:|data:|blob:|\/)/i.test(value)) return value;
        return resolveWorkbenchStaticPath(value.includes('/') ? value : `${TEMPLATE_PREVIEW_ROOT}${value}`);
    }

    const TEMPLATE_MEDIA_CATEGORIES = ['starter', 'image', 'video', 'audio'];
    const TEMPLATE_LIBRARY_CATEGORIES = ['starter', 'image', 'video', 'audio', 'user'];

    function normalizeTemplateMediaCategory(category, fallback = 'image') {
        const value = String(category || '').trim().toLowerCase();
        return TEMPLATE_MEDIA_CATEGORIES.includes(value) ? value : fallback;
    }

    function normalizeTemplateLibraryCategory(category, fallback = 'starter') {
        const value = String(category || '').trim().toLowerCase();
        return TEMPLATE_LIBRARY_CATEGORIES.includes(value) ? value : fallback;
    }

    function normalizeTemplateLibraryItem(raw, index) {
        const item = raw && typeof raw === 'object' ? raw : {};
        const id = sanitizeStoragePart(item.id || item.key || `template_${index + 1}`) || `template_${index + 1}`;
        const mediaCategory = normalizeTemplateMediaCategory(item.category, 'image');
        const source = String(item.source || '').trim().toLowerCase() === 'user' || String(item.path || '').startsWith('user:') ? 'user' : 'static';
        const category = source === 'user' ? 'user' : mediaCategory;
        const modelDependency = normalizeTemplateModelDependency(item, mediaCategory);
        return {
            key: `${source}:${id}`,
            id,
            title: localizeTemplateText(item.title, id),
            description: localizeTemplateText(item.description, ''),
            category,
            mediaCategory,
            tags: Array.isArray(item.tags) ? item.tags.map((tag) => String(tag || '').trim()).filter(Boolean) : [],
            typeLabel: localizeTemplateText(item.typeLabel || item.type_label, t('Node graph', '节点图')),
            modelDependency,
            path: source === 'user' ? `user:${id}` : resolveWorkbenchStaticPath(item.path || ''),
            preview: resolveTemplatePreviewPath(item.preview || item.preview_image || item.thumbnail),
            source,
            updatedAt: item.updated_at || '',
            filePath: item.file_path || ''
        };
    }

    async function getWorkbenchTemplateLibraryItems(options) {
        if (templateLibraryItemsCache && !options?.force) return templateLibraryItemsCache;
        try {
            const response = await fetch(TEMPLATE_LIBRARY_MANIFEST_PATH, { cache: 'no-store' });
            if (response.ok) {
                const manifest = await response.json();
                const rows = Array.isArray(manifest) ? manifest : Array.isArray(manifest.templates) ? manifest.templates : [];
                const items = rows.map(normalizeTemplateLibraryItem).filter((item) => item.id && item.path);
                const userItems = await getUserWorkbenchTemplateLibraryItems();
                if (userItems.length) items.push(...userItems);
                if (items.length) {
                    templateLibraryItemsCache = items;
                    return templateLibraryItemsCache;
                }
            }
        } catch (err) {
            console.warn('[SimpAI Canvas] template library manifest unavailable, using built-in defaults:', err);
        }
        const fallbackItems = getDefaultWorkbenchTemplateLibraryItems().map(normalizeTemplateLibraryItem);
        const userItems = await getUserWorkbenchTemplateLibraryItems();
        templateLibraryItemsCache = fallbackItems.concat(userItems);
        return templateLibraryItemsCache;
    }

    async function getUserWorkbenchTemplateLibraryItems() {
        try {
            const response = await sendCanvasTemplateListRequest({});
            const rows = Array.isArray(response?.templates) ? response.templates : [];
            return rows.map(normalizeTemplateLibraryItem).filter((item) => item.id && item.path);
        } catch (err) {
            console.warn('[SimpAI Canvas] user template list unavailable:', err);
        }
        return [];
    }

    function templateCategoryLabel(category) {
        return {
            starter: t('Starter', '新手'),
            image: t('Image', '图像'),
            video: t('Video', '视频'),
            audio: t('Audio', '音频'),
            user: t('User', '用户')
        }[category] || category;
    }

    function templateCategoryIcon(category) {
        return {
            starter: 'fa-graduation-cap',
            image: 'fa-image',
            video: 'fa-film',
            audio: 'fa-volume-high',
            user: 'fa-user'
        }[category] || 'fa-layer-group';
    }

    function closeTemplateLibrary() {
        const existing = document.querySelector('.sai-template-library-modal');
        if (existing) existing.remove();
    }

    async function openTemplateLibrary() {
        closeTemplateLibrary();
        closeContextMenu();
        closeCanvasSettingsPanel();
        const items = await getWorkbenchTemplateLibraryItems();
        const modal = document.createElement('div');
        modal.className = `sai-canvas-modal sai-template-library-modal ${detectWorkbenchTheme() === 'dark' ? 'theme-dark' : ''}`;
        modal.__saiTemplateItems = items;
        const initialCategory = items.some(item => (item.category || 'image') === 'starter')
            ? 'starter'
            : (items.some(item => item.category === 'user') ? 'user' : normalizeTemplateLibraryCategory(items[0]?.category, 'starter'));
        modal.innerHTML = renderTemplateLibraryHtml({ category: initialCategory, query: '' }, items);
        document.body.appendChild(modal);
        bindTemplateLibraryModal(modal);
        const input = modal.querySelector('[data-template-search]');
        if (input) input.focus({ preventScroll: true });
    }

    function renderTemplateLibraryHtml(state, sourceItems) {
        const currentCategory = normalizeTemplateLibraryCategory(state?.category, 'starter');
        const query = String(state?.query || '').trim().toLowerCase();
        const items = (sourceItems || getDefaultWorkbenchTemplateLibraryItems()).filter((item) => {
            if ((item.category || 'image') !== currentCategory) return false;
            if (!query) return true;
            const dependency = item.modelDependency || {};
            return [item.title, item.description, item.typeLabel, dependency.label, dependency.note, ...(dependency.models || []), ...(item.tags || [])].join(' ').toLowerCase().includes(query);
        });
        const categories = TEMPLATE_LIBRARY_CATEGORIES;
        return `
<div class="sai-canvas-modal-panel sai-template-library-panel" data-template-category="${escapeHtml(currentCategory)}">
  <aside class="sai-template-library-sidebar">
    <div class="sai-template-library-title"><i class="fa-solid fa-layer-group"></i><span>${escapeHtml(t('Templates', '模板库'))}</span></div>
    <div class="sai-template-library-categories">
      ${categories.map((category) => `<button type="button" data-template-category-button="${escapeHtml(category)}" class="${category === currentCategory ? 'is-active' : ''}"><i class="fa-solid ${escapeHtml(templateCategoryIcon(category))}"></i><span>${escapeHtml(templateCategoryLabel(category))}</span></button>`).join('')}
    </div>
  </aside>
  <section class="sai-template-library-main">
    <div class="sai-template-library-head">
      <label class="sai-template-search"><i class="fa-solid fa-magnifying-glass"></i><input type="search" data-template-search value="${escapeHtml(state?.query || '')}" placeholder="${escapeHtml(t('Search templates', '搜索模板'))}"></label>
      <button type="button" data-template-save-current title="${escapeHtml(t('Save current canvas as template', '将当前画布保存为模板'))}"><i class="fa-solid fa-floppy-disk"></i><span>${escapeHtml(t('Save current', '保存当前'))}</span></button>
      <button type="button" data-template-close title="${escapeHtml(t('Close', '关闭'))}" aria-label="${escapeHtml(t('Close', '关闭'))}"><i class="fa-solid fa-xmark"></i></button>
    </div>
    <div class="sai-template-library-section-title">${escapeHtml(templateCategoryLabel(currentCategory))}</div>
    <div class="sai-template-grid">
      ${items.length ? items.map(renderTemplateCardHtml).join('') : `<div class="sai-template-empty">${escapeHtml(t('No templates in this category yet.', '这个分类还没有模板。'))}</div>`}
    </div>
  </section>
</div>`;
    }

    function renderTemplateCardHtml(item) {
        const isUserTemplate = item.source === 'user';
        const mediaCategory = normalizeTemplateMediaCategory(item.mediaCategory || item.category, 'image');
        const tags = [
            templateCategoryLabel(mediaCategory),
            isUserTemplate ? t('User', '用户') : t('Built-in', '内置'),
            item.typeLabel || t('Node graph', '节点图')
        ].filter(Boolean);
        const templateKey = item.key || item.id;
        const dependency = item.modelDependency || normalizeTemplateModelDependency(item, mediaCategory);
        return `
<article class="sai-template-card" data-template-id="${escapeHtml(item.id)}">
  <button type="button" class="sai-template-preview" data-template-use="${escapeHtml(templateKey)}" title="${escapeHtml(t('Use template', '使用模板'))}">
    ${item.preview ? `<img src="${escapeHtml(item.preview)}" alt="">` : `<div class="sai-template-preview-fallback"><i class="fa-solid fa-route"></i></div>`}
  </button>
  <div class="sai-template-card-body">
    <h3>${escapeHtml(item.title)}</h3>
    <p>${escapeHtml(item.description || '')}</p>
    ${renderTemplateDependencyHtml(dependency)}
    <div class="sai-template-tags">${tags.map((tag) => `<span>${escapeHtml(tag)}</span>`).join('')}</div>
    <div class="sai-template-card-actions ${isUserTemplate ? 'has-delete' : ''}">
      <button type="button" class="sai-template-use" data-template-use="${escapeHtml(templateKey)}"><i class="fa-solid fa-plus"></i><span>${escapeHtml(t('Create from template', '从模板新建'))}</span></button>
      ${isUserTemplate ? `<button type="button" class="sai-template-delete" data-template-delete="${escapeHtml(templateKey)}" title="${escapeHtml(t('Delete user template', '删除用户模板'))}" aria-label="${escapeHtml(t('Delete user template', '删除用户模板'))}"><i class="fa-solid fa-trash"></i></button>` : ''}
    </div>
  </div>
</article>`;
    }

    function templateDependencyIcon(mode) {
        return {
            model_free: 'fa-circle-check',
            teaching_only: 'fa-graduation-cap',
            requires_models: 'fa-cubes',
            unknown: 'fa-circle-question'
        }[mode] || 'fa-circle-question';
    }

    function renderTemplateDependencyHtml(dependency) {
        const dep = dependency || normalizeTemplateModelDependency({}, 'image');
        return `<div class="sai-template-dependency" data-dependency="${escapeHtml(dep.mode || 'unknown')}" title="${escapeHtml(dep.note || dep.label || '')}">
  <i class="fa-solid ${escapeHtml(templateDependencyIcon(dep.mode))}"></i>
  <span>${escapeHtml(dep.label || '')}</span>
  <small>${escapeHtml(dep.note || '')}</small>
</div>`;
    }

    function bindTemplateLibraryModal(modal) {
        if (!modal.__saiTemplateLibraryClickBound) {
            modal.__saiTemplateLibraryClickBound = true;
            modal.addEventListener('click', async (evt) => {
                const closeBtn = evt.target.closest('[data-template-close]');
                if (closeBtn || evt.target === modal) {
                    closeTemplateLibrary();
                    return;
                }
                const saveCurrentBtn = evt.target.closest('[data-template-save-current]');
                if (saveCurrentBtn) {
                    await saveCurrentCanvasAsTemplate(modal);
                    return;
                }
                const categoryBtn = evt.target.closest('[data-template-category-button]');
                if (categoryBtn) {
                    const category = normalizeTemplateLibraryCategory(categoryBtn.getAttribute('data-template-category-button'), 'starter');
                    const query = modal.querySelector('[data-template-search]')?.value || '';
                    modal.innerHTML = renderTemplateLibraryHtml({ category, query }, modal.__saiTemplateItems || []);
                    bindTemplateLibraryModal(modal);
                    return;
                }
                const deleteBtn = evt.target.closest('[data-template-delete]');
                if (deleteBtn) {
                    const id = deleteBtn.getAttribute('data-template-delete');
                    const item = (modal.__saiTemplateItems || []).find((candidate) => (candidate.key || candidate.id) === id || candidate.id === id);
                    if (item) await deleteUserWorkbenchTemplate(item, modal);
                    return;
                }
                const useBtn = evt.target.closest('[data-template-use]');
                if (useBtn) {
                    const id = useBtn.getAttribute('data-template-use');
                    const item = (modal.__saiTemplateItems || []).find((candidate) => (candidate.key || candidate.id) === id || candidate.id === id);
                    if (item) await createWorkbenchFromTemplate(item);
                }
            });
        }
        const input = modal.querySelector('[data-template-search]');
        if (input) {
            input.addEventListener('input', () => {
                const panel = modal.querySelector('.sai-template-library-panel');
                const category = normalizeTemplateLibraryCategory(panel?.getAttribute('data-template-category'), 'starter');
                modal.innerHTML = renderTemplateLibraryHtml({ category, query: input.value || '' }, modal.__saiTemplateItems || []);
                bindTemplateLibraryModal(modal);
                modal.querySelector('[data-template-search]')?.focus({ preventScroll: true });
            });
        }
    }

    function requestCanvasConfirmDialog(options) {
        const opts = options || {};
        return new Promise((resolve) => {
            const modal = document.createElement('div');
            modal.className = `sai-canvas-modal sai-canvas-confirm-modal ${detectWorkbenchTheme() === 'dark' ? 'theme-dark' : ''}`;
            modal.innerHTML = `
<div class="sai-canvas-modal-panel sai-canvas-confirm-panel ${opts.danger ? 'is-danger' : ''}">
  <div class="sai-canvas-confirm-body">
    <div class="sai-canvas-confirm-icon"><i class="fa-solid ${escapeHtml(opts.icon || (opts.danger ? 'fa-trash' : 'fa-circle-question'))}"></i></div>
    <div class="sai-canvas-confirm-copy">
      <h3>${escapeHtml(opts.title || t('Confirm action', '确认操作'))}</h3>
      ${opts.message ? `<p>${escapeHtml(opts.message)}</p>` : ''}
      ${opts.detail ? `<small>${escapeHtml(opts.detail)}</small>` : ''}
    </div>
  </div>
  <div class="sai-canvas-confirm-actions">
    <button type="button" data-confirm-cancel>${escapeHtml(opts.cancelLabel || t('Cancel', '取消'))}</button>
    <button type="button" class="primary ${opts.danger ? 'danger' : ''}" data-confirm-ok>${escapeHtml(opts.confirmLabel || t('Confirm', '确认'))}</button>
  </div>
</div>`;
            const cleanup = (value) => {
                document.removeEventListener('keydown', onKeyDown);
                modal.remove();
                resolve(value);
            };
            const onKeyDown = (evt) => {
                if (evt.key === 'Escape') {
                    evt.preventDefault();
                    cleanup(false);
                } else if (evt.key === 'Enter') {
                    evt.preventDefault();
                    cleanup(true);
                }
            };
            modal.addEventListener('click', (evt) => {
                if (evt.target === modal || evt.target.closest('[data-confirm-cancel]')) cleanup(false);
                if (evt.target.closest('[data-confirm-ok]')) cleanup(true);
            });
            document.addEventListener('keydown', onKeyDown);
            document.body.appendChild(modal);
            modal.querySelector('[data-confirm-ok]')?.focus({ preventScroll: true });
        });
    }

    async function deleteUserWorkbenchTemplate(item, parentModal) {
        if (!item || item.source !== 'user') {
            showToast(t('Built-in templates cannot be deleted.', '内置模板不能删除。'));
            return;
        }
        const title = item.title || item.id;
        const confirmed = await requestCanvasConfirmDialog({
            danger: true,
            icon: 'fa-trash',
            title: t('Delete user template', '删除用户模板'),
            message: title,
            detail: t('This only removes the saved template. Projects created from it are kept.', '这只会移除已保存的模板，由它创建的项目会保留。'),
            confirmLabel: t('Delete', '删除'),
            cancelLabel: t('Cancel', '取消')
        });
        if (!confirmed) {
            return;
        }
        const result = await sendCanvasTemplateDeleteRequest(item.id);
        if (!result?.ok) {
            showToast(t('Template delete failed: {error}', '模板删除失败：{error}').replace('{error}', result?.error || result?.details || 'unknown'));
            return;
        }
        templateLibraryItemsCache = null;
        showToast(t('Template deleted: {title}', '模板已删除：{title}').replace('{title}', title));
        const items = await getWorkbenchTemplateLibraryItems({ force: true });
        if (parentModal && document.body.contains(parentModal)) {
            const panel = parentModal.querySelector('.sai-template-library-panel');
            const category = normalizeTemplateLibraryCategory(panel?.getAttribute('data-template-category') || item.category || 'user', 'starter');
            const query = parentModal.querySelector('[data-template-search]')?.value || '';
            parentModal.__saiTemplateItems = items;
            parentModal.innerHTML = renderTemplateLibraryHtml({ category, query }, items);
            bindTemplateLibraryModal(parentModal);
        }
    }

    async function loadWorkbenchTemplateData(item) {
        if (item?.source === 'user' || String(item?.path || '').startsWith('user:')) {
            const templateId = String(item?.id || String(item?.path || '').replace(/^user:/, '')).trim();
            const response = await sendCanvasTemplateLoadRequest(templateId);
            if (response?.ok && response.project) return response.project;
            showToast(t('Failed to load user template: {error}', '读取用户模板失败：{error}').replace('{error}', response?.error || 'unknown'));
            return createDemoWorkbenchProject({ id: project.id || PROJECT_ID, storage: project.storage || buildProjectStorageInfo(storageKey, storageScope) });
        }
        if (item?.path) {
            try {
                const response = await fetch(item.path, { cache: 'no-store' });
                if (response.ok) return await response.json();
            } catch (err) {
                console.warn('[SimpAI Canvas] template fetch failed, using fallback demo:', err);
            }
        }
        return createDemoWorkbenchProject({ id: project.id || PROJECT_ID, storage: project.storage || buildProjectStorageInfo(storageKey, storageScope) });
    }

    function currentWorkbenchSettingsForTemplateProject() {
        const current = project?.settings && typeof project.settings === 'object' ? project.settings : {};
        const preserved = {};
        Object.keys(current).forEach((key) => {
            if (!key || key.startsWith('__')) return;
            preserved[key] = cloneRunValue(current[key], current[key]);
        });
        return preserved;
    }

    function applyTemplateProjectSettings(templateProject, sourceKey) {
        const templateSettings = templateProject?.settings && typeof templateProject.settings === 'object'
            ? templateProject.settings
            : {};
        templateProject.settings = Object.assign(
            {},
            DEFAULT_SETTINGS,
            templateSettings,
            currentWorkbenchSettingsForTemplateProject(),
            { __template_source: sourceKey }
        );
        return templateProject.settings;
    }

    function requestSaveTemplateDetails() {
        return new Promise((resolve) => {
            const defaultId = sanitizeStoragePart(`${project.id || 'canvas'}_template_${new Date().toISOString().replace(/[-:.TZ]/g, '').slice(0, 14)}`) || `template_${Date.now()}`;
            const templateMeta = project && typeof project.template === 'object' ? project.template : {};
            const defaultCategory = TEMPLATE_MEDIA_CATEGORIES.includes(templateMeta.category)
                ? templateMeta.category
                : 'image';
            const defaultTitle = project.title || project.id || t('Canvas Template', '画布模板');
            const modal = document.createElement('div');
            modal.className = `sai-canvas-modal sai-template-create-modal ${detectWorkbenchTheme() === 'dark' ? 'theme-dark' : ''}`;
            modal.innerHTML = `
<div class="sai-canvas-modal-panel sai-template-create-panel">
  <div class="sai-canvas-modal-head">
    <span>${escapeHtml(t('Save current canvas as template', '将当前画布保存为模板'))}</span>
    <button type="button" data-template-create-cancel title="${escapeHtml(t('Cancel', '取消'))}" aria-label="${escapeHtml(t('Cancel', '取消'))}"><i class="fa-solid fa-xmark"></i></button>
  </div>
  <form class="sai-template-create-body">
    <label><span>${escapeHtml(t('Template ID', '模板 ID'))}</span><input type="text" data-save-template-field="id" value="${escapeHtml(defaultId)}" autocomplete="off" spellcheck="false"></label>
    <label><span>${escapeHtml(t('Title', '标题'))}</span><input type="text" data-save-template-field="title" value="${escapeHtml(defaultTitle)}" autocomplete="off"></label>
    <label><span>${escapeHtml(t('Category', '分类'))}</span><select data-save-template-field="category">
      ${TEMPLATE_MEDIA_CATEGORIES.map(category => `<option value="${escapeHtml(category)}" ${category === defaultCategory ? 'selected' : ''}>${escapeHtml(templateCategoryLabel(category))}</option>`).join('')}
    </select></label>
    <label><span>${escapeHtml(t('Description', '描述'))}</span><textarea data-save-template-field="description" rows="3">${escapeHtml(t('Saved from the current canvas.', '从当前画布保存。'))}</textarea></label>
    <label><span>${escapeHtml(t('Tags', '标签'))}</span><input type="text" data-save-template-field="tags" value="user, canvas" autocomplete="off"></label>
    <div class="sai-template-create-actions">
      <button type="button" data-template-create-cancel>${escapeHtml(t('Cancel', '取消'))}</button>
      <button type="submit" class="primary">${escapeHtml(t('Save', '保存'))}</button>
    </div>
  </form>
</div>`;
            const cleanup = (value) => {
                modal.remove();
                resolve(value);
            };
            modal.addEventListener('click', (evt) => {
                if (evt.target === modal || evt.target.closest('[data-template-create-cancel]')) cleanup(null);
            });
            modal.querySelector('form')?.addEventListener('submit', (evt) => {
                evt.preventDefault();
                const read = (key) => modal.querySelector(`[data-save-template-field="${key}"]`)?.value || '';
                const id = sanitizeStoragePart(read('id')).replace(/[:]/g, '_') || defaultId;
                const title = read('title').trim() || id;
                const category = normalizeTemplateMediaCategory(read('category'), 'starter');
                const description = read('description').trim();
                const tags = read('tags').split(',').map(tag => tag.trim()).filter(Boolean);
                cleanup({ id, title, category, description, tags });
            });
            document.body.appendChild(modal);
            const input = modal.querySelector('[data-save-template-field="id"]');
            input?.focus({ preventScroll: true });
            input?.select();
        });
    }

    async function saveCurrentCanvasAsTemplate(parentModal) {
        const details = await requestSaveTemplateDetails();
        if (!details) return;
        await saveProject(true, { persist: false });
        const templateProject = compactProjectForStorage(project, { stripAllMaterializedDataUrls: true, stripStorage: true, runHistoryLimit: 8 });
        templateProject.id = details.id;
        templateProject.title = details.title;
        templateProject.settings = Object.assign({}, DEFAULT_SETTINGS, templateProject.settings || {}, { __template_source: 'user' });
        const modelDependency = inferProjectTemplateModelDependency(templateProject);
        const result = await sendCanvasTemplateSaveRequest({
            template_id: details.id,
            title: details.title,
            description: details.description,
            category: details.category,
            tags: details.tags,
            type_label: t('User template', '用户模板'),
            model_dependency: modelDependency,
            project: templateProject
        });
        if (!result?.ok) {
            showToast(t('Template save failed: {error}', '模板保存失败：{error}').replace('{error}', result?.error || result?.details || 'unknown'));
            return;
        }
        templateLibraryItemsCache = null;
        showToast(t('Template saved: {title}', '模板已保存：{title}').replace('{title}', details.title));
        const items = await getWorkbenchTemplateLibraryItems({ force: true });
        if (parentModal && document.body.contains(parentModal)) {
            parentModal.__saiTemplateItems = items;
            parentModal.innerHTML = renderTemplateLibraryHtml({ category: 'user', query: '' }, items);
            bindTemplateLibraryModal(parentModal);
        }
    }

    function inferProjectTemplateModelDependency(sourceProject) {
        const nodes = Array.isArray(sourceProject?.nodes) ? sourceProject.nodes : [];
        const presetNodes = nodes.filter(node => node && ['preset', 'classic'].includes(node.type) && node.source?.kind !== 'onboarding_model_status_example');
        if (!presetNodes.length) {
            return {
                mode: 'model_free',
                label: t('Model-free', '无模型依赖'),
                note: t('No runnable Preset or Classic nodes detected.', '未检测到可运行的 Preset 或 Classic 节点。'),
                models: []
            };
        }
        const models = [];
        presetNodes.forEach((node) => {
            const requirements = node.model_requirements || {};
            const modelList = Array.isArray(requirements.model_list) ? requirements.model_list : [];
            modelList.forEach((item) => {
                const name = String(item?.name || item?.path_file || item?.filename || item || '').trim();
                if (name && !models.includes(name)) models.push(name);
            });
        });
        return {
            mode: 'requires_models',
            label: t('Requires models', '需要模型'),
            note: models.length
                ? t('Contains {presetCount} preset node(s) and {modelCount} model requirement(s). Check models before Run.', '包含 {presetCount} 个 preset 节点和 {modelCount} 个模型依赖。运行前请检查模型。')
                    .replace('{presetCount}', presetNodes.length)
                    .replace('{modelCount}', models.length)
                : t('Contains {presetCount} preset node(s). Check model readiness before Run.', '包含 {presetCount} 个 preset 节点。运行前请检查模型就绪状态。')
                    .replace('{presetCount}', presetNodes.length),
            models
        };
    }

    function requestTemplateWorkbenchId(item, defaultId) {
        return new Promise((resolve) => {
            const modal = document.createElement('div');
            modal.className = `sai-canvas-modal sai-template-create-modal ${detectWorkbenchTheme() === 'dark' ? 'theme-dark' : ''}`;
            modal.innerHTML = `
<div class="sai-canvas-modal-panel sai-template-create-panel">
  <div class="sai-canvas-modal-head">
    <span>${escapeHtml(t('Create workbench from template', '从模板新建工作台'))}</span>
    <button type="button" data-template-create-cancel title="${escapeHtml(t('Cancel', '取消'))}" aria-label="${escapeHtml(t('Cancel', '取消'))}"><i class="fa-solid fa-xmark"></i></button>
  </div>
  <form class="sai-template-create-body">
    <label>
      <span>${escapeHtml(item?.title || t('Template', '模板'))}</span>
      <input type="text" data-template-create-id value="${escapeHtml(defaultId)}" autocomplete="off" spellcheck="false">
    </label>
    <div class="sai-template-create-actions">
      <button type="button" data-template-create-cancel>${escapeHtml(t('Cancel', '取消'))}</button>
      <button type="submit" class="primary">${escapeHtml(t('Create', '新建'))}</button>
    </div>
  </form>
</div>`;
            const cleanup = (value) => {
                modal.remove();
                resolve(value);
            };
            modal.addEventListener('click', (evt) => {
                if (evt.target === modal || evt.target.closest('[data-template-create-cancel]')) cleanup(null);
            });
            const form = modal.querySelector('form');
            form?.addEventListener('submit', (evt) => {
                evt.preventDefault();
                const value = modal.querySelector('[data-template-create-id]')?.value || '';
                cleanup(value.trim());
            });
            document.body.appendChild(modal);
            const input = modal.querySelector('[data-template-create-id]');
            input?.focus({ preventScroll: true });
            input?.select();
        });
    }

    async function createWorkbenchFromTemplate(item) {
        const defaultId = sanitizeStoragePart(`${item.id}_${new Date().toISOString().replace(/[-:.TZ]/g, '').slice(0, 14)}`) || `template_${Date.now()}`;
        const nextId = await requestTemplateWorkbenchId(item, defaultId);
        if (!nextId) return;
        const safeId = sanitizeStoragePart(nextId).replace(/[:]/g, '_') || defaultId;
        await saveProject(true, { persist: false });
        setActiveBrowserCacheProject(safeId, storageScope);
        let templateProject = await loadWorkbenchTemplateData(item);
        templateProject = sanitizeProject(templateProject || createDefaultProject());
        const now = nowIso();
        templateProject.id = safeId;
        templateProject.title = item.title || templateProject.title || safeId;
        templateProject.created_at = templateProject.created_at || now;
        templateProject.updated_at = now;
        templateProject.storage = buildProjectStorageInfo(storageKey, storageScope);
        applyTemplateProjectSettings(templateProject, item.source === 'user' ? `user:${item.id}` : item.id);
        project = templateProject;
        syncCanvasProjectAssetRoot(project);
        resetRenderedProjectDomCache();
        refreshCanvasProjectAssetRoot({ render: false }).catch((err) => {
            console.warn('[SimpAI Canvas] template asset root refresh skipped:', err);
        });
        backendLoadedStorageKey = '';
        selectedNodeId = null;
        selectedNodeIds = new Set();
        selectedEdgeId = null;
        selectedGroupId = null;
        resetHistory();
        mutate();
        resetGalleryFrostReveals();
        closeTemplateLibrary();
        showToast(t('Created workbench from template: {id}', '已从模板新建工作台：{id}').replace('{id}', safeId));
    }

    async function switchProjectWithPrompt() {
        const nextId = window.prompt(t('Enter project file name (saved under user directory canvas_workbench/projects)', '输入项目文件名（保存在用户目录 canvas_workbench/projects 下）'), project.id || PROJECT_ID);
        if (!nextId) return;
        const safeId = sanitizeStoragePart(nextId).replace(/[:]/g, '_') || PROJECT_ID;
        const cachedCurrent = await saveProject(true, { persist: false });
        if (!cachedCurrent) {
            showToast(t('Current workbench could not be saved to browser cache; switch cancelled.', '当前工作台无法保存到浏览器缓存，已取消切换。'));
            return;
        }
        setActiveBrowserCacheProject(safeId, storageScope);
        project = loadProject(storageKey, browserCacheProjectScope(storageScope));
        if ((project.id || PROJECT_ID) !== safeId) {
            project.id = safeId;
            project.title = project.title || safeId;
        }
        resetRenderedProjectDomCache();
        backendLoadedStorageKey = '';
        selectedNodeId = null;
        selectedNodeIds = new Set();
        selectedEdgeId = null;
        selectedGroupId = null;
        resetHistory();
        renderAll();
        const ok = await loadProjectFromBackend({ force: false });
        if (!ok) {
            project.storage = buildProjectStorageInfo(storageKey, storageScope);
            await saveProject(true, { persist: false });
            renderAll();
        }
        showToast(t('Switched to project: {id}', '已切换到项目：{id}').replace('{id}', safeId));
    }

    function onDocumentKeyDown(evt) {
        if (!root || root.hidden) return;
        if (textareaEditorState?.modal?.contains?.(evt.target)) return;
        if (isWorkbenchGenerateShortcut(evt)) {
            const agentInput = evt.target?.closest?.('[data-canvas-agent-input]');
            const editable = isEditableElement(evt.target);
            const canRunCanvasAction = isCanvasRunShortcut(evt);
            consumeWorkbenchShortcut(evt);
            if (agentInput && canRunCanvasAction) {
                handleCanvasAgentAction(canvasAgentPrimaryAction());
                return;
            }
            if (canRunCanvasAction && !editable) {
                const node = getNode(selectedNodeId);
                if (evt.shiftKey) runSelectedChain();
                else if (node && (node.type === 'preset' || node.type === 'classic')) runPresetNodeFromUi(node);
                return;
            }
            return;
        }
        if (isEditableElement(evt.target)) return;
        if (evt.key === 'Escape') {
            if (outpaintOverlayState.active) { hideOutpaintOverlay(); renderCanvasAgentPanel(); return; }
            if (connectState) cancelConnection();
            else if (!palette.hidden) closePresetPalette();
            else closeContextMenu();
            return;
        }
        if (evt.key === 'Enter' && outpaintOverlayState.active) {
            evt.preventDefault();
            confirmOutpaintFromOverlay();
            return;
        }
        if (evt.altKey && !evt.ctrlKey && !evt.metaKey) {
            const key = String(evt.key || '').toLowerCase();
            const group = ensureProjectGroups().find(item => String(item.shortcut || '').trim().toLowerCase() === key);
            if (group) {
                evt.preventDefault();
                focusGroup(group);
                return;
            }
        }
        if ((evt.ctrlKey || evt.metaKey) && evt.key.toLowerCase() === 's') {
            evt.preventDefault();
            saveProject(false).catch((err) => console.warn('[SimpAI Canvas] shortcut save failed:', err));
            return;
        }
        if ((evt.ctrlKey || evt.metaKey) && evt.key.toLowerCase() === 'z') {
            evt.preventDefault();
            if (evt.shiftKey) redoCanvasEdit();
            else undoCanvasEdit();
            return;
        }
        if ((evt.ctrlKey || evt.metaKey) && evt.key.toLowerCase() === 'y') {
            evt.preventDefault();
            redoCanvasEdit();
            return;
        }
        if ((evt.ctrlKey || evt.metaKey) && evt.key.toLowerCase() === 'k') {
            evt.preventDefault();
            openPresetPalette(viewportCenterWorld());
            return;
        }
        if ((evt.ctrlKey || evt.metaKey) && evt.key.toLowerCase() === 'c') {
            evt.preventDefault();
            copyCanvasSelection();
            return;
        }
        if ((evt.ctrlKey || evt.metaKey) && evt.key.toLowerCase() === 'v') {
            evt.preventDefault();
            pasteCanvasClipboard(viewportCenterWorld(), { withInputConnections: evt.shiftKey });
            return;
        }
        if ((evt.ctrlKey || evt.metaKey) && evt.key.toLowerCase() === 'd') {
            evt.preventDefault();
            duplicateSelection();
            return;
        }
        if ((evt.ctrlKey || evt.metaKey) && evt.key === '0') {
            evt.preventDefault();
            project.viewport.zoom = 1;
            renderAll({ inspector: false });
            scheduleSave();
            return;
        }
        if ((evt.ctrlKey || evt.metaKey) && (evt.key === '+' || evt.key === '=')) {
            evt.preventDefault();
            zoomAtViewportCenter(1.15);
            return;
        }
        if ((evt.ctrlKey || evt.metaKey) && evt.key === '-') {
            evt.preventDefault();
            zoomAtViewportCenter(1 / 1.15);
            return;
        }
        if ((evt.ctrlKey || evt.metaKey) && evt.key === 'Enter') {
            const node = getNode(selectedNodeId);
            if (evt.shiftKey) runSelectedChain();
            else if (node && (node.type === 'preset' || node.type === 'classic')) runPresetNodeFromUi(node);
            return;
        }
        if (!evt.ctrlKey && !evt.metaKey && !evt.altKey && evt.code === 'Space') {
            const node = getNode(selectedNodeId);
            if (node?.type === 'timeline') {
                evt.preventDefault();
                toggleTimelinePreviewPlayback(node);
                return;
            }
            if (node && ['video', 'audio'].includes(node.type)) {
                evt.preventDefault();
                playMediaSelection(node);
                return;
            }
            if (node?.type === 'result') {
                const media = nodesLayer?.querySelector(`[data-node-id="${cssEscape(node.id)}"] video, [data-node-id="${cssEscape(node.id)}"] audio`);
                if (media) {
                    evt.preventDefault();
                    if (media.paused) media.play().catch(() => {});
                    else media.pause();
                    return;
                }
            }
        }
        if (evt.shiftKey && (evt.key === '!' || evt.code === 'Digit1')) {
            evt.preventDefault();
            fitAll();
            return;
        }
        if (evt.shiftKey && (evt.key === '@' || evt.code === 'Digit2')) {
            evt.preventDefault();
            fitSelection();
            return;
        }
        if (evt.shiftKey && ['ArrowLeft', 'ArrowRight', 'ArrowUp', 'ArrowDown'].includes(evt.key)) {
            evt.preventDefault();
            const alignMap = {
                ArrowLeft: 'left',
                ArrowRight: 'right',
                ArrowUp: 'top',
                ArrowDown: 'bottom'
            };
            alignSelectedNodes(alignMap[evt.key]);
            return;
        }
        if (evt.key === 'Delete' || evt.key === 'Backspace') {
            deleteSelection();
            return;
        }
        if (evt.key.toLowerCase() === 'h') setMode('hand');
        if (evt.key.toLowerCase() === 'v') setMode('select');
        if (evt.key.toLowerCase() === 'c') setMode('connect');
        if (evt.key.toLowerCase() === 'p') {
            evt.preventDefault();
            toggleSelectedNodesFlag('locked');
            return;
        }
        if (evt.key.toLowerCase() === 'i') importSelectedTransferAt(viewportCenterWorld());
    }

    function isWorkbenchGenerateShortcut(evt) {
        return !!evt && (evt.key === 'Enter' || evt.keyCode === 13) && (evt.ctrlKey || evt.metaKey || evt.altKey);
    }

    function isCanvasRunShortcut(evt) {
        return !!evt && (evt.key === 'Enter' || evt.keyCode === 13) && (evt.ctrlKey || evt.metaKey) && !evt.altKey && !evt.isComposing;
    }

    function consumeWorkbenchShortcut(evt) {
        if (!evt) return;
        evt.preventDefault();
        evt.stopPropagation();
        if (typeof evt.stopImmediatePropagation === 'function') evt.stopImmediatePropagation();
    }

    function isEditableElement(target) {
        if (!target || !target.closest) return false;
        return !!target.closest('input,textarea,select,[contenteditable="true"]');
    }

    function nodeHasActiveEditable(nodeEl) {
        const active = document.activeElement;
        return !!(nodeEl && active && active !== document.body && nodeEl.contains(active) && isEditableElement(active));
    }

    function openGroupListPanel() {
        return WORKBENCH_GROUP_LIST.openPanel({
            addAreaGroup,
            ensureWorkbenchFormFieldNames,
            focusGroup,
            getGroup,
            getGroups: ensureProjectGroups,
            getNodesInsideGroup,
            groupShortcutLabel,
            detectWorkbenchTheme,
            normalizeCanvasColor,
            viewportCenterWorld
        });
    }

    async function onDocumentPaste(evt) {
        if (!root || root.hidden || isEditableElement(evt.target)) return;
        const items = Array.from(evt.clipboardData?.items || []);
        const imageItems = items.filter(item => item.type && item.type.startsWith('image/'));
        if (!imageItems.length) return;
        evt.preventDefault();
        let offset = 0;
        const base = viewportCenterWorld();
        for (const item of imageItems) {
            const file = item.getAsFile();
            if (!file) continue;
            await addImageNodeFromFile(file, { x: base.x + offset, y: base.y + offset });
            offset += 28;
        }
    }

    function clientToWorld(clientX, clientY) {
        const rect = viewport.getBoundingClientRect();
        const z = project.viewport.zoom || 1;
        return {
            x: Math.round((clientX - rect.left - project.viewport.x) / z),
            y: Math.round((clientY - rect.top - project.viewport.y) / z)
        };
    }

    function viewportCenterWorld() {
        const rect = viewport.getBoundingClientRect();
        return clientToWorld(rect.left + rect.width / 2, rect.top + rect.height / 2);
    }

    function zoomAtViewportCenter(factor) {
        const rect = viewport.getBoundingClientRect();
        zoomAtClient(rect.left + rect.width / 2, rect.top + rect.height / 2, factor);
    }

    function zoomAtClient(clientX, clientY, factor) {
        const before = clientToWorld(clientX, clientY);
        const oldZoom = project.viewport.zoom || 1;
        const nextZoom = clamp(oldZoom * factor, 0.15, 3);
        if (Math.abs(nextZoom - oldZoom) < 0.0001) return;
        const rect = viewport.getBoundingClientRect();
        cancelPanEdgeSettleRender();
        cancelDragEdgeSettleRender();
        endDragEdgeLodVisual();
        beginWheelPreviewLod(oldZoom, nextZoom);
        project.viewport.zoom = nextZoom;
        project.viewport.x = Math.round(clientX - rect.left - before.x * nextZoom);
        project.viewport.y = Math.round(clientY - rect.top - before.y * nextZoom);
        preferSvgEdgesForViewportInteraction(5000);
        applyViewport();
        scheduleViewportNodeRender();
        scheduleViewportZoomSettleRender();
        renderStatus();
        updateMinimapForViewportInteraction();
        scheduleViewportSave();
    }

    function fitAll() {
        if (!project.nodes.length && !ensureProjectGroups().length) {
            centerCanvas();
            return;
        }
        const bounds = getNodesBounds();
        const rect = viewport.getBoundingClientRect();
        const width = Math.max(1, bounds.maxX - bounds.minX);
        const height = Math.max(1, bounds.maxY - bounds.minY);
        const zoom = clamp(Math.min((rect.width - 180) / width, (rect.height - 140) / height), 0.15, 1.5);
        project.viewport.zoom = zoom;
        project.viewport.x = Math.round(rect.width / 2 - (bounds.minX + width / 2) * zoom);
        project.viewport.y = Math.round(rect.height / 2 - (bounds.minY + height / 2) * zoom);
        renderAll({ inspector: false });
        scheduleSave();
    }

    function fitSelection() {
        if (selectedGroupId) {
            focusGroup(getGroup(selectedGroupId));
            return;
        }
        const node = getNode(selectedNodeId);
        if (!node) {
            fitAll();
            return;
        }
        const rect = viewport.getBoundingClientRect();
        const size = defaultNodeSize(node.type);
        const w = node.w || size.w;
        const h = node.h || size.h;
        const zoom = clamp(Math.min((rect.width - 180) / Math.max(1, w), (rect.height - 140) / Math.max(1, h)), 0.3, 1.6);
        project.viewport.zoom = zoom;
        project.viewport.x = Math.round(rect.width / 2 - ((node.x || 0) + w / 2) * zoom);
        project.viewport.y = Math.round(rect.height / 2 - ((node.y || 0) + h / 2) * zoom);
        renderAll({ inspector: false });
        scheduleSave();
    }

    function centerCanvas() {
        const rect = viewport.getBoundingClientRect();
        project.viewport.x = Math.round(rect.width / 2);
        project.viewport.y = Math.round(rect.height / 2);
        project.viewport.zoom = 1;
        renderAll({ inspector: false });
        scheduleSave();
    }

    function getNodesBounds() {
        let minX = Infinity;
        let minY = Infinity;
        let maxX = -Infinity;
        let maxY = -Infinity;
        for (const node of project.nodes) {
            const size = defaultNodeSize(node.type);
            const x = node.x || 0;
            const y = node.y || 0;
            const w = node.w || size.w;
            const h = node.h || size.h;
            minX = Math.min(minX, x);
            minY = Math.min(minY, y);
            maxX = Math.max(maxX, x + w);
            maxY = Math.max(maxY, y + h);
        }
        for (const group of ensureProjectGroups()) {
            const rect = getGroupRect(group);
            minX = Math.min(minX, rect.x);
            minY = Math.min(minY, rect.y);
            maxX = Math.max(maxX, rect.x + rect.w);
            maxY = Math.max(maxY, rect.y + rect.h);
        }
        if (!Number.isFinite(minX)) return { minX: 0, minY: 0, maxX: 1, maxY: 1 };
        return { minX, minY, maxX, maxY };
    }

    async function importSelectedTransferAt(world) {
        if (!window.SimpAITransferStation) {
            showToast(t('Transfer Station API is not ready.', '中转站 API 未就绪'));
            return;
        }
        let items = [];
        if (typeof window.SimpAITransferStation.getItems === 'function') {
            items = await window.SimpAITransferStation.getItems({ dataUrl: true, file: false });
        } else if (typeof window.SimpAITransferStation.getAllItems === 'function') {
            items = await window.SimpAITransferStation.getAllItems({ dataUrl: true, file: false });
        } else if (typeof window.SimpAITransferStation.getSelectedItem === 'function') {
            const item = await window.SimpAITransferStation.getSelectedItem({ dataUrl: true, file: false });
            if (item) items = [item];
        }
        if (!items.length) {
            showToast(t('Transfer Station has no importable images.', '中转站没有可导入图片'));
            return;
        }
        let offset = 0;
        for (const item of items) {
            await addImageNodeFromTransferItem(item, { x: world.x + offset, y: world.y + offset });
            offset += 28;
        }
        showToast(t('Imported {count} transfer-station image(s).', '已导入 {count} 张中转站图片').replace('{count}', items.length));
    }

    async function importTransferItemAt(id, world) {
        if (!window.SimpAITransferStation || typeof window.SimpAITransferStation.getItem !== 'function') {
            showToast(t('Transfer Station API is not ready.', '中转站 API 未就绪'));
            return;
        }
        const item = await window.SimpAITransferStation.getItem(id, { dataUrl: true, file: false });
        if (!item) return;
        await addImageNodeFromTransferItem(item, world);
    }

    function openImageFilePicker(world) {
        importFileInput = importFileInput || document.createElement('input');
        importFileInput.type = 'file';
        importFileInput.accept = 'image/*,video/*,audio/*';
        importFileInput.multiple = false;
        try { importFileInput.webkitdirectory = false; } catch (err) {}
        try { importFileInput.directory = false; } catch (err) {}
        importFileInput.removeAttribute('webkitdirectory');
        importFileInput.removeAttribute('directory');
        importFileInput.hidden = true;
        if (!importFileInput.isConnected) document.body.appendChild(importFileInput);
        importFileInput.onchange = async () => {
            const files = Array.from(importFileInput.files || []).filter(isMediaFile).slice(0, 1);
            let offset = 0;
            for (const file of files) {
                await addMediaNodeFromFile(file, { x: world.x + offset, y: world.y + offset });
                offset += 28;
            }
            importFileInput.value = '';
            if (files.length) showToast(t('Imported {count} local media file(s).', '已导入 {count} 个本地媒体').replace('{count}', files.length));
        };
        importFileInput.click();
    }

    function mediaBrowserInitialState(world) {
        return {
            tab: 'outputs',
            mediaType: 'image',
            folder: '',
            query: '',
            danbooruQuery: '',
            rating: 'all',
            page: 1,
            selectedId: '',
            world: {
                x: Math.round(Number(world?.x || 0)),
                y: Math.round(Number(world?.y || 0))
            }
        };
    }

    function normalizeMediaBrowserState(value, world) {
        const base = mediaBrowserInitialState(world || viewportCenterWorld());
        const state = Object.assign({}, base, value && typeof value === 'object' ? value : {});
        state.tab = state.tab === 'danbooru' ? 'danbooru' : 'outputs';
        state.mediaType = state.mediaType === 'video' ? 'video' : 'image';
        state.folder = String(state.folder || '').replace(/\\/g, '/').replace(/^\/+|\/+$/g, '');
        state.query = String(state.query || '');
        state.danbooruQuery = String(state.danbooruQuery || '');
        state.rating = state.rating || 'all';
        state.page = Math.max(1, Number(state.page || 1) || 1);
        state.selectedId = String(state.selectedId || '');
        state.world = {
            x: Math.round(Number(state.world?.x ?? world?.x ?? base.world.x ?? 0)),
            y: Math.round(Number(state.world?.y ?? world?.y ?? base.world.y ?? 0))
        };
        return state;
    }

    function serializableMediaBrowserState(state) {
        const next = normalizeMediaBrowserState(state || {});
        return {
            tab: next.tab,
            mediaType: next.mediaType,
            folder: next.folder,
            query: next.query,
            danbooruQuery: next.danbooruQuery,
            rating: next.rating,
            page: next.page,
            selectedId: next.selectedId
        };
    }

    function mediaBrowserNodeState(node) {
        return normalizeMediaBrowserState(node?.media_browser || node?.params || {}, {
            x: Number(node?.x || 0) + Number(node?.w || defaultNodeSize('media_browser').w || 0) + 48,
            y: Number(node?.y || 0)
        });
    }

    function saveMediaBrowserNodeState(node, state, options) {
        if (!node || node.type !== 'media_browser' || isNodeLocked(node)) return;
        if (options?.history) pushHistoryBatch(`media-browser:${node.id}:${options.history}`, 'Edit media browser');
        node.media_browser = serializableMediaBrowserState(state);
        scheduleSave();
    }

    function mediaBrowserRuntimeFor(nodeId) {
        const id = String(nodeId || '');
        if (!id) return { data: { ok: true, items: [], folders: [] }, loading: false, version: 0, error: '' };
        if (!mediaBrowserNodeRuntime.has(id)) {
            mediaBrowserNodeRuntime.set(id, {
                data: { ok: true, items: [], folders: [] },
                loading: false,
                frostRevealed: false,
                version: 0,
                error: ''
            });
        }
        return mediaBrowserNodeRuntime.get(id);
    }

    function mediaBrowserRuntimeSignature(nodeId) {
        const runtime = mediaBrowserRuntimeFor(nodeId);
        const data = runtime.data || {};
        const items = Array.isArray(data.items) ? data.items : [];
        const folders = Array.isArray(data.folders) ? data.folders : [];
        return JSON.stringify({
            loading: !!runtime.loading,
            loadingMore: !!runtime.loadingMore,
            version: runtime.version || 0,
            frost_revealed: !!runtime.frostRevealed,
            ok: data.ok !== false,
            error: runtime.error || data.error || '',
            truncated: !!data.truncated,
            has_more: !!data.has_more,
            next_offset: data.next_offset ?? '',
            next_page: data.next_page ?? '',
            folders: folders.slice(0, 120),
            items: items.map(item => [
                item?.id || '',
                item?.name || '',
                item?.preview_url || '',
                item?.media_type || '',
                item?.size || '',
                item?.updated_at || '',
                item?.width || '',
                item?.height || ''
            ])
        });
    }

    async function fetchMediaBrowserData(state, options) {
        const limit = Number(options?.limit || MEDIA_BROWSER_PAGE_SIZE);
        if (state.tab === 'danbooru') {
            const pageState = Object.assign({}, state, {
                page: Math.max(1, Number(options?.page || state.page || 1) || 1)
            });
            return fetchDanbooruGalleryPosts(pageState);
        }
        if (typeof WORKBENCH_API.mediaGallery !== 'function') {
            return { ok: false, error: 'media gallery API is not loaded', items: [] };
        }
        return WORKBENCH_API.mediaGallery({
            media_type: state.mediaType,
            folder: state.folder,
            query: state.query,
            limit,
            offset: Math.max(0, Number(options?.offset || 0) || 0),
            include_dimensions: true,
            include_metadata: true,
            max_seconds: 5
        });
    }

    function mergeMediaBrowserPage(existing, page, append) {
        const pageData = page || { ok: false, error: 'empty media browser response', items: [] };
        if (append && pageData.ok === false) {
            return Object.assign({}, existing || {}, {
                ok: false,
                error: pageData.error || pageData.details || 'Load failed',
                load_more_error: pageData.error || pageData.details || 'Load failed'
            });
        }
        const baseItems = append && Array.isArray(existing?.items) ? existing.items : [];
        const pageItems = Array.isArray(pageData.items) ? pageData.items : [];
        const seen = new Set(baseItems.map(item => String(item?.id || '')));
        const mergedItems = baseItems.concat(pageItems.filter(item => {
            const id = String(item?.id || '');
            if (!id || seen.has(id)) return false;
            seen.add(id);
            return true;
        }));
        const nextOffset = pageData.next_offset ?? (append ? mergedItems.length : pageItems.length);
        return Object.assign({}, append ? (existing || {}) : {}, pageData, {
            ok: pageData.ok !== false,
            items: mergedItems,
            has_more: !!(pageData.has_more || pageData.truncated),
            next_offset: pageData.has_more || pageData.truncated ? nextOffset : null,
            loaded_count: mergedItems.length
        });
    }

    function selectedMediaBrowserItemFrom(state, data) {
        const selectedId = String(state?.selectedId || '');
        const items = Array.isArray(data?.items) ? data.items : [];
        return items.find(item => String(item.id || '') === selectedId) || null;
    }

    function captureMediaBrowserScroll(scope, memoryKey) {
        const grid = scope?.querySelector?.('.sai-media-browser-grid') || null;
        if (!grid) return memoryKey ? (mediaBrowserScrollMemory.get(memoryKey) || null) : null;
        const state = {
            top: grid.scrollTop || 0,
            left: grid.scrollLeft || 0,
            height: grid.scrollHeight || 0,
            clientHeight: grid.clientHeight || 0,
            capturedAt: performance.now()
        };
        if (memoryKey) mediaBrowserScrollMemory.set(memoryKey, state);
        return state;
    }

    function restoreMediaBrowserScroll(scope, state, memoryKey) {
        const target = state || (memoryKey ? mediaBrowserScrollMemory.get(memoryKey) : null);
        if (!target) return;
        const applyRestore = () => {
            const grid = scope?.querySelector?.('.sai-media-browser-grid') || null;
            if (!grid) return false;
            const maxTop = Math.max(0, (grid.scrollHeight || 0) - (grid.clientHeight || 0));
            grid.scrollTop = Math.min(Math.max(0, Number(target.top || 0)), maxTop);
            grid.scrollLeft = Math.max(0, Number(target.left || 0));
            if (memoryKey) {
                mediaBrowserScrollMemory.set(memoryKey, Object.assign({}, target, {
                    top: grid.scrollTop || 0,
                    left: grid.scrollLeft || 0,
                    height: grid.scrollHeight || 0,
                    clientHeight: grid.clientHeight || 0,
                    capturedAt: performance.now()
                }));
            }
            return true;
        };
        if (!applyRestore()) return;
        requestAnimationFrame(applyRestore);
        window.setTimeout(applyRestore, 180);
    }

    function openMediaBrowserPanel(world, initialState) {
        const existing = document.querySelector('.sai-media-browser-modal');
        if (existing) existing.remove();
        const modal = document.createElement('div');
        modal.className = `sai-canvas-modal sai-media-browser-modal ${detectWorkbenchTheme() === 'dark' ? 'theme-dark' : ''}`;
        modal.__mediaBrowserState = normalizeMediaBrowserState(initialState || mediaBrowserInitialState(world || viewportCenterWorld()), world || viewportCenterWorld());
        modal.__mediaBrowserData = { ok: true, items: [], folders: [] };
        modal.addEventListener('click', async (evt) => {
            if (evt.target === modal || evt.target.closest('[data-modal-close]')) {
                modal.remove();
                return;
            }
            const frostArea = evt.target.closest('.sai-media-browser-main');
            if (frostArea && revealGalleryFrostArea(modal)) {
                evt.preventDefault();
                evt.stopPropagation();
                return;
            }
            const tabButton = evt.target.closest('[data-media-browser-tab]');
            if (tabButton) {
                modal.__mediaBrowserState.tab = tabButton.getAttribute('data-media-browser-tab') || 'outputs';
                modal.__mediaBrowserState.selectedId = '';
                modal.__mediaBrowserState.page = 1;
                await refreshMediaBrowserPanel(modal);
                return;
            }
            const mediaTypeButton = evt.target.closest('[data-media-browser-type]');
            if (mediaTypeButton) {
                modal.__mediaBrowserState.mediaType = mediaTypeButton.getAttribute('data-media-browser-type') || 'image';
                modal.__mediaBrowserState.selectedId = '';
                await refreshMediaBrowserPanel(modal);
                return;
            }
            const itemButton = evt.target.closest('[data-media-browser-item]');
            if (itemButton) {
                modal.__mediaBrowserState.selectedId = itemButton.getAttribute('data-media-browser-item') || '';
                renderMediaBrowserPanel(modal);
                if (evt.detail >= 2) await importSelectedMediaBrowserItem(modal);
                return;
            }
            const actionButton = evt.target.closest('[data-media-browser-action]');
            if (!actionButton) return;
            const action = actionButton.getAttribute('data-media-browser-action');
            if (action === 'refresh' || action === 'search' || action === 'reconnect') {
                readMediaBrowserFields(modal);
                await refreshMediaBrowserPanel(modal);
            } else if (action === 'load-more') {
                await loadMoreMediaBrowserPanel(modal);
            } else if (action === 'page-prev') {
                modal.__mediaBrowserState.page = Math.max(1, Number(modal.__mediaBrowserState.page || 1) - 1);
                await refreshMediaBrowserPanel(modal);
            } else if (action === 'page-next') {
                modal.__mediaBrowserState.page = Math.max(1, Number(modal.__mediaBrowserState.page || 1) + 1);
                await refreshMediaBrowserPanel(modal);
            } else if (action === 'import') {
                await importSelectedMediaBrowserItem(modal);
            } else if (action === 'copy-prompt') {
                await copySelectedMediaBrowserPrompt(modal);
            } else if (action === 'apply-prompt') {
                applySelectedMediaBrowserPromptToTarget(modal);
            } else if (action === 'delete-local') {
                await deleteSelectedMediaBrowserPanelItem(modal);
            }
        });
        modal.addEventListener('change', async (evt) => {
            const frostToggle = evt.target.closest('[data-media-browser-frost]');
            if (frostToggle) {
                setGalleryFrostEnabled(!!frostToggle.checked);
                renderMediaBrowserPanel(modal);
                renderNodes();
                return;
            }
            const field = evt.target.closest('[data-media-browser-field]');
            if (!field) return;
            readMediaBrowserFields(modal);
            modal.__mediaBrowserState.selectedId = '';
            if (field.getAttribute('data-media-browser-field') === 'rating') modal.__mediaBrowserState.page = 1;
            await refreshMediaBrowserPanel(modal);
        });
        modal.addEventListener('keydown', async (evt) => {
            if (evt.key !== 'Enter') return;
            const field = evt.target.closest('[data-media-browser-search]');
            if (!field) return;
            evt.preventDefault();
            readMediaBrowserFields(modal);
            modal.__mediaBrowserState.page = 1;
            await refreshMediaBrowserPanel(modal);
        });
        modal.addEventListener('scroll', (evt) => {
            const grid = evt.target?.closest?.('.sai-media-browser-grid');
            if (grid) maybeAutoLoadMoreMediaBrowserPanel(modal, grid);
        }, true);
        document.body.appendChild(modal);
        renderMediaBrowserPanel(modal, true);
        refreshMediaBrowserPanel(modal).catch((err) => {
            modal.__mediaBrowserData = { ok: false, error: err?.message || String(err || 'media browser failed'), items: [] };
            renderMediaBrowserPanel(modal);
        });
    }

    function readMediaBrowserFields(modal) {
        const state = modal.__mediaBrowserState || mediaBrowserInitialState(viewportCenterWorld());
        const localQuery = modal.querySelector('[data-media-browser-search="outputs"]');
        const danbooruQuery = modal.querySelector('[data-media-browser-search="danbooru"]');
        const folder = modal.querySelector('[data-media-browser-field="folder"]');
        const rating = modal.querySelector('[data-media-browser-field="rating"]');
        if (localQuery) state.query = localQuery.value || '';
        if (danbooruQuery) state.danbooruQuery = danbooruQuery.value || '';
        if (folder) state.folder = folder.value || '';
        if (rating) state.rating = rating.value || 'all';
        modal.__mediaBrowserState = state;
        return state;
    }

    async function refreshMediaBrowserPanel(modal) {
        const state = readMediaBrowserFields(modal);
        modal.__mediaBrowserLoadingMore = false;
        renderMediaBrowserPanel(modal, true);
        let data;
        try {
            data = await fetchMediaBrowserData(state, { limit: MEDIA_BROWSER_PAGE_SIZE, offset: 0 });
        } catch (err) {
            data = { ok: false, error: err?.message || String(err || 'media browser failed'), items: [] };
        }
        modal.__mediaBrowserData = mergeMediaBrowserPage(null, data, false);
        const items = Array.isArray(modal.__mediaBrowserData.items) ? modal.__mediaBrowserData.items : [];
        if (!items.some(item => String(item.id || '') === String(state.selectedId || ''))) {
            state.selectedId = items[0]?.id || '';
        }
        renderMediaBrowserPanel(modal, false);
        scheduleMediaBrowserPaintRefresh(modal);
    }

    async function loadMoreMediaBrowserPanel(modal) {
        if (!modal || modal.__mediaBrowserLoadingMore) return;
        const current = modal.__mediaBrowserData || {};
        if (!current.has_more && !current.truncated) return;
        const state = readMediaBrowserFields(modal);
        modal.__mediaBrowserLoadingMore = true;
        renderMediaBrowserPanel(modal, false);
        try {
            let page;
            if (state.tab === 'danbooru') {
                const nextPage = Math.max(1, Number(current.next_page || (Number(current.page || state.page || 1) + 1)) || 1);
                page = await fetchMediaBrowserData(state, { limit: MEDIA_BROWSER_PAGE_SIZE, page: nextPage });
                state.page = nextPage;
            } else {
                page = await fetchMediaBrowserData(state, {
                    limit: MEDIA_BROWSER_PAGE_SIZE,
                    offset: Number(current.next_offset ?? current.items?.length ?? 0) || 0
                });
            }
            modal.__mediaBrowserData = mergeMediaBrowserPage(current, page, true);
            modal.__mediaBrowserState = state;
        } finally {
            modal.__mediaBrowserLoadingMore = false;
            renderMediaBrowserPanel(modal, false);
            scheduleMediaBrowserPaintRefresh(modal);
        }
    }

    function mediaBrowserShouldAutoLoadMore(scroller) {
        if (!scroller) return false;
        return (scroller.scrollHeight - scroller.scrollTop - scroller.clientHeight) < 360;
    }

    function maybeAutoLoadMoreMediaBrowserPanel(modal, scroller) {
        if (!mediaBrowserShouldAutoLoadMore(scroller)) return;
        const data = modal?.__mediaBrowserData || {};
        if (!data.has_more || modal.__mediaBrowserLoadingMore) return;
        loadMoreMediaBrowserPanel(modal).catch((err) => console.warn('[SimpAI Canvas] media browser modal stream load failed', err));
    }

    function primeMediaBrowserThumbImages(modal) {
        const images = Array.from(modal?.querySelectorAll?.('.sai-media-browser-thumb img') || []).slice(0, 48);
        images.forEach((img, index) => {
            try {
                img.loading = 'eager';
                img.fetchPriority = index < 16 ? 'high' : 'auto';
                if (typeof img.decode === 'function' && !img.complete) img.decode().catch(() => {});
            } catch (err) {}
        });
    }

    function nudgeMediaBrowserPaint(modal) {
        const grid = modal?.querySelector?.('.sai-media-browser-grid');
        if (!grid) return;
        try {
            grid.style.transform = 'translateZ(0)';
            grid.getBoundingClientRect();
            requestAnimationFrame(() => {
                if (grid.isConnected) grid.style.transform = '';
            });
        } catch (err) {}
    }

    function scheduleMediaBrowserPaintRefresh(modal) {
        if (!modal || !modal.isConnected) return;
        const seq = (Number(modal.__mediaBrowserPaintSeq || 0) + 1);
        modal.__mediaBrowserPaintSeq = seq;
        requestAnimationFrame(() => {
            if (!modal.isConnected || modal.__mediaBrowserPaintSeq !== seq) return;
            primeMediaBrowserThumbImages(modal);
            nudgeMediaBrowserPaint(modal);
            window.setTimeout(() => {
                if (!modal.isConnected || modal.__mediaBrowserPaintSeq !== seq) return;
                renderMediaBrowserPanel(modal, false);
                requestAnimationFrame(() => {
                    if (!modal.isConnected || modal.__mediaBrowserPaintSeq !== seq) return;
                    primeMediaBrowserThumbImages(modal);
                    nudgeMediaBrowserPaint(modal);
                });
            }, 140);
        });
    }

    function mediaBrowserCompactStatus(value) {
        return String(value || '').replace(/\s+/g, ' ').trim();
    }

    function renderMediaBrowserPanel(modal, loading) {
        syncGalleryFrostClass();
        modal.classList.toggle('sai-media-browser-frost-enabled', isGalleryFrostEnabled());
        const scrollState = loading ? null : captureMediaBrowserScroll(modal);
        const state = modal.__mediaBrowserState || mediaBrowserInitialState(viewportCenterWorld());
        const data = modal.__mediaBrowserData || { ok: true, items: [], folders: [] };
        const items = Array.isArray(data.items) ? data.items : [];
        const selected = selectedMediaBrowserItem(modal);
        const isDanbooru = state.tab === 'danbooru';
        const loadingMore = !!modal.__mediaBrowserLoadingMore;
        let status = loading
            ? t('Loading...', '加载中...')
            : (data.ok ? `${items.length} ${t('items', '项')}${data.truncated ? ` · ${t('truncated', '已截断')}` : ''}` : (data.error || t('Load failed', '加载失败')));
        if (!loading) {
            status = data.ok !== false
                ? `${items.length} ${t('items', '项')}${data.has_more ? ` / ${t('more available', '还有更多')}` : ''}${loadingMore ? ` / ${t('loading more...', '正在加载更多...')}` : ''}`
                : (data.load_more_error || data.error || t('Load failed', '加载失败'));
        }
        const statusText = mediaBrowserCompactStatus(status);
        modal.innerHTML = `
<div class="sai-canvas-modal-panel sai-media-browser-panel">
  <div class="sai-canvas-modal-head">
    <h3>${escapeHtml(t('Media Browser', '媒体浏览器'))}</h3>
    <button type="button" data-modal-close title="${escapeHtml(t('Close', '关闭'))}"><i class="fa-solid fa-xmark"></i></button>
  </div>
  <div class="sai-media-browser-tabs">
    <button type="button" data-media-browser-tab="outputs" class="${state.tab === 'outputs' ? 'is-active' : ''}"><i class="fa-solid fa-photo-film"></i><span>${escapeHtml(t('Outputs', '输出'))}</span></button>
    <button type="button" data-media-browser-tab="danbooru" class="${isDanbooru ? 'is-active' : ''}"><i class="fa-solid fa-globe"></i><span>Danbooru</span></button>
    <label class="sai-media-browser-frost" title="${escapeHtml(t('Blur media previews by default', '默认模糊媒体预览'))}"><input type="checkbox" data-media-browser-frost ${isGalleryFrostEnabled() ? 'checked' : ''}><span>${escapeHtml(t('Blur', '模糊'))}</span></label>
  </div>
  ${isDanbooru ? renderDanbooruBrowserControls(state) : renderOutputBrowserControls(state, data)}
  <div class="sai-media-browser-main">
    <div class="sai-media-browser-grid">${loading ? renderMediaBrowserLoadingCards() : renderMediaBrowserItems(items, state.selectedId, isDanbooru, data)}</div>
    <aside class="sai-media-browser-detail">${renderMediaBrowserDetail(selected, isDanbooru)}</aside>
  </div>
  <div class="sai-canvas-modal-foot sai-media-browser-foot">
    <span title="${escapeHtml(statusText)}">${escapeHtml(statusText)}</span>
    <div>
      ${data.has_more ? `<button type="button" data-media-browser-action="load-more" ${loadingMore ? 'disabled' : ''}><i class="fa-solid ${loadingMore ? 'fa-spinner fa-spin' : 'fa-angles-down'}"></i><span>${escapeHtml(loadingMore ? t('Loading...', '正在加载...') : t('Load more', '加载更多'))}</span></button>` : ''}
      ${selected && !isDanbooru ? `<button type="button" class="is-danger" data-media-browser-action="delete-local"><i class="fa-solid fa-trash"></i><span>${escapeHtml(t('Delete file', '删除文件'))}</span></button>` : ''}
      ${mediaBrowserItemPrompt(selected) ? `<button type="button" data-media-browser-action="copy-prompt"><i class="fa-solid fa-copy"></i><span>${escapeHtml(t('Copy prompt', '复制提示词'))}</span></button>` : ''}
      ${mediaBrowserItemPrompt(selected) ? `<button type="button" data-media-browser-action="apply-prompt"><i class="fa-solid fa-pen-to-square"></i><span>${escapeHtml(t('Fill generator', '填入生成节点'))}</span></button>` : ''}
      <button type="button" data-media-browser-action="${isDanbooru ? 'reconnect' : 'refresh'}"><i class="fa-solid fa-rotate"></i><span>${escapeHtml(isDanbooru ? t('Reconnect', '重连') : t('Refresh', '刷新'))}</span></button>
      <button type="button" data-media-browser-action="import" ${selected ? '' : 'disabled'}><i class="fa-solid fa-plus"></i><span>${escapeHtml(t('Add to canvas', '加入画布'))}</span></button>
    </div>
  </div>
</div>`;
        ensureWorkbenchFormFieldNames(modal, 'media_browser');
        if (!loading) restoreMediaBrowserScroll(modal, scrollState);
    }

    function renderMediaBrowserNodeHtml(node) {
        syncGalleryFrostClass();
        const state = mediaBrowserNodeState(node);
        const runtime = mediaBrowserRuntimeFor(node.id);
        const data = runtime.data || { ok: true, items: [], folders: [] };
        const items = Array.isArray(data.items) ? data.items : [];
        const selected = selectedMediaBrowserItemFrom(state, data);
        const isDanbooru = state.tab === 'danbooru';
        const loading = !!runtime.loading;
        const loadingMore = !!runtime.loadingMore;
        const status = loading
            ? t('Loading...', '正在加载...')
            : (data.ok !== false ? `${items.length} ${t('items', '项')}${data.has_more ? ` / ${t('more available', '还有更多')}` : ''}${loadingMore ? ` / ${t('loading more...', '正在加载更多...')}` : ''}` : (runtime.error || data.error || t('Load failed', '加载失败')));
        const statusText = mediaBrowserCompactStatus(status);
        const mainFrostAttr = runtime.frostRevealed ? ' data-sai-frost-revealed="1"' : '';
        return `
<div class="sai-node-head">
  <span class="sai-node-kind">${escapeHtml(t('Browser', '浏览器'))}</span>
  <span class="sai-node-title">${escapeHtml(localizedDefaultTitle(node.title, 'Media Browser', '媒体浏览器'))}</span>
  ${renderNodeStateBadges(node)}
  <button type="button" data-media-browser-action="refresh" title="${escapeHtml(t('Refresh', '刷新'))}"><i class="fa-solid fa-rotate"></i></button>
  <button type="button" data-media-browser-action="open-modal" title="${escapeHtml(t('Open floating browser', '打开浮动浏览器'))}"><i class="fa-solid fa-up-right-from-square"></i></button>
  <button type="button" data-node-action="delete" title="${escapeHtml(t('Delete', '删除'))}"><i class="fa-solid fa-xmark"></i></button>
</div>
<div class="sai-media-browser-node">
  <div class="sai-media-browser-tabs">
    <button type="button" data-media-browser-tab="outputs" class="${state.tab === 'outputs' ? 'is-active' : ''}"><i class="fa-solid fa-photo-film"></i><span>${escapeHtml(t('Outputs', '输出'))}</span></button>
    <button type="button" data-media-browser-tab="danbooru" class="${isDanbooru ? 'is-active' : ''}"><i class="fa-solid fa-globe"></i><span>Danbooru</span></button>
    <label class="sai-media-browser-frost" title="${escapeHtml(t('Blur media previews by default', '默认模糊媒体预览'))}"><input type="checkbox" data-media-browser-frost ${isGalleryFrostEnabled() ? 'checked' : ''}><span>${escapeHtml(t('Blur', '模糊'))}</span></label>
  </div>
  ${isDanbooru ? renderDanbooruBrowserControls(state) : renderOutputBrowserControls(state, data)}
  <div class="sai-media-browser-main"${mainFrostAttr}>
    <div class="sai-media-browser-grid">${loading ? renderMediaBrowserLoadingCards() : renderMediaBrowserItems(items, state.selectedId, isDanbooru, data)}</div>
    <aside class="sai-media-browser-detail">${renderMediaBrowserDetail(selected, isDanbooru)}</aside>
  </div>
  <div class="sai-media-browser-foot">
    <span title="${escapeHtml(statusText)}">${escapeHtml(statusText)}</span>
    <div>
      ${mediaBrowserItemPrompt(selected) ? `<button type="button" data-media-browser-action="copy-prompt"><i class="fa-solid fa-copy"></i><span>${escapeHtml(t('Prompt', '提示词'))}</span></button>` : ''}
      ${mediaBrowserItemPrompt(selected) ? `<button type="button" data-media-browser-action="apply-prompt"><i class="fa-solid fa-pen-to-square"></i><span>${escapeHtml(t('Fill', '填入'))}</span></button>` : ''}
      ${selected && !isDanbooru ? `<button type="button" class="is-danger" data-media-browser-action="delete-local"><i class="fa-solid fa-trash"></i><span>${escapeHtml(t('Delete file', '删除文件'))}</span></button>` : ''}
      ${data.has_more ? `<button type="button" data-media-browser-action="load-more" ${loadingMore ? 'disabled' : ''}><i class="fa-solid ${loadingMore ? 'fa-spinner fa-spin' : 'fa-angles-down'}"></i><span>${escapeHtml(loadingMore ? t('Loading...', '正在加载...') : t('Load more', '加载更多'))}</span></button>` : ''}
      <button type="button" data-media-browser-action="${isDanbooru ? 'reconnect' : 'refresh'}"><i class="fa-solid fa-rotate"></i><span>${escapeHtml(isDanbooru ? t('Retry', '重试') : t('Refresh', '刷新'))}</span></button>
      <button type="button" data-media-browser-action="import" ${selected ? '' : 'disabled'}><i class="fa-solid fa-plus"></i><span>${escapeHtml(t('Add', '添加'))}</span></button>
    </div>
  </div>
</div>`;
    }

    function renderOutputBrowserControls(state, data) {
        const folders = Array.isArray(data?.folders) ? data.folders : [];
        const options = [`<option value="">${escapeHtml(t('Recent folders', '最近目录'))}</option>`]
            .concat(folders.map(folder => `<option value="${escapeHtml(folder)}" ${folder === state.folder ? 'selected' : ''}>${escapeHtml(folder)}</option>`))
            .join('');
        return `
<div class="sai-media-browser-controls sai-media-browser-output-controls">
  <div class="sai-media-browser-segment">
    <button type="button" data-media-browser-type="image" class="${state.mediaType === 'image' ? 'is-active' : ''}"><i class="fa-solid fa-image"></i><span>${escapeHtml(t('Images', '图片'))}</span></button>
    <button type="button" data-media-browser-type="video" class="${state.mediaType === 'video' ? 'is-active' : ''}"><i class="fa-solid fa-film"></i><span>${escapeHtml(t('Videos', '视频'))}</span></button>
  </div>
  <select data-media-browser-field="folder">${options}</select>
  <input type="search" data-media-browser-search="outputs" value="${escapeHtml(state.query || '')}" placeholder="${escapeHtml(t('Search filename', '搜索文件名'))}">
  <button type="button" data-media-browser-action="search" title="${escapeHtml(t('Search', '搜索'))}"><i class="fa-solid fa-magnifying-glass"></i></button>
</div>`;
    }

    function renderDanbooruBrowserControls(state) {
        const ratings = [
            ['all', t('All ratings', '全部分级')],
            ['general', 'General'],
            ['sensitive', 'Sensitive'],
            ['questionable', 'Questionable'],
            ['explicit', 'Explicit']
        ];
        return `
<div class="sai-media-browser-controls">
  <input type="search" data-media-browser-search="danbooru" value="${escapeHtml(state.danbooruQuery || '')}" placeholder="${escapeHtml(t('Danbooru tags, e.g. raiden_shogun', 'Danbooru 标签，例如 raiden_shogun'))}">
  <select data-media-browser-field="rating">${ratings.map(([value, label]) => `<option value="${escapeHtml(value)}" ${state.rating === value ? 'selected' : ''}>${escapeHtml(label)}</option>`).join('')}</select>
  <button type="button" data-media-browser-action="search" title="${escapeHtml(t('Search', '搜索'))}"><i class="fa-solid fa-magnifying-glass"></i></button>
  <button type="button" data-media-browser-action="reconnect" title="${escapeHtml(t('Reconnect / refresh Danbooru', '重连 / 刷新 Danbooru'))}"><i class="fa-solid fa-rotate"></i></button>
  <button type="button" data-media-browser-action="page-prev" ${Number(state.page || 1) <= 1 ? 'disabled' : ''}><i class="fa-solid fa-chevron-left"></i></button>
  <span class="sai-media-browser-page">${escapeHtml(t('Page', '页'))} ${Number(state.page || 1)}</span>
  <button type="button" data-media-browser-action="page-next"><i class="fa-solid fa-chevron-right"></i></button>
</div>`;
    }

    function renderMediaBrowserLoadingCards() {
        return Array.from({ length: 12 }).map(() => '<div class="sai-media-browser-card is-loading"></div>').join('');
    }

    function renderMediaBrowserItems(items, selectedId, isDanbooru, data) {
        if (data?.ok === false) {
            const message = data.load_more_error || data.error || t('Load failed.', '加载失败。');
            return `<div class="sai-media-browser-empty sai-media-browser-error">
  <b>${escapeHtml(isDanbooru ? t('Danbooru connection failed.', 'Danbooru 连接失败。') : t('Media load failed.', '媒体加载失败。'))}</b>
  <small>${escapeHtml(message)}</small>
  <button type="button" data-media-browser-action="${isDanbooru ? 'reconnect' : 'refresh'}"><i class="fa-solid fa-rotate"></i><span>${escapeHtml(isDanbooru ? t('Reconnect', '重连') : t('Refresh', '刷新'))}</span></button>
</div>`;
        }
        if (!items.length) {
            return `<div class="sai-media-browser-empty">${escapeHtml(t('No media found.', '没有找到媒体。'))}</div>`;
        }
        return items.map((item, index) => {
            const id = String(item.id || '');
            const selected = id === String(selectedId || '');
            const mediaType = item.media_type || (isDanbooru ? danbooruPostMediaType(item.raw || item) : 'image');
            const preview = item.preview_url || item.thumb || '';
            const title = item.name || item.title || id;
            const meta = mediaBrowserItemMeta(item);
            const imageLoading = index < 36 ? 'eager' : 'lazy';
            const imagePriority = index < 12 ? 'high' : 'auto';
            const body = mediaType === 'video'
                ? (preview ? `<video src="${escapeHtml(preview)}" muted preload="metadata"></video>` : '<i class="fa-solid fa-film"></i>')
                : (preview ? `<img src="${escapeHtml(preview)}" alt="" loading="${imageLoading}" decoding="async" fetchpriority="${imagePriority}" draggable="false">` : '<i class="fa-solid fa-image"></i>');
            return `<button type="button" class="sai-media-browser-card ${selected ? 'is-selected' : ''}" data-media-browser-item="${escapeHtml(id)}" draggable="true" title="${escapeHtml(t('Drag to canvas', '拖拽到画布'))}">
  <span class="sai-media-browser-thumb">${body}</span>
  <b title="${escapeHtml(title)}">${escapeHtml(title)}</b>
  <small>${escapeHtml(meta)}</small>
</button>`;
        }).join('');
    }

    function mediaBrowserItemMetadata(item) {
        const meta = item?.generation_metadata || item?.metadata || null;
        return meta && typeof meta === 'object' ? meta : {};
    }

    function mediaBrowserItemPrompt(item) {
        const metadata = mediaBrowserItemMetadata(item);
        return String(item?.prompt || metadata.prompt || '').trim();
    }

    function mediaBrowserItemNegativePrompt(item) {
        const metadata = mediaBrowserItemMetadata(item);
        return String(metadata.negative_prompt || metadata.negative || '').trim();
    }

    function nodeGenerationMetadata(node) {
        if (!node) return {};
        const asset = node.type === 'result' ? getSelectedResultAsset(node) : node.asset;
        const candidates = [
            asset?.generation_metadata,
            node.asset?.generation_metadata,
            node.source?.generation_metadata,
            asset?.metadata,
            node.metadata
        ];
        return candidates.find(item => item && typeof item === 'object') || {};
    }

    function generationMetadataPrompt(metadata) {
        if (!metadata || typeof metadata !== 'object') return '';
        return String(metadata.prompt || metadata.positive_prompt || metadata.positive || '').trim();
    }

    function generationMetadataNegativePrompt(metadata) {
        if (!metadata || typeof metadata !== 'object') return '';
        return String(metadata.negative_prompt || metadata.negative || '').trim();
    }

    function generationMetadataParameters(metadata) {
        const params = metadata?.parameters;
        return params && typeof params === 'object' ? params : {};
    }

    function generationMetadataParam(metadata, keys) {
        const params = generationMetadataParameters(metadata);
        const lowerMap = {};
        Object.keys(params).forEach(key => { lowerMap[String(key).toLowerCase()] = key; });
        for (const key of keys || []) {
            if (Object.prototype.hasOwnProperty.call(params, key) && params[key] !== '') return params[key];
            const realKey = lowerMap[String(key).toLowerCase()];
            if (realKey && params[realKey] !== '') return params[realKey];
        }
        return undefined;
    }

    function generationMetadataSeed(metadata) {
        const raw = generationMetadataParam(metadata, ['seed', 'Seed', 'image_seed']);
        const seed = Number.parseInt(String(raw ?? '').trim(), 10);
        return Number.isFinite(seed) && seed >= 0 ? seed : null;
    }

    function isGenerationPromptTargetNode(node) {
        return !!node && (node.type === 'preset' || node.type === 'classic');
    }

    function generationPromptTargetLabel(node) {
        if (!node) return '';
        return node.title || node.preset?.display_name || node.preset?.name || node.id || '';
    }

    function nodeDistanceScore(node, world) {
        const x = Number(node?.x || 0);
        const y = Number(node?.y || 0);
        const wx = Number(world?.x || 0);
        const wy = Number(world?.y || 0);
        return Math.hypot(x - wx, y - wy);
    }

    function resolveGenerationPromptTarget(sourceNode, world) {
        const addUnique = (list, node) => {
            if (isGenerationPromptTargetNode(node) && node.id !== sourceNode?.id && !list.some(item => item.id === node.id)) list.push(node);
        };
        const candidates = [];
        getSelectedNodeIdList().forEach(id => addUnique(candidates, getNode(id)));
        if (selectedNodeId) addUnique(candidates, getNode(selectedNodeId));
        if (sourceNode?.producer?.preset_node_id) addUnique(candidates, getNode(sourceNode.producer.preset_node_id));
        if (sourceNode?.id) {
            project.edges
                .filter(edge => edge.from === sourceNode.id && ['upload', 'media', 'text'].includes(edge.type))
                .forEach(edge => addUnique(candidates, getNode(edge.to)));
        }
        const origin = world || (sourceNode ? { x: sourceNode.x || 0, y: sourceNode.y || 0 } : viewportCenterWorld());
        project.nodes
            .filter(isGenerationPromptTargetNode)
            .sort((a, b) => nodeDistanceScore(a, origin) - nodeDistanceScore(b, origin))
            .slice(0, 6)
            .forEach(node => addUnique(candidates, node));
        return candidates[0] || null;
    }

    function applyMetadataParamIfVisible(target, metadata, sourceKeys, targetKeys) {
        if (!target || !metadata) return false;
        const raw = generationMetadataParam(metadata, sourceKeys);
        if (raw === undefined || raw === null || raw === '') return false;
        const visibleKeys = new Set([
            ...Object.keys(target.params || {}),
            ...getVisiblePresetParams(target).map(param => param.key)
        ]);
        const targetKey = (targetKeys || []).find(key => visibleKeys.has(key));
        if (!targetKey) return false;
        const numeric = Number(raw);
        target.params[targetKey] = Number.isFinite(numeric) && String(raw).trim() !== '' ? numeric : String(raw);
        return true;
    }

    function applyGenerationMetadataToPromptTarget(target, metadata, options) {
        if (!isGenerationPromptTargetNode(target)) return false;
        if (isNodeLocked(target)) {
            showToast(t('Locked generator node cannot be changed.', '锁定的生成节点不能修改。'));
            return false;
        }
        const prompt = generationMetadataPrompt(metadata);
        const negativePrompt = generationMetadataNegativePrompt(metadata);
        if (!prompt && !negativePrompt) {
            showToast(t('No prompt metadata to apply.', '没有可回填的提示词元数据。'));
            return false;
        }
        const promptSource = getPromptTextSourceNode(target, 'prompt');
        const negativeSource = getPromptTextSourceNode(target, 'negative_prompt');
        if (prompt && promptSource) {
            showToast(t('Generator prompt is connected from another text node.', '生成节点的 Prompt 已由文本节点连接。'));
            return false;
        }
        pushHistory('Apply generation metadata prompt');
        target.params = Object.assign({}, target.params || {});
        let changed = false;
        if (prompt) {
            target.params.prompt = prompt;
            changed = true;
        }
        if (negativePrompt && !negativeSource) {
            target.params.negative_prompt = negativePrompt;
            changed = true;
        }
        const seed = generationMetadataSeed(metadata);
        if (seed !== null) {
            target.params.seed_random = false;
            target.params.image_seed = seed;
            changed = true;
        }
        changed = applyMetadataParamIfVisible(target, metadata, ['steps', 'Steps'], ['steps', 'sample_steps']) || changed;
        changed = applyMetadataParamIfVisible(target, metadata, ['guidance_scale', 'cfg_scale', 'CFG scale'], ['guidance_scale', 'cfg_scale']) || changed;
        changed = applyMetadataParamIfVisible(target, metadata, ['sampler', 'Sampler'], ['sampler']) || changed;
        changed = applyMetadataParamIfVisible(target, metadata, ['scheduler', 'Scheduler'], ['scheduler']) || changed;
        if (!changed) {
            showToast(t('No compatible metadata fields were applied.', '没有可兼容回填的元数据字段。'));
            return false;
        }
        target.metadata_prompt_source = {
            source: metadata.source || '',
            scheme: metadata.scheme || '',
            label: options?.sourceLabel || '',
            applied_at: nowIso()
        };
        selectedNodeId = target.id;
        selectedNodeIds = new Set([target.id]);
        selectedEdgeId = null;
        selectedGroupId = null;
        mutate({ inspector: true });
        showToast(t('Metadata prompt filled into {target}.', '元数据提示词已填入 {target}。').replace('{target}', generationPromptTargetLabel(target)));
        return true;
    }

    function renderMediaBrowserDetail(item, isDanbooru) {
        if (!item) {
            return `<div class="sai-media-browser-detail-empty">${escapeHtml(t('Select an item to preview details.', '选择一项查看详情。'))}</div>`;
        }
        const preview = item.preview_url || item.thumb || '';
        const mediaType = item.media_type || (isDanbooru ? danbooruPostMediaType(item.raw || item) : 'image');
        const title = item.name || item.title || item.id || '';
        const metadata = mediaBrowserItemMetadata(item);
        const prompt = mediaBrowserItemPrompt(item);
        const negativePrompt = mediaBrowserItemNegativePrompt(item);
        const source = isDanbooru ? (item.post_url || '') : (item.relative_path || item.path || '');
        const metadataSource = metadata.source || metadata.scheme || '';
        const metadataParams = metadata.parameters && typeof metadata.parameters === 'object'
            ? Object.entries(metadata.parameters).slice(0, 8).map(([key, value]) => {
                const text = value && typeof value === 'object' ? JSON.stringify(value) : String(value ?? '');
                return `${key}: ${text}`;
            }).join('\n')
            : '';
        const width = Math.max(1, Number(item.width || item.image_width || 0) || 0);
        const height = Math.max(1, Number(item.height || item.image_height || 0) || 0);
        const aspectStyle = width && height ? ` style="--sai-media-aspect: ${width} / ${height};"` : '';
        return `
<div class="sai-media-browser-detail-preview"${aspectStyle}>
  ${mediaType === 'video'
            ? (preview ? `<video src="${escapeHtml(preview)}" controls muted preload="metadata"></video>` : '<i class="fa-solid fa-film"></i>')
            : (preview ? `<img src="${escapeHtml(preview)}" alt="">` : '<i class="fa-solid fa-image"></i>')}
</div>
<h4>${escapeHtml(title)}</h4>
<p>${escapeHtml(mediaBrowserItemMeta(item))}</p>
${source ? `<code>${escapeHtml(source)}</code>` : ''}
${metadataSource ? `<p>${escapeHtml(metadataSource)}</p>` : ''}
${prompt ? `<textarea readonly>${escapeHtml(prompt)}</textarea>` : ''}
${negativePrompt ? `<textarea readonly>${escapeHtml(negativePrompt)}</textarea>` : ''}
${metadataParams ? `<code>${escapeHtml(metadataParams)}</code>` : ''}`;
    }

    function selectedMediaBrowserItem(modal) {
        return selectedMediaBrowserItemFrom(modal.__mediaBrowserState || {}, modal.__mediaBrowserData || {});
    }

    function mediaBrowserItemMeta(item) {
        const bits = [];
        if (item.width && item.height) bits.push(`${item.width} x ${item.height}`);
        if (item.rating) bits.push(String(item.rating).toUpperCase());
        if (item.size) bits.push(formatBytes(item.size));
        if (item.updated_at_iso) bits.push(String(item.updated_at_iso).replace('T', ' '));
        return bits.filter(Boolean).join(' · ');
    }

    function addOutputGalleryMediaNode(item, world) {
        if (!item) return null;
        const mediaType = item.media_type === 'video' ? 'video' : 'image';
        const size = mediaType === 'video' ? defaultNodeSize('video') : { w: 264, h: 300 };
        const generationMetadata = mediaBrowserItemMetadata(item);
        pushHistory(mediaType === 'video' ? 'Add gallery video node' : 'Add gallery image node');
        const node = {
            id: uid(mediaType === 'video' ? 'vid' : 'img'),
            type: mediaType,
            x: Math.round(world?.x || 0),
            y: Math.round(world?.y || 0),
            w: size.w,
            h: size.h,
            title: item.name || (mediaType === 'video' ? 'gallery video' : 'gallery image'),
            asset: {
                kind: 'output_gallery',
                asset_id: `output:${item.relative_path || item.path || uid('asset')}`,
                mime: item.mime || (mediaType === 'video' ? 'video/mp4' : 'image/png'),
                size: item.size || 0,
                width: item.width || null,
                height: item.height || null,
                path: item.path || '',
                output_path: item.path || '',
                original_output_path: item.path || '',
                preview_url: item.preview_url || '',
                thumb: mediaType === 'image' ? (item.preview_url || '') : '',
                generation_metadata: generationMetadata,
                edit: mediaType === 'video' ? { trim_start: 0, trim_end: item.duration || 0, enabled: false } : null
            },
            source: {
                kind: 'output_gallery',
                folder: item.folder || '',
                relative_path: item.relative_path || '',
                generation_metadata: generationMetadata,
                imported_at: nowIso()
            }
        };
        placeNodeAvoidingOverlap(node, world || viewportCenterWorld());
        project.nodes.push(node);
        selectedNodeId = node.id;
        selectedNodeIds = new Set([node.id]);
        selectedEdgeId = null;
        selectedGroupId = null;
        mutate();
        return node;
    }

    async function importSelectedMediaBrowserItem(modal) {
        const item = selectedMediaBrowserItem(modal);
        if (!item) return;
        const state = modal.__mediaBrowserState || mediaBrowserInitialState(viewportCenterWorld());
        const world = state.world || viewportCenterWorld();
        try {
            if (state.tab === 'danbooru') {
                await importDanbooruGalleryPost(item, world);
            } else {
                addOutputGalleryMediaNode(item, world);
                showToast(t('Gallery media added to canvas.', '画廊媒体已加入画布。'));
            }
        } catch (err) {
            console.warn('[CanvasWorkbench] media browser import failed', err);
            showToast(t('Media import failed.', '媒体导入失败。'));
        }
    }

    async function addMediaBrowserItemToCanvas(item, state, world) {
        if (!item) return null;
        try {
            if (state?.tab === 'danbooru') {
                return await importDanbooruGalleryPost(item, world || viewportCenterWorld());
            }
            const node = addOutputGalleryMediaNode(item, world || viewportCenterWorld());
            showToast(t('Gallery media added to canvas.', 'Gallery media added to canvas.'));
            return node;
        } catch (err) {
            console.warn('[CanvasWorkbench] media browser import failed', err);
            showToast(t('Media import failed.', 'Media import failed.'));
        }
        return null;
    }

    function mediaBrowserPayloadFromDataTransfer(dataTransfer) {
        if (!dataTransfer) return null;
        const types = dataTransfer.types ? Array.from(dataTransfer.types) : [];
        if (types.includes(MEDIA_BROWSER_DRAG_MIME)) {
            try {
                const payload = JSON.parse(dataTransfer.getData(MEDIA_BROWSER_DRAG_MIME) || '{}');
                if (payload?.item) return payload;
            } catch (err) {
                console.warn('[SimpAI Canvas] media browser drag payload parse failed', err);
            }
        }
        return mediaBrowserDragPayload?.item ? mediaBrowserDragPayload : null;
    }

    async function addMediaBrowserPayloadToCanvas(payload, world) {
        if (!payload?.item) return null;
        const state = normalizeMediaBrowserState(payload.state || {}, world || viewportCenterWorld());
        state.tab = payload.tab === 'danbooru' || state.tab === 'danbooru' ? 'danbooru' : 'outputs';
        state.mediaType = payload.media_type === 'video' || state.mediaType === 'video' ? 'video' : 'image';
        state.selectedId = String(payload.item.id || state.selectedId || '');
        return addMediaBrowserItemToCanvas(payload.item, state, world || viewportCenterWorld());
    }

    function mediaBrowserNodeDragPayload(node, itemId) {
        if (!node || node.type !== 'media_browser') return null;
        const state = mediaBrowserNodeState(node);
        const data = mediaBrowserRuntimeFor(node.id).data || {};
        const items = Array.isArray(data.items) ? data.items : [];
        const item = items.find(entry => String(entry?.id || '') === String(itemId || ''));
        if (!item) return null;
        return {
            source: 'media_browser_node',
            node_id: node.id,
            tab: state.tab,
            media_type: state.mediaType,
            item,
            state: serializableMediaBrowserState(Object.assign({}, state, { selectedId: item.id || '' }))
        };
    }

    function bindMediaBrowserNodeDragEvents(nodeEl, node) {
        if (!nodeEl || !node || node.type !== 'media_browser') return;
        nodeEl.addEventListener('dragstart', (evt) => {
            const itemButton = evt.target?.closest?.('[data-media-browser-item]');
            if (!itemButton || !nodeEl.contains(itemButton)) return;
            const payload = mediaBrowserNodeDragPayload(node, itemButton.getAttribute('data-media-browser-item') || '');
            if (!payload) return;
            mediaBrowserDragPayload = payload;
            try {
                evt.dataTransfer.effectAllowed = 'copy';
                evt.dataTransfer.setData(MEDIA_BROWSER_DRAG_MIME, JSON.stringify(payload));
                evt.dataTransfer.setData('text/plain', payload.item.name || payload.item.title || payload.item.id || 'media browser item');
                const thumb = itemButton.querySelector('.sai-media-browser-thumb');
                if (thumb) evt.dataTransfer.setDragImage(thumb, Math.min(48, thumb.clientWidth / 2), Math.min(48, thumb.clientHeight / 2));
            } catch (err) {
                console.warn('[SimpAI Canvas] media browser drag setup failed', err);
            }
            itemButton.classList.add('is-dragging');
            nodeEl.classList.add('is-media-browser-dragging');
            evt.stopPropagation();
        }, true);
        nodeEl.addEventListener('dragend', () => {
            mediaBrowserDragPayload = null;
            nodeEl.classList.remove('is-media-browser-dragging');
            nodeEl.querySelectorAll('.sai-media-browser-card.is-dragging').forEach(el => el.classList.remove('is-dragging'));
            if (viewport) viewport.classList.remove('is-drop-target');
        }, true);
    }

    async function copyMediaBrowserItemPrompt(item) {
        const prompt = mediaBrowserItemPrompt(item);
        if (!prompt) return false;
        try {
            await navigator.clipboard.writeText(prompt);
            showToast(t('Prompt copied.', 'Prompt copied.'));
            return true;
        } catch (err) {
            showToast(t('Copy failed.', 'Copy failed.'));
            return false;
        }
    }

    function applyMediaBrowserItemPromptToTarget(item, state) {
        const metadata = mediaBrowserItemMetadata(item);
        const prompt = mediaBrowserItemPrompt(item);
        if (!prompt) {
            showToast(t('Selected media has no prompt metadata.', 'Selected media has no prompt metadata.'));
            return false;
        }
        const target = resolveGenerationPromptTarget(null, state?.world || viewportCenterWorld());
        if (!target) {
            showToast(t('Select a Preset/Classic generator node first.', 'Select a Preset/Classic generator node first.'));
            return false;
        }
        return applyGenerationMetadataToPromptTarget(target, Object.assign({}, metadata, {
            prompt,
            negative_prompt: mediaBrowserItemNegativePrompt(item) || metadata.negative_prompt || ''
        }), { sourceLabel: item?.name || item?.title || 'media browser' });
    }

    async function deleteLocalMediaBrowserItem(item, state) {
        if (!item || state?.tab === 'danbooru') return false;
        if (typeof WORKBENCH_API.mediaGalleryDelete !== 'function') {
            showToast('Media delete API is not loaded.');
            return false;
        }
        const rel = String(item.relative_path || item.id || '').trim();
        if (!rel) {
            showToast('Selected media has no local relative path.');
            return false;
        }
        const ok = window.confirm(`Delete this local file from disk?\n\n${item.name || rel}`);
        if (!ok) return false;
        const response = await WORKBENCH_API.mediaGalleryDelete({
            ids: [rel],
            media_type: state.mediaType || item.media_type || 'image'
        });
        if (!response?.ok) {
            const detail = response?.errors?.[0]?.error || response?.details || response?.error || 'unknown error';
            showToast(`Delete failed: ${detail}`);
            return false;
        }
        showToast('Local media file deleted.');
        return true;
    }

    async function deleteSelectedMediaBrowserPanelItem(modal) {
        const item = selectedMediaBrowserItem(modal);
        const state = modal.__mediaBrowserState || mediaBrowserInitialState(viewportCenterWorld());
        if (!await deleteLocalMediaBrowserItem(item, state)) return false;
        state.selectedId = '';
        modal.__mediaBrowserState = state;
        await refreshMediaBrowserPanel(modal);
        return true;
    }

    function readMediaBrowserNodeFields(node, nodeEl) {
        const state = mediaBrowserNodeState(node);
        const localQuery = nodeEl?.querySelector?.('[data-media-browser-search="outputs"]');
        const danbooruQuery = nodeEl?.querySelector?.('[data-media-browser-search="danbooru"]');
        const folder = nodeEl?.querySelector?.('[data-media-browser-field="folder"]');
        const rating = nodeEl?.querySelector?.('[data-media-browser-field="rating"]');
        if (localQuery) state.query = localQuery.value || '';
        if (danbooruQuery) state.danbooruQuery = danbooruQuery.value || '';
        if (folder) state.folder = folder.value || '';
        if (rating) state.rating = rating.value || 'all';
        state.world = {
            x: Math.round(Number(node?.x || 0) + Number(node?.w || defaultNodeSize('media_browser').w || 0) + 48),
            y: Math.round(Number(node?.y || 0))
        };
        return state;
    }

    function scheduleMediaBrowserNodePaintRefresh(nodeId) {
        if (!nodeId || !nodesLayer) return;
        window.requestAnimationFrame(() => {
            const nodeEl = nodesLayer?.querySelector?.(`[data-node-id="${CSS.escape(nodeId)}"]`);
            if (!nodeEl) return;
            primeMediaBrowserThumbImages(nodeEl);
            nudgeMediaBrowserPaint(nodeEl);
        });
    }

    async function refreshMediaBrowserNode(node, options) {
        if (!node || node.type !== 'media_browser') return null;
        const runtime = mediaBrowserRuntimeFor(node.id);
        const requestId = Number(runtime.requestId || 0) + 1;
        runtime.requestId = requestId;
        runtime.loading = true;
        runtime.loadingMore = false;
        runtime.error = '';
        runtime.version = Number(runtime.version || 0) + 1;
        if (options?.render !== false) renderNodes();
        const state = mediaBrowserNodeState(node);
        let data;
        try {
            data = await fetchMediaBrowserData(state, { limit: MEDIA_BROWSER_PAGE_SIZE, offset: 0 });
        } catch (err) {
            data = { ok: false, error: err?.message || String(err || 'media browser failed'), items: [] };
        }
        const latest = getNode(node.id);
        if (!latest || latest.type !== 'media_browser' || runtime.requestId !== requestId) return data;
        runtime.data = mergeMediaBrowserPage(null, data, false);
        runtime.loading = false;
        runtime.error = runtime.data.error || '';
        runtime.version = Number(runtime.version || 0) + 1;
        const items = Array.isArray(runtime.data.items) ? runtime.data.items : [];
        const nextState = mediaBrowserNodeState(latest);
        if (!items.some(item => String(item.id || '') === String(nextState.selectedId || ''))) {
            nextState.selectedId = items[0]?.id || '';
            saveMediaBrowserNodeState(latest, nextState);
        }
        renderNodes();
        scheduleMediaBrowserNodePaintRefresh(latest.id);
        return runtime.data;
    }

    function selectedMediaBrowserNodeItem(node) {
        const state = mediaBrowserNodeState(node);
        return selectedMediaBrowserItemFrom(state, mediaBrowserRuntimeFor(node.id).data || {});
    }

    function handleMediaBrowserNodeClick(node, evt, nodeEl) {
        if (!node || node.type !== 'media_browser') return false;
        const frostArea = evt.target.closest('.sai-media-browser-main');
        if (frostArea && revealGalleryFrostArea(frostArea)) {
            mediaBrowserRuntimeFor(node.id).frostRevealed = true;
            evt.preventDefault();
            evt.stopPropagation();
            return true;
        }
        const tabButton = evt.target.closest('[data-media-browser-tab]');
        if (tabButton) {
            evt.preventDefault();
            evt.stopPropagation();
            const state = readMediaBrowserNodeFields(node, nodeEl);
            state.tab = tabButton.getAttribute('data-media-browser-tab') === 'danbooru' ? 'danbooru' : 'outputs';
            state.selectedId = '';
            state.page = 1;
            saveMediaBrowserNodeState(node, state, { history: 'tab' });
            refreshMediaBrowserNode(node).catch((err) => console.warn('[SimpAI Canvas] media browser tab refresh failed', err));
            return true;
        }
        const typeButton = evt.target.closest('[data-media-browser-type]');
        if (typeButton) {
            evt.preventDefault();
            evt.stopPropagation();
            const state = readMediaBrowserNodeFields(node, nodeEl);
            state.mediaType = typeButton.getAttribute('data-media-browser-type') === 'video' ? 'video' : 'image';
            state.selectedId = '';
            saveMediaBrowserNodeState(node, state, { history: 'type' });
            refreshMediaBrowserNode(node).catch((err) => console.warn('[SimpAI Canvas] media browser type refresh failed', err));
            return true;
        }
        const itemButton = evt.target.closest('[data-media-browser-item]');
        if (itemButton) {
            evt.preventDefault();
            evt.stopPropagation();
            const state = mediaBrowserNodeState(node);
            state.selectedId = itemButton.getAttribute('data-media-browser-item') || '';
            saveMediaBrowserNodeState(node, state);
            renderNodes();
            if (evt.detail >= 2) {
                const item = selectedMediaBrowserNodeItem(node);
                addMediaBrowserItemToCanvas(item, state, state.world).catch((err) => console.warn('[SimpAI Canvas] media browser item add failed', err));
            }
            return true;
        }
        const actionButton = evt.target.closest('[data-media-browser-action]');
        if (!actionButton) return false;
        evt.preventDefault();
        evt.stopPropagation();
        const action = actionButton.getAttribute('data-media-browser-action') || '';
        handleMediaBrowserNodeAction(node, action, nodeEl).catch((err) => {
            console.warn('[SimpAI Canvas] media browser node action failed', err);
            showToast(`${t('Media Browser action failed', '媒体浏览器操作失败')}：${err?.message || err || t('unknown error', '未知错误')}`);
        });
        return true;
    }

    async function loadMoreMediaBrowserNode(node, nodeEl) {
        if (!node || node.type !== 'media_browser') return;
        const runtime = mediaBrowserRuntimeFor(node.id);
        const current = runtime.data || {};
        if (runtime.loadingMore || (!current.has_more && !current.truncated)) return;
        const state = readMediaBrowserNodeFields(node, nodeEl);
        runtime.loadingMore = true;
        runtime.version = Number(runtime.version || 0) + 1;
        renderNodes();
        try {
            let page;
            if (state.tab === 'danbooru') {
                const nextPage = Math.max(1, Number(current.next_page || (Number(current.page || state.page || 1) + 1)) || 1);
                page = await fetchMediaBrowserData(state, { limit: MEDIA_BROWSER_PAGE_SIZE, page: nextPage });
                state.page = nextPage;
                saveMediaBrowserNodeState(node, state);
            } else {
                page = await fetchMediaBrowserData(state, {
                    limit: MEDIA_BROWSER_PAGE_SIZE,
                    offset: Number(current.next_offset ?? current.items?.length ?? 0) || 0
                });
            }
            runtime.data = mergeMediaBrowserPage(current, page, true);
        } finally {
            runtime.loadingMore = false;
            runtime.version = Number(runtime.version || 0) + 1;
            renderNodes();
            scheduleMediaBrowserNodePaintRefresh(node.id);
        }
    }

    async function handleMediaBrowserNodeAction(node, action, nodeEl) {
        const state = readMediaBrowserNodeFields(node, nodeEl);
        if (action === 'refresh' || action === 'search' || action === 'reconnect') {
            state.page = action === 'search' ? 1 : state.page;
            saveMediaBrowserNodeState(node, state, { history: action });
            await refreshMediaBrowserNode(node);
            return;
        }
        if (action === 'load-more') {
            await loadMoreMediaBrowserNode(node, nodeEl);
            return;
        }
        if (action === 'open-modal') {
            openMediaBrowserPanel(state.world || viewportCenterWorld(), state);
            return;
        }
        if (action === 'page-prev' || action === 'page-next') {
            state.page = Math.max(1, Number(state.page || 1) + (action === 'page-next' ? 1 : -1));
            saveMediaBrowserNodeState(node, state, { history: 'page' });
            await refreshMediaBrowserNode(node);
            return;
        }
        const item = selectedMediaBrowserNodeItem(node);
        if (action === 'import') {
            await addMediaBrowserItemToCanvas(item, state, state.world || viewportCenterWorld());
        } else if (action === 'copy-prompt') {
            await copyMediaBrowserItemPrompt(item);
        } else if (action === 'apply-prompt') {
            applyMediaBrowserItemPromptToTarget(item, state);
        } else if (action === 'delete-local') {
            if (!await deleteLocalMediaBrowserItem(item, state)) return;
            state.selectedId = '';
            saveMediaBrowserNodeState(node, state, { history: 'delete-local' });
            await refreshMediaBrowserNode(node);
        }
    }

    function handleMediaBrowserNodeChange(node, evt, nodeEl) {
        if (!node || node.type !== 'media_browser') return false;
        const frostToggle = evt.target.closest('[data-media-browser-frost]');
        if (frostToggle) {
            setGalleryFrostEnabled(!!frostToggle.checked);
            renderNodes();
            return true;
        }
        const field = evt.target.closest('[data-media-browser-field]');
        if (!field) return false;
        const state = readMediaBrowserNodeFields(node, nodeEl);
        state.selectedId = '';
        if (field.getAttribute('data-media-browser-field') === 'rating') state.page = 1;
        saveMediaBrowserNodeState(node, state, { history: field.getAttribute('data-media-browser-field') || 'field' });
        refreshMediaBrowserNode(node).catch((err) => console.warn('[SimpAI Canvas] media browser field refresh failed', err));
        return true;
    }

    function handleMediaBrowserNodeKeydown(node, evt, nodeEl) {
        if (!node || node.type !== 'media_browser' || evt.key !== 'Enter') return false;
        const field = evt.target.closest('[data-media-browser-search]');
        if (!field) return false;
        evt.preventDefault();
        evt.stopPropagation();
        const state = readMediaBrowserNodeFields(node, nodeEl);
        state.page = 1;
        saveMediaBrowserNodeState(node, state, { history: 'search-enter' });
        refreshMediaBrowserNode(node).catch((err) => console.warn('[SimpAI Canvas] media browser enter refresh failed', err));
        return true;
    }

    async function fetchDanbooruGalleryPosts(state) {
        const params = new URLSearchParams();
        params.set('search[tags]', state.danbooruQuery || '');
        params.set('limit', '40');
        params.set('page', String(Math.max(1, Number(state.page || 1))));
        if (state.rating && state.rating !== 'all') params.set('search[rating]', state.rating);
        const response = await fetch(`${DANBOORU_GALLERY_ENDPOINT}/posts?${params.toString()}`);
        let payload = null;
        try {
            payload = await response.json();
        } catch (err) {
            payload = null;
        }
        if (!response.ok || payload?.ok === false) {
            const detail = String(payload?.details || '').replace(/\s+/g, ' ').slice(0, 240);
            const message = payload?.error
                ? (detail ? `${payload.error}: ${detail}` : payload.error)
                : (detail || `Danbooru Gallery HTTP ${response.status}`);
            throw new Error(message);
        }
        const posts = Array.isArray(payload) ? payload : (Array.isArray(payload?.posts) ? payload.posts : (Array.isArray(payload?.items) ? payload.items : []));
        const items = (Array.isArray(posts) ? posts : []).map(normalizeDanbooruBrowserPost).filter(Boolean);
        const page = Math.max(1, Number(state.page || 1) || 1);
        const hasMore = payload && typeof payload.has_more === 'boolean' ? payload.has_more : items.length >= 40;
        const nextPage = payload?.next_page || (hasMore ? page + 1 : null);
        return { ok: true, items, page, has_more: hasMore, next_page: nextPage };
    }

    function danbooruGalleryImageProxyUrl(url) {
        return `${DANBOORU_GALLERY_ENDPOINT}/image-proxy?url=${encodeURIComponent(url || '')}`;
    }

    function normalizeDanbooruBrowserPost(post) {
        if (!post || !post.id) return null;
        const previewUrl = post.preview_file_url
            ? danbooruGalleryImageProxyUrl(post.preview_file_url + (post.md5 ? `?v=${post.md5}` : ''))
            : '';
        const fullUrl = post.file_url || post.large_file_url || post.preview_file_url || '';
        const title = `danbooru_${post.id}.${post.file_ext || danbooruPostExtension(post)}`;
        const prompt = danbooruPostPrompt(post);
        return {
            id: `danbooru:${post.id}`,
            name: title,
            title,
            media_type: danbooruPostMediaType(post),
            preview_url: previewUrl,
            file_url: fullUrl,
            post_url: `https://danbooru.donmai.us/posts/${post.id}`,
            rating: post.rating || '',
            width: post.image_width || null,
            height: post.image_height || null,
            size: post.file_size || 0,
            prompt,
            generation_metadata: {
                ok: true,
                source: 'danbooru',
                prompt,
                parameters: {
                    post_id: post.id,
                    rating: post.rating || '',
                    score: post.score || '',
                    source: post.source || ''
                },
                raw_keys: ['tag_string_character', 'tag_string_copyright', 'tag_string_general', 'tag_string_meta']
            },
            raw: post
        };
    }

    function danbooruPostExtension(post) {
        const ext = String(post?.file_ext || '').trim().toLowerCase();
        if (ext) return ext;
        const url = String(post?.file_url || post?.large_file_url || post?.preview_file_url || '').split(/[?#]/, 1)[0];
        return (url.match(/\.([a-z0-9]+)$/i)?.[1] || 'jpg').toLowerCase();
    }

    function danbooruPostMediaType(post) {
        const ext = danbooruPostExtension(post);
        return ['webm', 'mp4', 'mov'].includes(ext) ? 'video' : 'image';
    }

    function danbooruPostPrompt(post) {
        if (!post) return '';
        const groups = [
            post.tag_string_character,
            post.tag_string_copyright,
            post.tag_string_general,
            post.tag_string_meta,
        ].filter(Boolean).join(' ');
        const source = groups || post.tag_string || '';
        return source.split(/\s+/).map(tag => tag.trim()).filter(Boolean).join(', ');
    }

    async function importDanbooruGalleryPost(item, world) {
        const url = item.file_url || item.preview_url || '';
        if (!url) {
            showToast(t('Danbooru post has no importable file URL.', '该 Danbooru 条目没有可导入文件地址。'));
            return null;
        }
        showToast(t('Importing Danbooru media...', '正在导入 Danbooru 媒体...'));
        const proxyUrl = danbooruGalleryImageProxyUrl(url);
        const response = await fetch(proxyUrl);
        if (!response.ok) throw new Error(`Danbooru media HTTP ${response.status}`);
        const blob = await response.blob();
        const ext = danbooruPostExtension(item.raw || item);
        const mime = blob.type || (item.media_type === 'video' ? 'video/mp4' : 'image/jpeg');
        const file = new File([blob], item.name || `danbooru_${Date.now()}.${ext}`, { type: mime });
        const node = await addMediaNodeFromFile(file, world || viewportCenterWorld());
        if (node) {
            const generationMetadata = mediaBrowserItemMetadata(item);
            node.title = item.name || node.title;
            node.source = Object.assign({}, node.source || {}, {
                kind: 'danbooru_gallery',
                post_id: String(item.raw?.id || '').trim(),
                post_url: item.post_url || '',
                original_url: url,
                prompt: item.prompt || '',
                generation_metadata: generationMetadata,
                imported_at: nowIso()
            });
            if (node.asset) {
                node.asset.original_url = url;
                node.asset.danbooru_post_id = item.raw?.id || '';
                node.asset.generation_metadata = generationMetadata;
            }
            mutate({ inspector: true });
        }
        showToast(t('Danbooru media added to canvas.', 'Danbooru 媒体已加入画布。'));
        return node;
    }

    async function copySelectedMediaBrowserPrompt(modal) {
        const item = selectedMediaBrowserItem(modal);
        const prompt = mediaBrowserItemPrompt(item);
        if (!prompt) return;
        try {
            await navigator.clipboard.writeText(prompt);
            showToast(t('Prompt copied.', '提示词已复制。'));
        } catch (err) {
            showToast(t('Copy failed.', '复制失败。'));
        }
    }

    function applySelectedMediaBrowserPromptToTarget(modal) {
        const item = selectedMediaBrowserItem(modal);
        const metadata = mediaBrowserItemMetadata(item);
        const prompt = mediaBrowserItemPrompt(item);
        if (!prompt) {
            showToast(t('Selected media has no prompt metadata.', '选中的媒体没有提示词元数据。'));
            return false;
        }
        const state = modal.__mediaBrowserState || mediaBrowserInitialState(viewportCenterWorld());
        const target = resolveGenerationPromptTarget(null, state.world || viewportCenterWorld());
        if (!target) {
            showToast(t('Select a Preset/Classic generator node first.', '请先选中一个 Preset/Classic 生成节点。'));
            return false;
        }
        return applyGenerationMetadataToPromptTarget(target, Object.assign({}, metadata, {
            prompt,
            negative_prompt: mediaBrowserItemNegativePrompt(item) || metadata.negative_prompt || ''
        }), { sourceLabel: item?.name || item?.title || 'media browser' });
    }

    function openProjectJsonPicker() {
        importProjectInput = importProjectInput || document.createElement('input');
        importProjectInput.type = 'file';
        importProjectInput.accept = '.json,.canvas.json,application/json';
        importProjectInput.multiple = false;
        importProjectInput.hidden = true;
        if (!importProjectInput.isConnected) document.body.appendChild(importProjectInput);
        importProjectInput.onchange = async () => {
            const file = importProjectInput.files && importProjectInput.files[0];
            importProjectInput.value = '';
            if (file) await importWorkbenchProjectFromFile(file, { persist: false });
        };
        importProjectInput.click();
    }

    function isImageFile(file) {
        return WORKBENCH_MEDIA_HELPERS.isImageFile(file);
    }

    function isVideoFile(file) {
        return WORKBENCH_MEDIA_HELPERS.isVideoFile(file);
    }

    function isAudioFile(file) {
        return WORKBENCH_MEDIA_HELPERS.isAudioFile(file);
    }

    function isMediaFile(file) {
        return WORKBENCH_MEDIA_HELPERS.isMediaFile(file);
    }

    function isBatchTextFile(file) {
        if (!file) return false;
        const name = String(file.name || '').toLowerCase();
        const type = String(file.type || '').toLowerCase();
        if (name.endsWith('.canvas.json') || name.endsWith('.workbench.json')) return false;
        return type.startsWith('text/') || name.endsWith('.txt') || name.endsWith('.md');
    }

    function isWorkbenchProjectFile(file) {
        if (!file) return false;
        const name = String(file.name || '').toLowerCase();
        return name.endsWith('.canvas.json') || name.endsWith('.workbench.json') || (name.endsWith('.json') && !file.type.startsWith('image/'));
    }

    async function addImageNodeFromTransferItem(item, world) {
        const dimensions = await getImageDimensions(item.dataUrl || item.previewUrl || '');
        const thumb = item.dataUrl ? await createThumbnailDataUrl(item.dataUrl, 1024) : (item.previewUrl || '');
        pushHistory('Add image node');
        const node = {
            id: uid('img'),
            type: 'image',
            x: world.x,
            y: world.y,
            w: 264,
            h: 300,
            title: item.name || 'transfer image',
            display_mode: 'frameless',
            asset: {
                kind: 'browser_upload',
                asset_id: `transfer:${item.id}`,
                mime: item.type || 'image/png',
                size: item.size || 0,
                width: dimensions.width || item.width || null,
                height: dimensions.height || item.height || null,
                data_url: item.dataUrl || '',
                thumb
            },
            source: { kind: 'transfer_station', transfer_id: item.id }
        };
        fitImageNodeToAssetBounds(node, node.asset, { preserveCenter: false });
        placeNodeAvoidingOverlap(node, world);
        project.nodes.push(node);
        selectedNodeId = node.id;
        selectedEdgeId = null;
        mutate();
        showToast(t('Image node imported.', '已导入图片节点'));
    }

    async function applyTransferItemToImageNode(node, item, options) {
        if (!node || node.type !== 'image' || !item) return false;
        const dataUrl = item.dataUrl || '';
        const previewUrl = item.previewUrl || '';
        const dimensions = await getImageDimensions(dataUrl || previewUrl);
        const thumb = dataUrl ? await createThumbnailDataUrl(dataUrl, 1024) : previewUrl;
        pushHistory(options?.history || 'Replace image');
        node.asset = {
            kind: 'browser_upload',
            asset_id: item.id ? `transfer:${item.id}` : uid('asset'),
            mime: item.type || 'image/png',
            size: item.size || 0,
            width: dimensions.width || item.width || null,
            height: dimensions.height || item.height || null,
            data_url: dataUrl,
            preview_url: previewUrl,
            thumb
        };
        node.title = item.name || node.title || 'image';
        if (String(node.display_mode || node.image_display_mode || '').toLowerCase() !== 'card') node.display_mode = 'frameless';
        fitImageNodeToAssetBounds(node, node.asset);
        node.mask = null;
        node.source = Object.assign({}, node.source || {}, {
            kind: 'transfer_station_drop',
            transfer_id: item.id || ''
        });
        selectedNodeId = node.id;
        selectedNodeIds = new Set([node.id]);
        selectedEdgeId = null;
        invalidateRenderedNode(node.id);
        mutate();
        syncPresetSpecialViewersForAssetNode(node.id);
        showToast(t('Image placed into Image node.', '图片已放入图像节点'));
        materializeNodeAssetForStorage(node.id).catch((err) => console.warn('[SimpAI Canvas] dropped image materialize skipped:', err));
        return true;
    }

    async function applyImageFileToNode(node, file, options) {
        if (!node || !['image', 'result'].includes(node.type) || !isImageFile(file)) return false;
        const dataUrl = await readFileAsDataUrl(file);
        const dimensions = await getImageDimensions(dataUrl);
        const thumb = await createThumbnailDataUrl(dataUrl, 1024);
        pushHistory(options?.history || 'Replace image');
        node.asset = {
            kind: 'browser_upload',
            asset_id: uid('asset'),
            mime: file.type || 'image/png',
            size: file.size || 0,
            width: dimensions.width || null,
            height: dimensions.height || null,
            data_url: dataUrl,
            thumb
        };
        node.title = file.name || node.title || 'image';
        node.mask = null;
        node.source = Object.assign({}, node.source || {}, { kind: options?.sourceKind || 'manual_upload' });
        if (node.type === 'result') {
            node.status = Object.assign({}, node.status || {}, { state: 'manual', percent: 1, message: t('Output image manually replaced.', '手动替换的输出图片') });
            node.source = Object.assign({}, node.source || {}, { kind: 'manual_output' });
        } else if (String(node.display_mode || node.image_display_mode || '').toLowerCase() !== 'card') {
            node.display_mode = 'frameless';
            fitImageNodeToAssetBounds(node, node.asset);
        }
        selectedNodeId = node.id;
        selectedNodeIds = new Set([node.id]);
        selectedEdgeId = null;
        invalidateRenderedNode(node.id);
        mutate();
        syncPresetSpecialViewersForAssetNode(node.id);
        showToast(t('Image replaced.', '图片已替换'));
        materializeNodeAssetForStorage(node.id).catch((err) => console.warn('[SimpAI Canvas] image materialize skipped:', err));
        return true;
    }

    async function addVlmPendingImageFromFile(node, file) {
        if (!node || node.type !== 'vlm' || !isImageFile(file)) return false;
        const dataUrl = await readFileAsDataUrl(file);
        const dimensions = await getImageDimensions(dataUrl);
        const thumb = await createThumbnailDataUrl(dataUrl, 480);
        node.chat = Object.assign({}, node.chat || {});
        const pending = Array.isArray(node.chat.pending_images) ? node.chat.pending_images.slice() : [];
        pending.push({
            id: uid('vlm_img'),
            name: file.name || 'image',
            mime: file.type || 'image/png',
            size: file.size || 0,
            width: dimensions.width || null,
            height: dimensions.height || null,
            data_url: dataUrl,
            thumb,
            added_at: nowIso()
        });
        node.chat.pending_images = pending;
        mutate({ inspector: true });
        return true;
    }

    async function attachVlmImages(node) {
        if (!node || node.type !== 'vlm' || isNodeLocked(node)) return;
        const input = document.createElement('input');
        input.type = 'file';
        input.accept = 'image/*';
        input.multiple = true;
        input.style.display = 'none';
        document.body.appendChild(input);
        input.addEventListener('change', async () => {
            const files = Array.from(input.files || []).filter(isImageFile);
            for (const file of files) {
                await addVlmPendingImageFromFile(node, file);
            }
            input.remove();
            if (files.length) showToast(t('{count} image(s) attached.', '已添加 {count} 张图片').replace('{count}', files.length));
        }, { once: true });
        input.click();
    }

    function disconnectVlmImageInput(node, slot) {
        if (!node || node.type !== 'vlm' || isNodeLocked(node)) return;
        const targetSlot = VLM_IMAGE_SLOTS.some(item => item.key === slot) ? slot : 'image_1';
        const edge = project.edges.find(item => item.type === 'image' && item.to === node.id && item.slot === targetSlot);
        if (edge) {
            deleteEdge(edge.id);
            return;
        }
        if (node.image_inputs?.[targetSlot]) {
            pushHistory('Disconnect VLM image');
            node.image_inputs = Object.assign({}, node.image_inputs || {}, { [targetSlot]: null });
            mutate({ inspector: true });
        }
    }

    function insertVlmChatCommand(node, command) {
        if (!node || node.type !== 'vlm' || isNodeLocked(node)) return;
        const cleanCommand = String(command || '').trim();
        if (!cleanCommand) return;
        if (cleanCommand.toLowerCase() === '/regen') {
            runVlmRegenCommand(node);
            return;
        }
        const current = String(node.params?.prompt || '').trim();
        const next = current ? `${cleanCommand} ${current}` : `${cleanCommand} `;
        updateVlmParam(node.id, 'prompt', next, 'textarea');
        const nodeEl = nodesLayer?.querySelector?.(`[data-node-id="${CSS.escape(node.id)}"]`);
        const input = nodeEl?.querySelector?.('.sai-vlm-compose textarea[data-vlm-param="prompt"]');
        if (input) {
            input.value = next;
            input.focus();
            input.setSelectionRange(input.value.length, input.value.length);
        }
    }

    function runVlmRegenCommand(node) {
        if (!node || node.type !== 'vlm' || isNodeLocked(node)) return;
        if (isVlmNodeBusy(node)) {
            showToast(t('VLM is still thinking. Wait for it to finish before regenerating.', 'VLM 还在思考中，等它完成后再继续生成。'));
            return;
        }
        const message = t('Another one', '再来一张');
        updateVlmParam(node.id, 'prompt', message, 'textarea');
        const nodeEl = nodesLayer?.querySelector?.(`[data-node-id="${CSS.escape(node.id)}"]`);
        const input = nodeEl?.querySelector?.('.sai-vlm-compose textarea[data-vlm-param="prompt"]');
        if (input) input.value = message;
        runVlmNode(node);
    }

    async function handleVlmChatDrop(node, dataTransfer) {
        if (!node || node.type !== 'vlm' || !dataTransfer) return false;
        const files = Array.from(dataTransfer.files || []).filter(isImageFile);
        if (!files.length) return false;
        for (const file of files) {
            await addVlmPendingImageFromFile(node, file);
        }
        showToast(t('{count} image(s) attached.', '已添加 {count} 张图片').replace('{count}', files.length));
        return true;
    }

    function removeVlmPendingImage(node, index) {
        if (!node || node.type !== 'vlm' || isNodeLocked(node)) return;
        const pending = Array.isArray(node.chat?.pending_images) ? node.chat.pending_images.slice() : [];
        if (index < 0 || index >= pending.length) return;
        pending.splice(index, 1);
        node.chat = Object.assign({}, node.chat || {}, { pending_images: pending });
        mutate({ inspector: true });
    }

    async function addImageNodeFromFile(file, world) {
        const dataUrl = await readFileAsDataUrl(file);
        const dimensions = await getImageDimensions(dataUrl);
        const thumb = await createThumbnailDataUrl(dataUrl, 1024);
        pushHistory('Add image node');
        const node = {
            id: uid('img'),
            type: 'image',
            x: world.x,
            y: world.y,
            w: 264,
            h: 300,
            title: file.name || 'image',
            display_mode: 'frameless',
            asset: {
                kind: 'browser_upload',
                asset_id: uid('asset'),
                mime: file.type || 'image/png',
                size: file.size || 0,
                width: dimensions.width || null,
                height: dimensions.height || null,
                data_url: dataUrl,
                thumb
            },
            source: { kind: 'dropped_file' }
        };
        fitImageNodeToAssetBounds(node, node.asset, { preserveCenter: false });
        placeNodeAvoidingOverlap(node, world);
        project.nodes.push(node);
        selectedNodeId = node.id;
        selectedEdgeId = null;
        mutate();
        materializeNodeAssetForStorage(node.id).catch((err) => console.warn('[SimpAI Canvas] image materialize skipped:', err));
    }

    function getInputImageNodePosition(targetNode, handle, size) {
        const point = handle ? getHandleCenterWorldPoint(handle) : null;
        const targetRect = getNodeRect(targetNode);
        return {
            x: Math.round(targetRect.x - size.w - 80),
            y: Math.round((point ? point.y : targetRect.y + targetRect.h / 2) - size.h / 2)
        };
    }

    function createEmptyImageNodeForInput(targetNode, slotLabel, handle) {
        const size = { w: 264, h: 300 };
        const base = getInputImageNodePosition(targetNode, handle, size);
        const node = {
            id: uid('img'),
            type: 'image',
            x: base.x,
            y: base.y,
            w: size.w,
            h: size.h,
            title: slotLabel ? `${slotLabel} Image` : 'Input Image',
            display_mode: 'frameless',
            asset: null,
            source: {
                kind: 'manual_input_placeholder',
                target_node_id: targetNode?.id || '',
                target_slot: slotLabel || ''
            }
        };
        placeNodeAvoidingOverlap(node, base, { excludeIds: [targetNode?.id].filter(Boolean) });
        project.nodes.push(node);
        return node;
    }

    function createNodeForUploadInput(targetNode, slot, handle) {
        if (slot === 'sam3_mask_video') return createSam3VideoMaskNodeForPresetInput(targetNode, handle);
        if (getUploadSlotMediaKind(slot) === 'video') return createVideoNodeForUploadInput(targetNode, slot, handle);
        return createImageNodeForUploadInput(targetNode, slot, handle);
    }

    function pickLocalVideoFile() {
        const input = document.createElement('input');
        input.type = 'file';
        input.accept = 'video/*,.mp4,.webm,.mov,.m4v,.avi,.mkv';
        input.style.display = 'none';
        document.body.appendChild(input);
        return new Promise((resolve) => {
            input.addEventListener('change', () => {
                const file = input.files && input.files[0] ? input.files[0] : null;
                input.remove();
                resolve(file && isVideoFile(file) ? file : null);
            }, { once: true });
            input.click();
        });
    }

    function pickLocalAudioFile() {
        const input = document.createElement('input');
        input.type = 'file';
        input.accept = 'audio/*,.mp3,.wav,.ogg,.flac,.m4a,.aac,.opus';
        input.style.display = 'none';
        document.body.appendChild(input);
        return new Promise((resolve) => {
            input.addEventListener('change', () => {
                const file = input.files && input.files[0] ? input.files[0] : null;
                input.remove();
                resolve(file && isAudioFile(file) ? file : null);
            }, { once: true });
            input.click();
        });
    }

    async function createVideoNodeForUploadInput(targetNode, slot, handle) {
        if (!targetNode || !slot || !['preset', 'classic'].includes(targetNode.type)) return null;
        if (isNodeLocked(targetNode)) {
            showToast(t('Locked node cannot change inputs', '锁定节点不能修改输入'));
            return null;
        }
        const existingId = targetNode.upload_slots?.[slot];
        const existingNode = existingId ? getNode(existingId) : null;
        if (existingNode?.type === 'video' || existingNode?.type === 'result') {
            selectNode(existingNode.id);
            showToast(t('{slot} already has a video source.', '{slot} 已有视频源').replace('{slot}', getSlotLabel(targetNode, slot)));
            return existingNode;
        }
        const file = await pickLocalVideoFile();
        if (!file) return null;
        const size = defaultNodeSize('video');
        const base = getInputImageNodePosition(targetNode, handle, size);
        const videoNode = await addMediaNodeFromFile(file, base);
        if (!videoNode || videoNode.type !== 'video') return null;
        createUploadEdge(videoNode.id, targetNode.id, slot, { silent: true });
        selectedNodeId = videoNode.id;
        selectedNodeIds = new Set([videoNode.id]);
        selectedEdgeId = null;
        mutate();
        showToast(t('{slot} video node added.', '{slot} 视频节点已添加').replace('{slot}', getSlotLabel(targetNode, slot)));
        return videoNode;
    }

    async function uploadSourceVideoForSam3Node(targetNode, handle) {
        if (!targetNode || targetNode.type !== 'sam3_video_mask') return null;
        if (isNodeLocked(targetNode)) {
            showToast(t('Locked node cannot change inputs', '锁定节点不能修改输入'));
            return null;
        }
        const file = await pickLocalVideoFile();
        if (!file) return null;
        const size = defaultNodeSize('video');
        const base = getInputImageNodePosition(targetNode, handle, size);
        const videoNode = await addMediaNodeFromFile(file, base);
        if (!videoNode || videoNode.type !== 'video') return null;
        createSam3VideoMaskEdge(videoNode.id, targetNode.id, { silent: true });
        selectedNodeId = videoNode.id;
        selectedNodeIds = new Set([videoNode.id]);
        selectedEdgeId = null;
        mutate();
        showToast(t('Source video uploaded and connected to SAM3.', '源视频已上传并连接到 SAM3'));
        return videoNode;
    }

    function createImageNodeForUploadInput(targetNode, slot, handle) {
        if (!targetNode || !slot || !['preset', 'classic'].includes(targetNode.type)) return null;
        if (isNodeLocked(targetNode)) {
            showToast(t('Locked node cannot change inputs', '锁定节点不能修改输入'));
            return null;
        }
        if (slot === 'sam3_mask_video') {
            return createSam3VideoMaskNodeForPresetInput(targetNode, handle);
        }
        if (getUploadSlotMediaKind(slot) !== 'image') {
            showToast(t('Only image input ports support double-click creation of Image nodes.', '当前只有图片输入口支持双击创建图像节点'));
            return null;
        }
        const existingId = targetNode.upload_slots?.[slot];
        const existingNode = existingId ? getNode(existingId) : null;
        if (existingNode) {
            selectNode(existingNode.id);
            showToast(t('{slot} already has an image node.', '{slot} 已有图片节点').replace('{slot}', getSlotLabel(targetNode, slot)));
            return existingNode;
        }
        pushHistory('Add input image node');
        const imageNode = createEmptyImageNodeForInput(targetNode, getSlotLabel(targetNode, slot), handle);
        createUploadEdge(imageNode.id, targetNode.id, slot, { silent: true });
        selectedNodeId = imageNode.id;
        selectedNodeIds = new Set([imageNode.id]);
        selectedEdgeId = null;
        mutate();
        showToast(t('{slot} image node added.', '{slot} 图片节点已添加').replace('{slot}', getSlotLabel(targetNode, slot)));
        return imageNode;
    }

    function createAdvancedMaskNodeForClassicInput(targetNode, handle) {
        if (!targetNode || targetNode.type !== 'classic') return null;
        if (isNodeLocked(targetNode)) {
            showToast(t('Locked node cannot change inputs', '锁定节点不能修改输入'));
            return null;
        }
        const existingId = targetNode.upload_slots?.inpaint_mask;
        const existingNode = existingId ? getNode(existingId) : null;
        if (existingNode?.type === 'mask') {
            selectNode(existingNode.id);
            showToast(t('Advanced Masking node already connected', '高级遮罩节点已连接'));
            return existingNode;
        }
        const size = defaultNodeSize('mask');
        const base = getInputImageNodePosition(targetNode, handle, size);
        pushHistory('Add advanced masking node');
        const maskNode = addMaskNode(base, { history: false });
        const sourceId = targetNode.upload_slots?.inpaint_image || null;
        const sourceNode = sourceId ? getNode(sourceId) : null;
        if (sourceNode && ['image', 'result'].includes(sourceNode.type)) {
            createMaskImageEdge(sourceNode.id, maskNode.id, { silent: true });
        }
        createUploadEdge(maskNode.id, targetNode.id, 'inpaint_mask', { silent: true });
        targetNode.params = Object.assign({}, targetNode.params || {}, { inpaint_advanced_masking_checkbox: true });
        selectedNodeId = maskNode.id;
        selectedNodeIds = new Set([maskNode.id]);
        selectedEdgeId = null;
        mutate();
        showToast(sourceNode ? t('Advanced Masking added and connected to Source Image.', '高级遮罩已添加并接入源图像') : t('Advanced Masking added; connect a Source Image.', '高级遮罩已添加，请连接源图像'));
        return maskNode;
    }

    function createSam3VideoMaskNodeForPresetInput(targetNode, handle) {
        if (!targetNode || !['preset', 'classic'].includes(targetNode.type)) return null;
        const existingId = targetNode.upload_slots?.sam3_mask_video;
        const existingNode = existingId ? getNode(existingId) : null;
        if (existingNode?.type === 'sam3_video_mask') {
            selectNode(existingNode.id);
            showToast(t('SAM3 Video Mask node already connected', 'SAM3 视频遮罩节点已连接'));
            return existingNode;
        }
        const size = defaultNodeSize('sam3_video_mask');
        const base = getInputImageNodePosition(targetNode, handle, size);
        pushHistory('Add SAM3 video mask node');
        const sam3Node = addSam3VideoMaskNode(base, { history: false, render: false, toast: false });
        const sourceId = targetNode.upload_slots?.sam3_input_video || targetNode.upload_slots?.scene_video || null;
        const sourceNode = sourceId ? getNode(sourceId) : null;
        if (sourceNode && isSam3VideoMaskSource(sourceNode)) {
            createSam3VideoMaskEdge(sourceNode.id, sam3Node.id, { silent: true });
        }
        createUploadEdge(sam3Node.id, targetNode.id, 'sam3_mask_video', { silent: true });
        selectedNodeId = sam3Node.id;
        selectedNodeIds = new Set([sam3Node.id]);
        selectedEdgeId = null;
        mutate();
        showToast(sourceNode ? t('SAM3 Video Mask added and connected to source video.', 'SAM3 视频遮罩已添加并接入源视频。') : t('SAM3 Video Mask added; connect a source video.', 'SAM3 视频遮罩已添加，请连接源视频。'));
        return sam3Node;
    }

    function createImageNodeForImageInput(targetNode, kind, slot, handle) {
        if (!targetNode || !kind) return null;
        if (isNodeLocked(targetNode)) {
            showToast(t('Locked node cannot change inputs', '锁定节点不能修改输入'));
            return null;
        }
        const existingId = kind === 'vlm'
            ? targetNode.image_inputs?.[slot || 'image_1']
            : targetNode.input_node_id;
        const existingNode = existingId ? getNode(existingId) : null;
        if (existingNode) {
            selectNode(existingNode.id);
            showToast(t('This input already has an image node.', '输入口已有图片节点'));
            return existingNode;
        }
        const label = kind === 'vlm'
            ? (VLM_IMAGE_SLOTS.find(item => item.key === slot)?.label || slot || 'Image')
            : kind === 'pose_studio'
            ? t('Reference', '参考图')
            : kind === 'gaussian_studio'
            ? t('Reference', '参考图')
            : 'Image';
        pushHistory('Add input image node');
        const imageNode = createEmptyImageNodeForInput(targetNode, label, handle);
        if (kind === 'vlm') createVlmImageEdge(imageNode.id, targetNode.id, slot, { silent: true });
        else if (kind === 'pose_studio') createPoseStudioReferenceEdge(imageNode.id, targetNode.id, { silent: true });
        else if (kind === 'gaussian_studio') createGaussianStudioReferenceEdge(imageNode.id, targetNode.id, { silent: true });
        else createWd14ImageEdge(imageNode.id, targetNode.id, { silent: true });
        selectedNodeId = imageNode.id;
        selectedNodeIds = new Set([imageNode.id]);
        selectedEdgeId = null;
        mutate();
        showToast(t('{label} node added.', '{label} 节点已添加').replace('{label}', label));
        return imageNode;
    }

    async function addMediaNodeFromFile(file, world) {
        if (isImageFile(file)) return addImageNodeFromFile(file, world);
        const type = isVideoFile(file) ? 'video' : 'audio';
        const dataUrl = await readFileAsDataUrl(file);
        const metadata = await getMediaMetadata(dataUrl, type);
        const previewFrames = type === 'video' ? await createVideoStoryboardDataUrls(dataUrl, metadata.duration, 8) : [];
        const waveform = type === 'audio' ? await createAudioWaveformPeaks(file, 96) : [];
        pushHistory(`Add ${type} node`);
        const size = defaultNodeSize(type);
        const duration = metadata.duration || null;
        const node = {
            id: uid(type === 'video' ? 'vid' : 'aud'),
            type,
            x: world.x,
            y: world.y,
            w: size.w,
            h: size.h,
            title: file.name || type,
            asset: {
                kind: 'browser_upload',
                asset_id: uid('asset'),
                mime: file.type || (type === 'video' ? 'video/mp4' : 'audio/mpeg'),
                size: file.size || 0,
                width: metadata.width || null,
                height: metadata.height || null,
                duration,
                fps: metadata.fps || null,
                frame_count: metadata.frame_count || null,
                data_url: dataUrl,
                thumb: previewFrames[0]?.thumb || '',
                preview_frames: previewFrames,
                waveform,
                edit: duration ? { trim_start: 0, trim_end: duration, enabled: false } : null
            },
            source: { kind: 'dropped_file' }
        };
        placeNodeAvoidingOverlap(node, world);
        project.nodes.push(node);
        selectedNodeId = node.id;
        selectedEdgeId = null;
        mutate();
        materializeNodeAssetForStorage(node.id).catch((err) => console.warn('[SimpAI Canvas] media materialize skipped:', err));
        return node;
    }

    function addBatchAnyNode(world, options) {
        const opts = options || {};
        const size = defaultNodeSize('batch_any');
        if (opts.history !== false) pushHistory('Add Batch Any node');
        const node = {
            id: uid('batch'),
            type: 'batch_any',
            x: world.x,
            y: world.y,
            w: size.w,
            h: size.h,
            title: opts.title || 'Batch Any',
            media_kind: '',
            items: [],
            current_index: 0,
            params: { stop_on_error: true },
            batch: { state: 'idle', run_ids: [], last_error: '' },
            asset: null,
            source: { kind: 'batch_any' }
        };
        placeNodeAvoidingOverlap(node, world, opts);
        project.nodes.push(node);
        const autoMessage = completePendingConnectionToNode(node);
        selectedNodeId = node.id;
        selectedNodeIds = new Set([node.id]);
        selectedEdgeId = null;
        if (opts.render !== false) mutate({ inspector: true });
        if (opts.toast !== false) showToast(autoMessage ? t('Batch Any node added, {message}', 'Batch Any 节点已添加，{message}').replace('{message}', autoMessage) : t('Batch Any node added', 'Batch Any 节点已添加'));
        return node;
    }

    async function createBatchAnyItemFromFile(file, kind) {
        if (kind === 'text') {
            const text = await readFileAsText(file);
            return {
                id: uid('batch_item'),
                name: file.name || 'text item',
                media_kind: 'text',
                added_at: nowIso(),
                text: { value: text, updated_at: nowIso() },
                asset: null
            };
        }
        const dataUrl = await readFileAsDataUrl(file);
        let metadata = { width: null, height: null, duration: null, fps: null, frame_count: null };
        let thumb = '';
        let previewFrames = [];
        let waveform = [];
        if (kind === 'image') {
            metadata = await getImageDimensions(dataUrl);
            thumb = await createThumbnailDataUrl(dataUrl, 1024);
        } else {
            metadata = await getMediaMetadata(dataUrl, kind);
            previewFrames = kind === 'video' ? await createVideoStoryboardDataUrls(dataUrl, metadata.duration, 8) : [];
            waveform = kind === 'audio' ? await createAudioWaveformPeaks(file, 96) : [];
            thumb = previewFrames[0]?.thumb || '';
        }
        const duration = metadata.duration || null;
        return {
            id: uid('batch_item'),
            name: file.name || `${kind} item`,
            media_kind: kind,
            added_at: nowIso(),
            asset: {
                kind: 'browser_upload',
                asset_id: uid('asset'),
                mime: file.type || (kind === 'video' ? 'video/mp4' : (kind === 'audio' ? 'audio/mpeg' : 'image/png')),
                size: file.size || 0,
                width: metadata.width || null,
                height: metadata.height || null,
                duration,
                fps: metadata.fps || null,
                frame_count: metadata.frame_count || null,
                data_url: dataUrl,
                thumb,
                preview_frames: previewFrames,
                waveform,
                edit: duration ? { trim_start: 0, trim_end: duration, enabled: false } : null
            }
        };
    }

    async function materializeBatchAnyItemForStorage(nodeId, itemId) {
        const node = getNode(nodeId);
        if (!node || node.type !== 'batch_any') return { ok: false, error: 'batch node not found' };
        const index = (node.items || []).findIndex(item => item.id === itemId);
        const item = index >= 0 ? node.items[index] : null;
        if (!item || !item.asset?.data_url) return { ok: false, error: 'item has no inline asset' };
        const response = await sendCanvasMaterializeAssetRequest({
            project_id: project.id || PROJECT_ID,
            asset_source: {
                node_id: `${node.id}:item:${item.id}`,
                type: item.media_kind || batchAnyMediaKind(node) || 'image',
                title: item.name || '',
                asset: serializeAssetForRun(item.asset),
                mask: null,
                source: {
                    kind: 'batch_any_item',
                    batch_node_id: node.id,
                    batch_item_id: item.id,
                    batch_index: index
                }
            }
        });
        const currentNode = getNode(nodeId);
        const currentItem = currentNode?.items?.find(entry => entry.id === itemId);
        if (!currentNode || !currentItem || !response?.ok || !response.asset_ref) return response;
        const ref = response.asset_ref || {};
        currentItem.asset = Object.assign({}, currentItem.asset || {}, ref, {
            kind: ref.kind || currentItem.asset.kind || 'canvas_asset',
            mime: ref.mime || currentItem.asset.mime || '',
            width: ref.width || currentItem.asset.width || null,
            height: ref.height || currentItem.asset.height || null,
            duration: ref.duration || currentItem.asset.duration || null,
            fps: ref.fps || currentItem.asset.fps || null,
            frame_count: ref.frame_count || currentItem.asset.frame_count || null,
            size: ref.size || currentItem.asset.size || null,
            preview_url: ref.preview_url || currentItem.asset.preview_url || '',
            thumb: currentItem.asset.thumb || ref.preview_url || '',
            generation_metadata: ref.generation_metadata || currentItem.asset.generation_metadata || null
        });
        if (ref.asset_root) setCanvasProjectAssetRoot(ref.asset_root);
        if (currentItem.asset.path || currentItem.asset.preview_url) delete currentItem.asset.data_url;
        currentItem.materialized_at = nowIso();
        if (Number(currentNode.current_index || 0) === index) currentNode.asset = currentItem.asset;
        saveProjectToBrowserCache();
        renderAll({ inspector: selectedNodeId === currentNode.id });
        return response;
    }

    function createBatchAnyItemFromSourceNode(source, kind) {
        if (kind === 'text') {
            const text = batchAnySourceText(source);
            if (!source) return null;
            return {
                id: uid('batch_item'),
                name: source.title || `${t('Text', '文本')} item`,
                media_kind: 'text',
                source_node_id: source.id,
                source_node_type: source.type,
                added_at: nowIso(),
                text: { value: text, updated_at: nowIso() },
                asset: null
            };
        }
        const asset = batchAnySourceAsset(source);
        if (!source || !asset) return null;
        const clonedAsset = cloneRunValue(asset, {});
        return {
            id: uid('batch_item'),
            name: source.title || clonedAsset.name || clonedAsset.filename || `${kind} item`,
            media_kind: kind,
            source_node_id: source.id,
            source_node_type: source.type,
            added_at: nowIso(),
            asset: clonedAsset
        };
    }

    function addSourceNodeToBatchAny(source, node, options) {
        const opts = options || {};
        if (!source || !node || node.type !== 'batch_any') return null;
        if (isNodeLocked(source) || isNodeLocked(node)) {
            if (opts.toast !== false) showToast('Locked nodes cannot change connections');
            return null;
        }
        if (!isBatchAnySourceNode(source)) {
            if (opts.toast !== false) showToast(t('Batch Any accepts text, image, video, audio, and result outputs.', 'Batch Any 可接入文本、图片、视频、音频和 Result 输出。'));
            return null;
        }
        const kind = batchAnySourceMediaKind(source);
        if (!batchAnyAcceptsMediaKind(node, kind)) {
            if (opts.toast !== false) showToast(t('This Batch Any already uses another media type.', '这个 Batch Any 已经使用另一种素材类型。'));
            return null;
        }
        const item = createBatchAnyItemFromSourceNode(source, kind);
        if (!item) {
            if (opts.toast !== false) showToast(t('No usable batch item found on source node.', '来源节点没有可用批量项。'));
            return null;
        }
        if (opts.history !== false) pushHistory('Add Batch Any source');
        node.items = Array.isArray(node.items) ? node.items : [];
        node.media_kind = node.media_kind || kind;
        const edgeId = uid('edge');
        item.source_edge_id = edgeId;
        node.items.push(item);
        project.edges.push({
            id: edgeId,
            type: 'batch_input',
            from: source.id,
            to: node.id,
            slot: item.id,
            media_kind: kind
        });
        if (node.items.length === 1) {
            node.current_index = 0;
            node.asset = item.asset || null;
            if (item.media_kind === 'text') node.text = { value: batchAnyTextFromItem(item), updated_at: item.added_at || nowIso() };
        }
        node.batch = Object.assign({ state: 'idle', run_ids: [], last_error: '' }, node.batch || {}, { state: 'idle', last_error: '' });
        if (opts.select !== false) {
            selectedNodeId = node.id;
            selectedNodeIds = new Set([node.id]);
            selectedEdgeId = null;
        }
        if (opts.render === false) scheduleSave();
        else mutate({ inspector: selectedNodeId === node.id });
        if (opts.toast !== false) {
            showToast(t('Added {name} to Batch Any.', '已加入 Batch Any：{name}').replace('{name}', item.name || source.id));
        }
        return item;
    }

    function createBatchAnyInputEdge(fromId, toId, options) {
        const source = getNode(fromId);
        const node = getNode(toId);
        return addSourceNodeToBatchAny(source, node, options);
    }

    async function addBatchAnyFilesToNode(node, files) {
        if (!node || node.type !== 'batch_any' || isNodeLocked(node)) return;
        const selected = Array.from(files || []).filter(file => isMediaFile(file) || isBatchTextFile(file));
        if (!selected.length) {
            showToast(t('No supported files selected.', '没有可用的文件。'));
            return;
        }
        const currentKind = batchAnyMediaKind(node);
        const firstKind = currentKind || batchAnyMediaKindFromFile(selected[0]);
        if (!firstKind) {
            showToast(t('Unsupported first file.', '第一个文件不支持。'));
            return;
        }
        const accepted = selected.filter(file => batchAnyMediaKindFromFile(file) === firstKind);
        const skipped = selected.length - accepted.length;
        if (!accepted.length) {
            showToast(t('Selected files do not match this Batch type.', '所选文件与当前批次类型不一致。'));
            return;
        }
        pushHistory('Import Batch Any files');
        node.media_kind = firstKind;
        node.items = Array.isArray(node.items) ? node.items : [];
        node.batch = Object.assign({}, node.batch || {}, { state: 'importing', last_error: '' });
        mutate({ inspector: true });
        for (const file of accepted) {
            const item = await createBatchAnyItemFromFile(file, firstKind);
            node.items.push(item);
            if (node.items.length === 1) {
                node.current_index = 0;
                node.asset = item.asset || null;
                if (item.media_kind === 'text') node.text = { value: batchAnyTextFromItem(item), updated_at: item.added_at || nowIso() };
            }
            if (item.asset?.data_url) materializeBatchAnyItemForStorage(node.id, item.id).catch((err) => console.warn('[SimpAI Canvas] batch item materialize skipped:', err));
        }
        if (!node.asset && node.items.length) setBatchAnyCurrentItem(node, 0, { render: false });
        node.batch = Object.assign({}, node.batch || {}, { state: 'idle', imported_at: nowIso(), last_error: '' });
        mutate({ inspector: true });
        showToast(skipped
            ? t('Imported {count} item(s); skipped {skipped} mismatched file(s).', '已导入 {count} 个素材；跳过 {skipped} 个类型不一致的文件。').replace('{count}', accepted.length).replace('{skipped}', skipped)
            : t('Imported {count} item(s).', '已导入 {count} 个素材。').replace('{count}', accepted.length));
    }

    function openBatchAnyFilePicker(node) {
        if (!node || node.type !== 'batch_any') return;
        const input = document.createElement('input');
        input.type = 'file';
        input.accept = 'image/*,video/*,audio/*,text/plain,.txt,.md';
        input.multiple = true;
        input.hidden = true;
        document.body.appendChild(input);
        input.addEventListener('change', async () => {
            const files = Array.from(input.files || []);
            input.remove();
            await addBatchAnyFilesToNode(node, files);
        }, { once: true });
        input.click();
    }

    async function runBatchAnyNode(node, options) {
        if (!node || node.type !== 'batch_any') return { ok: false, error: 'batch node not found' };
        const opts = options || {};
        const items = Array.isArray(node.items) ? node.items : [];
        if (!items.length) {
            showToast(t('Import files before running Batch Any.', '请先导入素材再运行 Batch Any。'));
            return { ok: false, error: 'no batch items' };
        }
        const target = batchAnyTargets(node)[0];
        if (!target?.node) {
            showToast(t('Connect Batch Any to a preset input first.', '请先把 Batch Any 连接到 preset 输入槽。'));
            return { ok: false, error: 'no target preset' };
        }
        const indexes = opts.currentOnly ? [Number(node.current_index || 0)] : items.map((_, index) => index);
        const jobId = uid('batch_any_job');
        node.batch = Object.assign({}, node.batch || {}, {
            state: 'running',
            job_id: jobId,
            target_node_id: target.node.id,
            target_slot: target.slot,
            current: 0,
            total: indexes.length,
            run_ids: [],
            last_error: ''
        });
        project.batch_jobs = Array.isArray(project.batch_jobs) ? project.batch_jobs : [];
        project.batch_jobs.push({
            id: jobId,
            script: 'Batch Any',
            source_node_id: node.id,
            target_node_id: target.node.id,
            target_slot: target.slot,
            item_ids: indexes.map(index => items[index]?.id || ''),
            run_ids: [],
            status: 'running',
            created_at: nowIso(),
            updated_at: nowIso()
        });
        mutate({ inspector: true });
        const job = project.batch_jobs.find(entry => entry.id === jobId);
        const results = [];
        let batchResultNode = null;
        let batchAssets = [];
        for (let order = 0; order < indexes.length; order += 1) {
            const index = indexes[order];
            const item = setBatchAnyCurrentItem(node, index, { render: false });
            if (!item) continue;
            node.batch.current = order + 1;
            node.batch.active_item_id = item.id;
            node.batch.active_item_name = item.name || '';
            mutate({ inspector: selectedNodeId === node.id });
            const result = await runPresetNode(target.node, {
                resultNode: batchResultNode,
                reuseExistingResult: !!batchResultNode,
                skipInputPreflight: true,
                initialDelayMs: 900
            });
            results.push(result);
            const runId = result?.result?.run_id || getNode(result?.result_node_id)?.producer?.run_id || '';
            if (runId) {
                node.batch.run_ids = Array.isArray(node.batch.run_ids) ? node.batch.run_ids.concat([runId]) : [runId];
                if (job) job.run_ids = Array.isArray(job.run_ids) ? job.run_ids.concat([runId]) : [runId];
            }
            const resultNode = getNode(result?.result_node_id);
            if (resultNode) {
                if (!batchResultNode) batchResultNode = resultNode;
                const newAssets = batchAnyResultAssetsFromResponse(result, resultNode);
                const assetIndex = batchAssets.length;
                if (newAssets.length) {
                    batchAssets = batchAssets.concat(cloneRunValue(newAssets, []));
                    resultNode.assets = cloneRunValue(batchAssets, []);
                    resultNode.selected_asset_index = assetIndex;
                    resultNode.asset = cloneRunValue(batchAssets[assetIndex], resultNode.asset || null);
                }
                resultNode.title = batchAnyResultTitle(node);
                resultNode.batch_job_id = jobId;
                resultNode.batch_node_id = node.id;
                resultNode.batch_item_id = item.id || resultNode.batch_item_id || '';
                resultNode.batch_index = index;
                resultNode.batch_item_name = item.name || resultNode.batch_item_name || '';
                resultNode.grid_role = 'batch_result';
            }
            if (!result?.ok && node.params?.stop_on_error !== false) {
                const error = result?.error || t('Batch item failed.', '批量素材运行失败。');
                node.batch.last_error = error;
                if (job) job.status = 'failed';
                break;
            }
        }
        const failed = results.find(result => !result?.ok);
        node.batch.state = failed ? 'failed' : 'finished';
        node.batch.finished_at = nowIso();
        if (job) {
            job.status = node.batch.state;
            job.updated_at = nowIso();
        }
        if (batchResultNode) {
            selectedNodeId = batchResultNode.id;
            selectedNodeIds = new Set([batchResultNode.id]);
            selectedEdgeId = null;
        }
        mutate({ inspector: true });
        showToast(failed ? t('Batch Any stopped with an error.', 'Batch Any 因错误停止。') : t('Batch Any finished.', 'Batch Any 已完成。'));
        return { ok: !failed, results, job_id: jobId };
    }

    async function applyMediaFileToNode(node, file, options) {
        if (!node || !['video', 'audio'].includes(node.type) || !file) return false;
        if (isNodeLocked(node)) {
            showToast(t('Locked node cannot be edited', '锁定节点不能编辑'));
            return false;
        }
        const type = isVideoFile(file) ? 'video' : (isAudioFile(file) ? 'audio' : '');
        if (!type || type !== node.type) {
            showToast(type ? t('Selected media type does not match this node.', '所选媒体类型与当前节点不匹配。') : t('Unsupported media file.', '不支持的媒体文件。'));
            return false;
        }
        const dataUrl = await readFileAsDataUrl(file);
        const metadata = await getMediaMetadata(dataUrl, type);
        const previewFrames = type === 'video' ? await createVideoStoryboardDataUrls(dataUrl, metadata.duration, 8) : [];
        const waveform = type === 'audio' ? await createAudioWaveformPeaks(file, 96) : [];
        const duration = metadata.duration || null;
        pushHistory(options?.history || (type === 'video' ? 'Re-upload video asset' : 'Re-upload audio asset'));
        node.title = file.name || node.title || type;
        node.asset = {
            kind: 'browser_upload',
            asset_id: uid('asset'),
            mime: file.type || (type === 'video' ? 'video/mp4' : 'audio/mpeg'),
            size: file.size || 0,
            width: metadata.width || null,
            height: metadata.height || null,
            duration,
            fps: metadata.fps || null,
            frame_count: metadata.frame_count || null,
            data_url: dataUrl,
            thumb: previewFrames[0]?.thumb || '',
            preview_frames: previewFrames,
            waveform,
            edit: duration ? { trim_start: 0, trim_end: duration, enabled: false } : null
        };
        node.source = Object.assign({}, node.source || {}, {
            kind: options?.sourceKind || 'manual_reupload',
            uploaded_name: file.name || '',
            uploaded_at: nowIso()
        });
        mutate({ inspector: true });
        const response = await materializeNodeAssetForStorage(node.id);
        const successMessage = type === 'video'
            ? t('Video asset replaced.', '视频资产已替换。')
            : t('Audio asset replaced.', '音频资产已替换。');
        const browserOnlyMessage = type === 'video'
            ? t('Video asset replaced in browser; storage failed.', '视频已在浏览器中替换；入库失败。')
            : t('Audio asset replaced in browser; storage failed.', '音频已在浏览器中替换；入库失败。');
        showToast(response?.ok ? successMessage : browserOnlyMessage);
        return true;
    }

    async function materializeNodeAssetForStorage(nodeId) {
        const node = getNode(nodeId);
        if (!node || !node.asset?.data_url) return { ok: false, error: 'node has no inline asset' };
        const response = await sendCanvasMaterializeAssetRequest({
            project_id: project.id || PROJECT_ID,
            asset_source: serializeAssetSourceForRun(node)
        });
        const current = getNode(nodeId);
        if (!current || !response?.ok || !response.asset_ref) return response;
        const ref = response.asset_ref || {};
        current.asset = Object.assign({}, current.asset || {}, ref, {
            kind: ref.kind || current.asset.kind || 'canvas_asset',
            mime: ref.mime || current.asset.mime || '',
            width: ref.width || current.asset.width || null,
            height: ref.height || current.asset.height || null,
            duration: ref.duration || current.asset.duration || null,
            fps: ref.fps || current.asset.fps || null,
            frame_count: ref.frame_count || current.asset.frame_count || null,
            size: ref.size || current.asset.size || null,
            preview_url: ref.preview_url || current.asset.preview_url || '',
            thumb: current.asset.thumb || ref.preview_url || '',
            generation_metadata: ref.generation_metadata || current.asset.generation_metadata || null
        });
        if (ref.asset_root) setCanvasProjectAssetRoot(ref.asset_root);
        if (current.asset.path || current.asset.preview_url) delete current.asset.data_url;
        current.source = Object.assign({}, current.source || {}, {
            materialized_asset_id: ref.asset_id || '',
            materialized_path: ref.path || '',
            materialized_at: nowIso()
        });
        saveProjectToBrowserCache();
        invalidateRenderedNode(current.id);
        renderAll({ inspector: false });
        syncPresetSpecialViewersForAssetNode(current.id);
        return response;
    }

    function readFileAsDataUrl(file) {
        return WORKBENCH_MEDIA_HELPERS.readFileAsDataUrl(file);
    }

    function readFileAsText(file) {
        return WORKBENCH_MEDIA_HELPERS.readFileAsText(file);
    }

    function extractWorkbenchProjectJson(raw) {
        const parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
        const candidate = parsed && typeof parsed === 'object' && parsed.project && typeof parsed.project === 'object'
            ? parsed.project
            : parsed;
        if (!candidate || typeof candidate !== 'object') throw new Error('JSON is not an object');
        const hasWorkbenchShape = candidate.schema === 'simpai.canvas.workbench.v1'
            || (Array.isArray(candidate.nodes) && Array.isArray(candidate.edges));
        if (!hasWorkbenchShape) throw new Error('Not a Canvas Workbench project JSON');
        return candidate;
    }

    function projectIdFromWorkbenchFile(file) {
        let name = String(file?.name || '').trim();
        name = name.replace(/\.canvas\.json$/i, '').replace(/\.workbench\.json$/i, '').replace(/\.json$/i, '');
        return sanitizeStoragePart(name).replace(/[:]/g, '_');
    }

    function importedProjectId(incoming, file) {
        const currentId = sanitizeStoragePart(project?.id || PROJECT_ID).replace(/[:]/g, '_') || PROJECT_ID;
        const incomingId = sanitizeStoragePart(incoming?.id || '').replace(/[:]/g, '_');
        const fileId = projectIdFromWorkbenchFile(file);
        let nextId = incomingId || fileId || `imported_${Date.now()}`;
        if (nextId === currentId) {
            const base = fileId && fileId !== currentId ? fileId : `${currentId}_import`;
            nextId = `${base}_${new Date().toISOString().replace(/[-:.TZ]/g, '').slice(0, 14)}`;
        }
        return nextId;
    }

    async function importWorkbenchProjectFromFile(file, options) {
        try {
            const incoming = extractWorkbenchProjectJson(await readFileAsText(file));
            await saveProject(true, { persist: false });
            const nextProjectId = importedProjectId(incoming, file);
            setActiveBrowserCacheProject(nextProjectId, storageScope);
            project = sanitizeProject(incoming);
            project.id = nextProjectId;
            project.title = project.title || nextProjectId;
            project.storage = buildProjectStorageInfo(storageKey, storageScope);
            resetRenderedProjectDomCache();
            selectedNodeId = null;
            selectedEdgeId = null;
            selectedNodeIds = new Set();
            resetHistory();
            saveProjectToBrowserCache();
            renderAll();
            resetGalleryFrostReveals();
            if (options?.persist) await saveProject(false, { persist: true, backupExisting: false });
            else showToast(`Imported ${file.name || 'workbench JSON'} into browser cache`);
        } catch (error) {
            console.warn('[SimpAI Canvas] failed to import workbench JSON:', error);
            showToast(`Import failed: ${error?.message || error || 'invalid JSON'}`);
        }
    }

