    function updateTextNodeValue(nodeId, value) {
        const node = getNode(nodeId);
        if (!node || !isTextOutputNode(node)) return;
        if (isNodeLocked(node)) return;
        if (['text', 'translation', 'tag_cart'].includes(node.type) && getTextNodeInputSource(node) && node.type === 'text') return;
        pushHistoryBatch(`text:${nodeId}:value`, node.type === 'wd14' ? 'Edit WD14 output' : (node.type === 'vlm' ? 'Edit VLM output' : (node.type === 'translation' ? 'Edit translation output' : (node.type === 'tag_cart' ? 'Edit Tag Cart output' : 'Edit text node'))));
        node.text = Object.assign({}, node.text || {}, { value: String(value || ''), updated_at: nowIso() });
        scheduleSave();
    }

    function refreshNoteDom(nodeId) {
        const node = getNode(nodeId);
        const nodeEl = nodesLayer?.querySelector(`[data-node-id="${CSS.escape(nodeId || '')}"]`);
        if (!node || !nodeEl || node.type !== 'note') return;
        const body = nodeEl.querySelector('[data-note-text]');
        if (!body) return;
        const style = Object.assign({ color: '#f8fafc', background: '#164e63', font_size: 14 }, node.style || {});
        body.style.color = normalizeCanvasColor(style.color, '#f8fafc');
        body.style.background = normalizeCanvasColor(style.background, '#164e63');
        body.style.fontSize = `${clamp(Number(style.font_size || 14), 10, 42)}px`;
        if (document.activeElement !== body) body.value = node.text || '';
    }

    function updateNoteText(nodeId, value, options) {
        const node = getNode(nodeId);
        if (!node || node.type !== 'note' || isNodeLocked(node)) return;
        pushHistoryBatch(`note:${nodeId}:text`, 'Edit tip note');
        node.text = String(value || '');
        scheduleSave();
        if (options?.render) mutate({ inspector: true });
        else refreshNoteDom(nodeId);
    }

    function updateNoteStyle(nodeId, key, value, inputType) {
        const node = getNode(nodeId);
        if (!node || node.type !== 'note' || isNodeLocked(node) || !key) return;
        pushHistoryBatch(`note:${nodeId}:style:${key}`, 'Edit tip note style');
        node.style = Object.assign({}, node.style || {});
        node.style[key] = inputType === 'number' || key === 'font_size'
            ? clamp(Number(value || 14), 10, 42)
            : normalizeCanvasColor(value, key === 'color' ? '#f8fafc' : '#164e63');
        refreshNoteDom(nodeId);
        scheduleSave();
    }

    function updateNodeCustomColor(nodeId, value, options) {
        const node = getNode(nodeId);
        if (!node || isNodeLocked(node)) return;
        const color = normalizeCanvasColor(value, '');
        pushHistoryBatch(`node:${nodeId}:custom-color`, 'Edit node color');
        node.style = Object.assign({}, node.style || {});
        if (color) {
            node.style.node_color = expandCanvasHexColor(color, '#14b8a6');
            delete node.style.accent_color;
        } else {
            delete node.style.node_color;
            delete node.style.accent_color;
            if (!Object.keys(node.style).length) delete node.style;
        }
        const nodeEl = nodesLayer?.querySelector?.(`[data-node-id="${CSS.escape(nodeId || '')}"]`);
        if (nodeEl) applyNodeCustomColorVars(node, nodeEl);
        invalidateMinimapStaticCache();
        renderMinimap();
        scheduleSave();
        if (options?.renderInspector) renderInspector();
    }

    function updateNoteSize(nodeId, key, value) {
        const node = getNode(nodeId);
        if (!node || node.type !== 'note' || isNodeLocked(node) || !['w', 'h'].includes(key)) return;
        pushHistoryBatch(`note:${nodeId}:size:${key}`, 'Resize tip note');
        node[key] = Math.round(Math.max(key === 'w' ? 180 : 120, Number(value || 0)));
        updateNodePositionDom([nodeId]);
        renderEdges();
        renderMinimap();
        scheduleSave();
    }

    function updateNoteTail(nodeId, key, value, inputType, options) {
        const node = getNode(nodeId);
        if (!node || node.type !== 'note' || isNodeLocked(node) || !key) return;
        pushHistoryBatch(`note:${nodeId}:tail:${key}`, 'Edit tip note pointer');
        node.tail = Object.assign({}, node.tail || {});
        if (key === 'enabled') {
            node.tail.enabled = inputType === 'checkbox' ? !!value : !!value;
            if (node.tail.enabled) ensureNoteTailTarget(node);
        } else if (key === 'target_x' || key === 'target_y') {
            const target = ensureNoteTailTarget(node);
            target[key === 'target_x' ? 'x' : 'y'] = Math.round(Number(value || 0));
            node.tail.enabled = true;
        }
        scheduleSave();
        renderEdges();
        if (options?.renderNodes) renderNodes();
        if (options?.renderInspector) renderInspector();
    }

    function toggleNoteTail(node) {
        if (!node || node.type !== 'note' || isNodeLocked(node)) return;
        pushHistory('Toggle tip note pointer');
        node.tail = Object.assign({}, node.tail || {});
        node.tail.enabled = !node.tail.enabled;
        if (node.tail.enabled) ensureNoteTailTarget(node);
        scheduleSave();
        renderNodes();
        renderEdges();
        if (selectedNodeId === node.id) renderInspector();
    }

    function resetNoteTail(node) {
        if (!node || node.type !== 'note' || isNodeLocked(node)) return;
        pushHistory('Reset tip note pointer');
        node.tail = Object.assign({}, node.tail || {}, {
            enabled: true,
            target: defaultNoteTailTarget(node)
        });
        scheduleSave();
        renderNodes();
        renderEdges();
        if (selectedNodeId === node.id) renderInspector();
    }

    function startNoteTailDrag(node, evt) {
        if (!node || node.type !== 'note' || isNodeLocked(node)) {
            showToast(t('Locked note pointer cannot be moved.', '锁定的提示贴不能移动指引点。'));
            return;
        }
        const target = ensureNoteTailTarget(node);
        selectedNodeId = node.id;
        selectedNodeIds = new Set([node.id]);
        selectedEdgeId = null;
        selectedGroupId = null;
        noteTailDragState = {
            pointerId: evt.pointerId,
            nodeId: node.id,
            startClientX: evt.clientX,
            startClientY: evt.clientY,
            startX: Number(target.x || 0),
            startY: Number(target.y || 0),
            historyPushed: false
        };
        updateSelectionDomClasses();
        renderEdges();
        renderInspector();
        document.addEventListener('pointermove', onNoteTailDragMove, true);
        document.addEventListener('pointerup', stopNoteTailDrag, true);
        document.addEventListener('pointercancel', stopNoteTailDrag, true);
    }

    function onNoteTailDragMove(evt) {
        if (!noteTailDragState || evt.pointerId !== noteTailDragState.pointerId) return;
        const node = getNode(noteTailDragState.nodeId);
        if (!node || node.type !== 'note') return;
        evt.preventDefault();
        const zoom = project.viewport.zoom || 1;
        const dx = (evt.clientX - noteTailDragState.startClientX) / zoom;
        const dy = (evt.clientY - noteTailDragState.startClientY) / zoom;
        if (!noteTailDragState.historyPushed && (Math.abs(dx) > 1 || Math.abs(dy) > 1)) {
            pushHistory('Move tip note pointer');
            noteTailDragState.historyPushed = true;
        }
        node.tail = Object.assign({}, node.tail || {});
        node.tail.enabled = true;
        node.tail.target = {
            x: Math.round(noteTailDragState.startX + dx),
            y: Math.round(noteTailDragState.startY + dy)
        };
        if (project.settings.snap) {
            node.tail.target.x = snapCanvasCoord(node.tail.target.x);
            node.tail.target.y = snapCanvasCoord(node.tail.target.y);
        }
        renderEdges();
    }

    function stopNoteTailDrag(evt) {
        if (!noteTailDragState) return;
        if (evt && evt.pointerId !== noteTailDragState.pointerId) return;
        const nodeId = noteTailDragState.nodeId;
        noteTailDragState = null;
        document.removeEventListener('pointermove', onNoteTailDragMove, true);
        document.removeEventListener('pointerup', stopNoteTailDrag, true);
        document.removeEventListener('pointercancel', stopNoteTailDrag, true);
        scheduleSave();
        if (selectedNodeId === nodeId) renderInspector();
    }

