    function getTranslateCacheKey(target, key) {
        return `${target || 'text'}:${key || ''}`;
    }

    function rememberTranslation(node, target, key, entry) {
        if (!node || !entry) return;
        const cacheKey = getTranslateCacheKey(target, key);
        const bucket = getTranslationCacheBucket(node, target, key) || { entries: [] };
        const entries = Array.isArray(bucket.entries) ? bucket.entries.slice() : [];
        const existingIndex = entries.findIndex(item => item && item.before === entry.before);
        if (existingIndex >= 0) entries.splice(existingIndex, 1);
        entries.unshift(entry);
        node.translation_cache = Object.assign({}, node.translation_cache || {}, {
            [cacheKey]: {
                entries: entries.slice(0, 24),
                updated_at: nowIso()
            }
        });
    }

    function setTranslatedFieldValue(node, target, key, value, field) {
        if (!node) return false;
        if (target === 'node-param') {
            updateNodeParam(node.id, key, value, 'textarea');
        } else if (target === 'vlm-param') {
            updateVlmParam(node.id, key || 'prompt', value, 'textarea');
        } else {
            updateTextNodeValue(node.id, value);
        }
        if (field) field.value = value;
        return true;
    }

    function readTagCartFieldValue(node, target, key, field) {
        if (!node) return String(field?.value || '');
        if (target === 'node-param') {
            return String(node.params?.[key] ?? field?.value ?? '');
        }
        if (target === 'vlm-param') {
            return String(node.params?.[key || 'prompt'] ?? field?.value ?? '');
        }
        return String(getNodeTextOutput(node) || field?.value || '');
    }

    async function openTagCartForField(node, button, options) {
        if (!node || !button || button.disabled || isNodeLocked(node)) return;
        const wrap = button.closest('.sai-translate-wrap');
        const field = options?.field || (wrap ? wrap.querySelector('textarea') : null);
        if (!field || field.readOnly || field.disabled) return;
        const ready = await ensureWorkbenchLazyRuntime(
            'tagCart',
            () => typeof window.SimpAITagCartAdapter?.open === 'function',
            t('Loading Tag Cart...', '正在加载标签选择器...'),
            t('Tag Cart is not ready.', '标签选择器还未就绪。')
        );
        if (!ready) return;
        const adapter = window.SimpAITagCartAdapter;
        if (!adapter || typeof adapter.open !== 'function') {
            showToast(t('Tag Cart is not ready.', '标签选择器还未就绪。'));
            return;
        }
        const target = button.getAttribute('data-translate-target') || 'text-value';
        const key = button.getAttribute('data-translate-key') || '';
        const targetKind = key === 'negative_prompt' ? 'negative' : 'positive';
        const baseText = readTagCartFieldValue(getNode(node.id) || node, target, key, field);
        adapter.open({
            action: 'append',
            targetKind,
            anchor: options?.anchor || button.getBoundingClientRect(),
            baseText,
            container: root,
            target: {
                getBaseText: () => baseText,
                getText: () => readTagCartFieldValue(getNode(node.id) || node, target, key, field),
                setText: (nextValue, meta) => {
                    const latest = getNode(node.id) || node;
                    if (!latest) return false;
                    const ok = setTranslatedFieldValue(latest, target, key, nextValue, field);
                    renderAll({ inspector: false });
                    if (!meta?.auto) showToast(t('Tags inserted.', '标签已发送到提示词。'));
                    return ok;
                }
            }
        });
    }

    async function openTagCartForNode(node, button, options) {
        if (!node || node.type !== 'tag_cart' || isNodeLocked(node)) return;
        const ready = await ensureWorkbenchLazyRuntime(
            'tagCart',
            () => typeof window.SimpAITagCartAdapter?.open === 'function',
            t('Loading Tag Cart...', '正在加载标签选择器...'),
            t('Tag Cart is not ready.', '标签选择器还未就绪。')
        );
        if (!ready) return;
        const adapter = window.SimpAITagCartAdapter;
        if (!adapter || typeof adapter.open !== 'function') {
            showToast(t('Tag Cart is not ready.', '标签选择器还未就绪。'));
            return;
        }
        const params = node.params || {};
        const source = getTextNodeInputSource(node);
        const baseText = source ? String(getNodeTextOutput(source) || '') : '';
        const nodeEl = nodesLayer?.querySelector(`[data-node-id="${cssEscape(node.id)}"]`);
        const inlineHost = nodeEl?.querySelector('[data-tag-cart-inline-host]') || null;
        inlineHost?.querySelectorAll('.sai-tag-cart-inline-reopen').forEach(item => item.remove());
        const defaultSize = defaultNodeSize('tag_cart');
        if (node.w < defaultSize.w || node.h < defaultSize.h) {
            node.w = Math.max(node.w || 0, defaultSize.w);
            node.h = Math.max(node.h || 0, defaultSize.h);
            if (nodeEl) {
                nodeEl.style.width = `${node.w}px`;
                nodeEl.style.minHeight = `${node.h}px`;
            }
            scheduleSave();
            renderEdges();
        }
        const readCurrent = () => {
            const latest = getNode(node.id) || node;
            const current = String(latest.text?.value || '');
            if (current) return current;
            const latestSource = getTextNodeInputSource(latest);
            return latestSource ? String(getNodeTextOutput(latestSource) || '') : '';
        };
        const ok = adapter.open({
            action: params.action === 'replace' ? 'replace' : 'append',
            targetKind: 'positive',
            anchor: button?.getBoundingClientRect ? button.getBoundingClientRect() : null,
            inlineContainer: inlineHost,
            inlineHeight: 520,
            onClose: () => {
                if (activeInlineTagCartNodeId === node.id) activeInlineTagCartNodeId = '';
                const latestEl = nodesLayer?.querySelector(`[data-node-id="${cssEscape(node.id)}"]`);
                if (latestEl) {
                    latestEl.__simpaiRenderKey = undefined;
                    renderNodes();
                    renderEdges();
                    renderMinimap();
                }
            },
            baseText,
            target: {
                getBaseText: () => {
                    const latest = getNode(node.id) || node;
                    const latestSource = getTextNodeInputSource(latest);
                    return latestSource ? String(getNodeTextOutput(latestSource) || '') : baseText;
                },
                getText: readCurrent,
                setText: (nextValue, meta) => {
                    const latest = getNode(node.id) || node;
                    if (!latest || isNodeLocked(latest)) return false;
                    pushHistoryBatch(`tag-cart:${latest.id}:text`, 'Edit Tag Cart output');
                    latest.text = Object.assign({}, latest.text || {}, {
                        value: String(nextValue || ''),
                        updated_at: nowIso()
                    });
                    latest.params = Object.assign({}, latest.params || {}, {
                        action: meta?.action || latest.params?.action || 'append',
                        target_kind: 'positive'
                    });
                    scheduleSave();
                    syncTextOutputDom(latest.id, String(nextValue || ''));
                    if (nodesLayer) {
                        const latestEl = nodesLayer.querySelector(`[data-node-id="${cssEscape(latest.id)}"]`);
                        if (latestEl) latestEl.__simpaiRenderKey = nodeRenderKey(latest);
                    }
                    renderEdges();
                    renderInspector();
                    renderStatus();
                    renderMinimap();
                    showToast(source ? t('Tags inserted into Tag Cart node output.', '标签已写入标签选择器节点输出。') : t('Tags inserted.', '标签已插入。'));
                    return true;
                }
            }
        });
        if (ok && inlineHost) activeInlineTagCartNodeId = node.id;
        if (!options?.restore && ok) renderEdges();
    }

    function syncTextOutputDom(nodeId, value) {
        const nodeEl = nodesLayer?.querySelector(`[data-node-id="${cssEscape(nodeId)}"]`);
        if (!nodeEl) return;
        const field = nodeEl.querySelector('[data-text-value]');
        if (field && field.value !== String(value || '')) field.value = String(value || '');
    }

    async function requestTranslation(text, options) {
        const start = await sendCanvasTranslateRunRequest({
            text,
            direction: options?.direction || 'toggle',
            method: options?.method || ''
        });
        if (!start?.ok || !start.job_id) return start || { ok: false, error: 'translate request failed' };
        const deadline = Date.now() + 120000;
        while (Date.now() < deadline) {
            await wait(650);
            const result = await sendCanvasTranslatePollRequest(start.job_id);
            if (!result?.ok && result?.state !== 'failed') return result || { ok: false, error: 'translate poll failed' };
            if (result.state === 'finished') return result;
            if (result.state === 'failed') return result;
        }
        return { ok: false, error: 'translate timeout', job_id: start.job_id };
    }

    async function runTranslationNode(node) {
        if (!node || node.type !== 'translation' || isNodeLocked(node)) return { ok: false, error: 'translation node is unavailable' };
        const source = getTextNodeInputSource(node);
        const text = String(source ? getNodeTextOutput(source) : (node.input_text || '')).trim();
        if (!text) {
            showToast('Translation node has no input text.');
            return { ok: false, error: 'Translation node has no input text.' };
        }
        pushHistoryBatch(`translation:${node.id}:run`, 'Run translation node');
        node.status = { state: 'running', message: 'Translating...' };
        mutate();
        try {
            const result = await requestTranslation(text, {
                direction: node.params?.direction || 'toggle',
                method: node.params?.method || ''
            });
            if (!result?.ok || result.state === 'failed') {
                node.status = { state: 'failed', message: result?.details || result?.error || 'Translation failed.' };
                showToast(`Translation failed: ${node.status.message}`);
                mutate();
                return { ok: false, error: node.status.message };
            }
            const translated = String(result.translated_text || '').trim();
            node.text = { value: translated, updated_at: nowIso() };
            rememberTranslation(node, 'text-value', '', {
                before: text,
                after: translated,
                method: result.method || '',
                direction: result.direction || node.params?.direction || 'toggle',
                translated_at: nowIso()
            });
            node.status = { state: 'finished', message: `Translated${result.method ? ` with ${result.method}` : ''}.` };
            mutate();
            return { ok: true, text: translated };
        } catch (err) {
            node.status = { state: 'failed', message: err?.message || String(err) };
            showToast(`Translation failed: ${node.status.message}`);
            mutate();
            return { ok: false, error: node.status.message };
        }
    }

    async function handleTranslateButton(node, button) {
        if (!node || !button || button.disabled || isNodeLocked(node)) return;
        const wrap = button.closest('.sai-translate-wrap');
        const field = wrap ? wrap.querySelector('textarea') : null;
        if (!field || field.readOnly || field.disabled) return;
        const target = button.getAttribute('data-translate-target') || 'text-value';
        const key = button.getAttribute('data-translate-key') || '';
        const text = String(field.value || '');
        if (!text.trim()) {
            showToast(t('No text to translate.', '没有可翻译的文本'));
            return;
        }
        const cacheKey = getTranslateCacheKey(target, key);
        const cached = getTranslationCacheEntry(node, target, key, text);
        if (cached && text === cached.after) {
            pushHistoryBatch(`translate:${node.id}:${cacheKey}`, 'Restore source text');
            setTranslatedFieldValue(node, target, key, cached.before || '', field);
            showToast('Restored source text');
            renderAll({ inspector: false });
            return;
        }
        if (cached && text === cached.before) {
            pushHistoryBatch(`translate:${node.id}:${cacheKey}`, 'Apply cached translation');
            setTranslatedFieldValue(node, target, key, cached.after || '', field);
            showToast(`Applied cached translation${cached.method ? ` (${cached.method})` : ''}`);
            renderAll({ inspector: false });
            return;
        }
        const cache = node.translation_cache?.[cacheKey];
        if (cache && text === cache.after) {
            pushHistoryBatch(`translate:${node.id}:${cacheKey}`, 'Restore translated text');
            setTranslatedFieldValue(node, target, key, cache.before || '', field);
            showToast(t('Restored pre-translation text.', '已回退到翻译前文本'));
            renderAll({ inspector: false });
            return;
        }
        button.disabled = true;
        button.classList.add('is-busy');
        try {
            const result = await requestTranslation(text, { direction: 'toggle' });
            if (!result?.ok || result.state === 'failed') {
                showToast(t('Translation failed: {error}', '翻译失败：{error}').replace('{error}', result?.details || result?.error || 'unknown error'));
                return;
            }
            const translated = String(result.translated_text || '').trim();
            if (!translated) {
                showToast(t('Translation result is empty.', '翻译结果为空'));
                return;
            }
            pushHistoryBatch(`translate:${node.id}:${cacheKey}`, 'Translate text');
            node.translation_cache = Object.assign({}, node.translation_cache || {}, {
                [cacheKey]: {
                    before: text,
                    after: translated,
                    method: result.method || '',
                    translated_at: nowIso()
                }
            });
            rememberTranslation(node, target, key, {
                before: text,
                after: translated,
                method: result.method || '',
                direction: result.direction || 'toggle',
                translated_at: nowIso()
            });
            setTranslatedFieldValue(node, target, key, translated, field);
            showToast(t('Translated and replaced{method}', '已翻译并替换{method}').replace('{method}', result.method ? ` (${result.method})` : ''));
            renderAll({ inspector: false });
        } finally {
            button.disabled = false;
            button.classList.remove('is-busy');
        }
    }

    function isTextOutputNode(node) {
        if (!node) return false;
        if (node.type === 'batch_any') return batchAnyMediaKind(node) === 'text';
        return node.type === 'text' || node.type === 'wildcards_helper' || node.type === 'translation' || node.type === 'tag_cart' || node.type === 'wd14' || node.type === 'vlm' || node.type === 'style_selector' || isDirectorTimelineNode(node);
    }

    function getNodeTextOutput(node, visited) {
        if (!isTextOutputNode(node)) return '';
        const seen = visited || new Set();
        if (seen.has(node.id)) return '';
        seen.add(node.id);
        if (node.type === 'style_selector') {
            return WORKBENCH_STYLE_SELECTOR_NODE.getPrompt?.(node, styleSelectorNodeContext()) || String(node.text?.value || '');
        }
        if (isDirectorTimelineNode(node)) {
            const payload = directorTimelinePayload(node);
            return String(payload?.prompt_override || '');
        }
        if (node.type === 'text') {
            const source = getTextNodeInputSource(node);
            if (source) return getNodeTextOutput(source, seen);
        }
        if (node.type === 'translation') {
            return String(node.text?.value || '');
        }
        if (node.type === 'tag_cart') {
            const value = String(node.text?.value || '');
            if (value) return value;
            const source = getTextNodeInputSource(node);
            return source ? getNodeTextOutput(source, seen) : '';
        }
        if (node.type === 'batch_any') {
            return batchAnyTextFromItem(batchAnyCurrentItem(node)) || String(node.text?.value || '');
        }
        if (node.type === 'wildcards_helper') {
            return wildcardHelperBuildTag(node.params || {});
        }
        return String(node.text?.value || '');
    }

    function wouldCreateTextCycle(fromId, toId) {
        if (!fromId || !toId || fromId === toId) return true;
        const seen = new Set([toId]);
        let current = getNode(fromId);
        while (current && ['text', 'translation', 'tag_cart', 'wildcards_helper'].includes(current.type)) {
            if (seen.has(current.id)) return true;
            seen.add(current.id);
            current = getTextNodeInputSource(current);
        }
        return false;
    }

    function addCompareNode(world, options) {
        const opts = options || {};
        const size = defaultNodeSize('compare');
        if (opts.history !== false) pushHistory('Add compare node');
        const node = {
            id: uid('compare'),
            type: 'compare',
            x: world.x,
            y: world.y,
            w: size.w,
            h: size.h,
            title: opts.title || 'Image Compare',
            inputs: { a: null, b: null },
            params: { position: 50, mode: 'fit' },
            source: { kind: 'manual_compare' }
        };
        placeNodeAvoidingOverlap(node, world, opts);
        project.nodes.push(node);
        const autoMessage = completePendingConnectionToNode(node);
        selectedNodeId = node.id;
        selectedNodeIds = new Set([node.id]);
        selectedEdgeId = null;
        if (opts.render !== false) mutate();
        if (opts.toast !== false) showToast(autoMessage ? t('Compare node added, {message}', 'Compare 节点已添加，{message}').replace('{message}', autoMessage) : t('Compare node added', 'Compare 节点已添加'));
        return node;
    }

    function createCompareNodeFromSources(sources) {
        const pair = (sources || []).filter(isImageCompareSource).slice(0, 2);
        if (pair.length < 2) {
            showToast('Select two Image or image Result nodes first.');
            return null;
        }
        const rectA = getNodeRect(pair[0]);
        const rectB = getNodeRect(pair[1]);
        const size = defaultNodeSize('compare');
        const base = {
            x: Math.round(Math.max(rectA.x + rectA.w, rectB.x + rectB.w) + 80),
            y: Math.round((Math.min(rectA.y, rectB.y) + Math.max(rectA.y + rectA.h, rectB.y + rectB.h)) / 2 - size.h / 2)
        };
        pushHistory('Create compare node');
        const node = addCompareNode(base, { history: false, render: false, toast: false, title: `${pair[0].title || 'Image A'} / ${pair[1].title || 'Image B'}` });
        createCompareImageEdge(pair[0].id, node.id, 'a', { silent: true });
        createCompareImageEdge(pair[1].id, node.id, 'b', { silent: true });
        selectedNodeId = node.id;
        selectedNodeIds = new Set([node.id]);
        selectedEdgeId = null;
        mutate();
        showToast(t('Compare node created from selected images.', 'Compare 节点已从选中图片创建'));
        return node;
    }

    function addTimelineNode(world, options) {
        const opts = options || {};
        const size = defaultNodeSize('timeline');
        if (opts.history !== false) pushHistory('Add media timeline node');
        const node = {
            id: uid('timeline'),
            type: 'timeline',
            x: world.x,
            y: world.y,
            w: size.w,
            h: size.h,
            title: opts.title || 'Media Timeline',
            params: { width: 1280, height: 720, aspect: '16:9', fps: 30, duration: 10, background: '#000000', zoom: 1 },
            tracks: typeof WORKBENCH_TIMELINE.DEFAULT_TRACKS !== 'undefined'
                ? cloneRunValue(WORKBENCH_TIMELINE.DEFAULT_TRACKS, [])
                : [{ id: 'v1', type: 'video', name: 'Video / Image' }, { id: 'a1', type: 'audio', name: 'Audio' }],
            clips: [],
            source: { kind: 'manual_timeline' }
        };
        placeNodeAvoidingOverlap(node, world, opts);
        if (typeof WORKBENCH_TIMELINE.normalizeNode === 'function') WORKBENCH_TIMELINE.normalizeNode(node);
        project.nodes.push(node);
        const autoMessage = completePendingConnectionToNode(node);
        selectedNodeId = node.id;
        selectedNodeIds = new Set([node.id]);
        selectedEdgeId = null;
        if (opts.render !== false) mutate();
        if (opts.toast !== false) showToast(autoMessage ? t('Timeline added, {message}', 'Timeline 已添加，{message}').replace('{message}', autoMessage) : t('Timeline added', 'Timeline 已添加'));
        return node;
    }

    function timelineTrackForSource(node, source) {
        const asset = getTimelineSourceAsset(source) || {};
        const kind = typeof WORKBENCH_TIMELINE.assetMediaKind === 'function' ? WORKBENCH_TIMELINE.assetMediaKind(asset) : assetMediaKind(asset);
        return typeof WORKBENCH_TIMELINE.defaultTrackId === 'function' ? WORKBENCH_TIMELINE.defaultTrackId(kind) : (kind === 'audio' ? 'a1' : 'v1');
    }

    function addTimelineClipFromSource(timelineNode, source, options) {
        if (!timelineNode || timelineNode.type !== 'timeline' || !isTimelineSource(source)) return null;
        const opts = options || {};
        if (isNodeLocked(timelineNode)) {
            showToast('Locked timeline cannot be edited');
            return null;
        }
        if (opts.history !== false) pushHistory('Add timeline clip');
        if (typeof WORKBENCH_TIMELINE.normalizeNode === 'function') WORKBENCH_TIMELINE.normalizeNode(timelineNode);
        const trackId = opts.track_id || timelineTrackForSource(timelineNode, source);
        const start = Number.isFinite(Number(opts.start))
            ? Number(opts.start)
            : (typeof WORKBENCH_TIMELINE.nextStartForTrack === 'function' ? WORKBENCH_TIMELINE.nextStartForTrack(timelineNode, trackId) : 0);
        const clip = typeof WORKBENCH_TIMELINE.createClipFromSource === 'function'
            ? WORKBENCH_TIMELINE.createClipFromSource(source, { id: uid('clip'), track_id: trackId, start }, timelineNodeContext())
            : { id: uid('clip'), source_node_id: source.id, title: source.title || 'Clip', kind: 'image', track_id: trackId, start, duration: 4 };
        timelineNode.clips = Array.isArray(timelineNode.clips) ? timelineNode.clips : [];
        timelineNode.clips.push(clip);
        timelineNode.params = Object.assign({}, timelineNode.params || {});
        timelineNode.params.duration = Math.max(Number(timelineNode.params.duration || 1), Number(clip.start || 0) + Number(clip.duration || 0));
        if (typeof WORKBENCH_TIMELINE.normalizeNode === 'function') WORKBENCH_TIMELINE.normalizeNode(timelineNode);
        if (opts.edge !== false) {
            project.edges.push({ id: uid('edge'), type: 'timeline', from: source.id, to: timelineNode.id, slot: clip.id });
        }
        if (opts.render !== false) mutate();
        return clip;
    }

    function addSelectedMediaToTimeline(timelineNode) {
        if (!timelineNode || timelineNode.type !== 'timeline') return;
        const sources = getSelectedNodeIdList()
            .map(id => getNode(id))
            .filter(source => source && source.id !== timelineNode.id && isTimelineSource(source));
        if (!sources.length) {
            showToast('Select Image / Video / Audio / Result nodes together with the timeline first.');
            return;
        }
        pushHistory('Add selected media to timeline');
        sources.forEach(source => addTimelineClipFromSource(timelineNode, source, { history: false, render: false }));
        selectedNodeId = timelineNode.id;
        selectedNodeIds = new Set([timelineNode.id]);
        selectedEdgeId = null;
        mutate();
        showToast(t('Added {count} media item(s) to Timeline.', '已添加 {count} 个素材到 Timeline').replace('{count}', sources.length));
    }

    function createTimelineNodeFromSources(sources) {
        const list = (sources || []).filter(isTimelineSource);
        if (!list.length) {
            showToast('Select Image / Video / Audio / Result nodes first.');
            return null;
        }
        const rects = list.map(getNodeRect);
        const minY = Math.min(...rects.map(rect => rect.y));
        const maxX = Math.max(...rects.map(rect => rect.x + rect.w));
        const size = defaultNodeSize('timeline');
        const base = { x: Math.round(maxX + 80), y: Math.round(minY) };
        pushHistory('Create media timeline');
        const node = addTimelineNode(base, { history: false, render: false, toast: false, title: 'Media Timeline' });
        list.forEach(source => addTimelineClipFromSource(node, source, { history: false, render: false }));
        selectedNodeId = node.id;
        selectedNodeIds = new Set([node.id]);
        selectedEdgeId = null;
        mutate();
        showToast(t('Timeline created from {count} media item(s).', 'Timeline 已从 {count} 个素材创建').replace('{count}', list.length));
        return node;
    }

    function addManualOutputNode(world) {
        pushHistory('Add output node');
        const size = defaultResultNodeSize();
        const node = {
            id: uid('result'),
            type: 'result',
            x: world.x,
            y: world.y,
            w: size.w,
            h: size.h,
            title: t('Manual Output', '手动输出'),
            producer: { preset_node_id: null, run_id: null, task_id: null },
            status: {
                state: 'manual',
                queue_position: null,
                step: 0,
                total_steps: 0,
                percent: 1,
                message: t('You can manually replace the image and connect it to the next preset input.', '可手动替换图片，并连接到下一个 preset 输入。')
            },
            preview: null,
            asset: null,
            source: { kind: 'manual_output' }
        };
        placeNodeAvoidingOverlap(node, world);
        project.nodes.push(node);
        const autoMessage = completePendingConnectionToNode(node);
        selectedNodeId = node.id;
        selectedEdgeId = null;
        mutate();
        showToast(autoMessage ? t('Manual output node added, {message}', '已添加手动输出节点，{message}').replace('{message}', autoMessage) : t('Manual output node added', '已添加手动输出节点'));
        return node;
    }

    function createUploadEdge(fromId, toId, slot, options) {
        const from = getNode(fromId);
        const to = getNode(toId);
        const allowedSlots = to ? (to.type === 'classic' ? getVisibleClassicUploadSlots(to).map(item => item.key) : getVisibleUploadSlots(to).map(item => item.key)) : [];
        if (!from || !to || !['preset', 'classic'].includes(to.type) || !allowedSlots.includes(slot)) {
            showToast(t('Can only connect to preset/classic input slots.', '只能连接到 preset/classic 输入槽'));
            return;
        }
        if (!canNodeConnectToUploadSlot(from, slot)) {
            showToast(t('The source media type does not match this preset slot.', '源媒体类型与当前 preset 槽位不匹配'));
            return;
        }
        if (isNodeLocked(from) || isNodeLocked(to)) {
            showToast('Locked nodes cannot change connections');
            return;
        }
        if (!options || !options.silent) pushHistory('Connect upload edge');
        project.edges = project.edges.filter(edge => !(edge.type === 'upload' && edge.to === toId && edge.slot === slot));
        project.edges.push({
            id: uid('edge'),
            type: 'upload',
            from: fromId,
            to: toId,
            slot
        });
        to.upload_slots = to.upload_slots || {};
        to.upload_slots[slot] = fromId;
        syncResolutionConfigForPresetInputs(to);
        selectedEdgeId = null;
        selectedNodeId = toId;
        refreshPresetSpecialNodeDom(to, { syncViewer: true });
        if (options && options.silent) return;
        mutate();
        showToast(t('{slot} connected.', '{slot} 已连接').replace('{slot}', getSlotLabel(to, slot)));
    }

    function createPresetToPresetBridgeEdge(fromId, toId, slot) {
        const from = getNode(fromId);
        const to = getNode(toId);
        const allowedSlots = to ? (to.type === 'classic' ? getVisibleClassicUploadSlots(to) : getVisibleUploadSlots(to)).map(item => item.key) : [];
        if (!from || !to || !['preset', 'classic'].includes(from.type) || !['preset', 'classic'].includes(to.type) || !allowedSlots.includes(slot)) {
            showToast('Preset/Classic output can only connect to a preset/classic input slot.');
            return;
        }
        if (!canPresetOutputConnectToUploadSlot(from, slot)) {
            showToast('Preset output media type does not match this input slot.');
            return;
        }
        if (isNodeLocked(from) || isNodeLocked(to)) {
            showToast('Locked nodes cannot change connections');
            return;
        }
        pushHistory('Connect preset chain');
        const resultNode = findOrCreateBridgeResultNode(from, to, slot);
        project.edges = project.edges.filter(edge => !(edge.type === 'upload' && edge.to === toId && edge.slot === slot));
        ensureGenerateEdge(fromId, resultNode.id);
        project.edges.push({
            id: uid('edge'),
            type: 'upload',
            from: resultNode.id,
            to: toId,
            slot
        });
        to.upload_slots = to.upload_slots || {};
        to.upload_slots[slot] = resultNode.id;
        syncResolutionConfigForPresetInputs(to);
        selectedEdgeId = null;
        selectedNodeId = resultNode.id;
        refreshPresetSpecialNodeDom(to, { syncViewer: true });
        mutate();
        showToast(`Preset chain connected via ${getSlotLabel(to, slot)} result bridge.`);
    }

    function findOrCreateBridgeResultNode(fromPreset, toPreset, slot) {
        const existing = project.edges
            .filter(edge => edge.type === 'generate' && edge.from === fromPreset.id)
            .map(edge => getNode(edge.to))
            .find(node => node?.type === 'result' && project.edges.some(edge => edge.type === 'upload' && edge.from === node.id && edge.to === toPreset.id && edge.slot === slot));
        if (existing) return existing;
        const size = defaultNodeSize('result');
        const fromRect = getNodeRect(fromPreset);
        const toRect = getNodeRect(toPreset);
        const mid = {
            x: Math.round((fromRect.x + fromRect.w + toRect.x) / 2 - size.w / 2),
            y: Math.round((fromRect.y + toRect.y) / 2)
        };
        const node = {
            id: uid('result'),
            type: 'result',
            x: mid.x,
            y: mid.y,
            w: size.w,
            h: size.h,
            title: `${fromPreset.title || 'Preset'} Output`,
            producer: { preset_node_id: fromPreset.id, run_id: null, task_id: null },
            status: {
                state: 'reserved',
                queue_position: null,
                step: 0,
                total_steps: 0,
                percent: 0,
                message: `Auto bridge for ${toPreset.title || 'downstream preset'} ${getSlotLabel(toPreset, slot)}.`
            },
            preview: null,
            asset: null,
            source: { kind: 'auto_bridge', downstream_preset_id: toPreset.id, downstream_slot: slot }
        };
        placeNodeAvoidingOverlap(node, mid, { excludeIds: [fromPreset.id, toPreset.id] });
        project.nodes.push(node);
        return node;
    }

    function findOrCreatePoseStudioBridgeResultNode(fromPreset, poseNode) {
        const existing = project.edges
            .filter(edge => edge.type === 'generate' && edge.from === fromPreset.id)
            .map(edge => getNode(edge.to))
            .find(node => node?.type === 'result' && project.edges.some(edge => edge.type === 'image' && edge.from === node.id && edge.to === poseNode.id && edge.slot === 'reference'));
        if (existing) return existing;
        const size = defaultNodeSize('result');
        const fromRect = getNodeRect(fromPreset);
        const toRect = getNodeRect(poseNode);
        const mid = {
            x: Math.round((fromRect.x + fromRect.w + toRect.x) / 2 - size.w / 2),
            y: Math.round((fromRect.y + toRect.y) / 2)
        };
        const node = {
            id: uid('result'),
            type: 'result',
            x: mid.x,
            y: mid.y,
            w: size.w,
            h: size.h,
            title: `${fromPreset.title || 'Preset'} Output`,
            producer: { preset_node_id: fromPreset.id, run_id: null, task_id: null, expected_media_kind: 'image' },
            status: {
                state: 'reserved',
                queue_position: null,
                step: 0,
                total_steps: 0,
                percent: 0,
                message: `Auto bridge for ${poseNode.title || 'Pose Studio'} reference.`
            },
            preview: null,
            asset: null,
            source: {
                kind: 'auto_bridge',
                downstream_pose_studio_id: poseNode.id,
                downstream_slot: 'reference',
                expected_media_kind: 'image'
            }
        };
        placeNodeAvoidingOverlap(node, mid, { excludeIds: [fromPreset.id, poseNode.id] });
        project.nodes.push(node);
        return node;
    }

